type ScannerCheckPackId = typeof scannerCheckPacks[number]['id'];

const highRiskActiveScanChecks = new Set<ActiveScanCheckId>([
  'cors-origin',
  'authz-diff',
  'oast-ssrf',
  'reflected-xss',
  'sql-injection',
  'path-traversal',
]);

function activeScanCheckSeverity(checkId: ActiveScanCheckId): Severity {
  if (checkId === 'command-injection') return 'critical';
  if (highRiskActiveScanChecks.has(checkId)) return 'high';
  return 'medium';
}

function activeScanCheckConfidence(checkId: ActiveScanCheckId): Issue['confidence'] {
  return checkId === 'method-options' ? 'tentative' : 'firm';
}

