function mergeIssues(baseIssues: Issue[], passiveIssues: Issue[]) {
  const byKey = new Map<string, Issue>();
  for (const issue of [...baseIssues, ...passiveIssues]) {
    byKey.set(`${issue.title}:${issue.host}:${issue.path}`, issue);
  }
  return Array.from(byKey.values()).sort((a, b) => severityRank[b.severity] - severityRank[a.severity]);
}

function applyIssueTriageOverrides(issues: Issue[], overrides: IssueTriageOverride[]) {
  const byId = new Map(overrides.map((override) => [override.issueId, override]));
  return issues.map((issue) => {
    const override = byId.get(issue.id);
    if (!override) return issue;
    return {
      ...issue,
      status: override.status,
      assignee: override.assignee,
      triageNote: override.triageNote,
      lastTriagedAt: override.updatedAt,
    };
  });
}

function highestFindingSeverity(findings: Array<{ severity: Severity }>, fallback: Severity = 'info') {
  return findings.reduce<Severity>(
    (highest, finding) => (severityRank[finding.severity] > severityRank[highest] ? finding.severity : highest),
    fallback,
  );
}

function makeDefaultScannerAuditQueue(exchanges: HttpExchange[]): ScannerAuditQueueItem[] {
  const now = new Date().toISOString();
  const authzCandidates = exchanges.filter((exchange) => exchange.tags.includes('authz')).length;
  return [
    {
      id: 'queue-passive-headers',
      kind: 'passive',
      label: 'Passive header checks',
      target: `${exchanges.length} exchanges`,
      status: 'running',
      priority: 'medium',
      requestCount: exchanges.length,
      detail: 'Review captured responses for CSP, nosniff, role metadata, and server error signals.',
      createdAt: now,
      updatedAt: now,
    },
    {
      id: 'queue-authz-replay',
      kind: 'authz-replay',
      label: 'Authorization replay candidates',
      target: `${authzCandidates} tagged requests`,
      status: authzCandidates > 0 ? 'queued' : 'blocked',
      priority: authzCandidates > 0 ? 'high' : 'low',
      requestCount: authzCandidates,
      detail: 'Validate role and identity-boundary candidates with Repeater matrix evidence.',
      createdAt: now,
      updatedAt: now,
    },
    {
      id: 'queue-crawl-audit',
      kind: 'crawl-audit',
      label: 'Crawler insertion-point audit',
      target: 'Target map insertion points',
      status: 'queued',
      priority: 'medium',
      requestCount: 0,
      detail: 'Run crawl-derived scanner probes after Target Map discovery has populated insertion points.',
      createdAt: now,
      updatedAt: now,
    },
    {
      id: 'queue-active-scan',
      kind: 'active-scan',
      label: 'Active scanner probes',
      target: exchanges[0] ? `${exchanges[0].host}${exchanges[0].path}` : 'Selected request',
      status: 'queued',
      priority: 'medium',
      requestCount: 4,
      detail: 'Scoped, throttled security-header, CORS, cache-key, and OPTIONS checks are staged from the selected request.',
      createdAt: now,
      updatedAt: now,
    },
  ];
}

interface PassiveScanReview {
  issues: Issue[];
  totalCandidates: number;
  duplicateCandidates: number;
  confidenceCounts: Record<Issue['confidence'], number>;
  checkCounts: Array<{ id: string; label: string; count: number; duplicates: number }>;
}

interface PassiveIssueCandidate extends Issue {
  checkId: string;
  checkLabel: string;
  confidenceReason: string;
}

function buildPassiveIssues(exchanges: HttpExchange[]): Issue[] {
  return buildPassiveScanReview(exchanges).issues;
}

function buildPassiveScanReview(exchanges: HttpExchange[]): PassiveScanReview {
  const candidates = exchanges.flatMap((exchange) => {
    const issues: PassiveIssueCandidate[] = [];
    const response = exchange.responseRaw.toLowerCase();
    const idPrefix = `passive-${exchange.id}`;

    if (exchange.mime.includes('text/html') && !response.includes('content-security-policy:')) {
      issues.push({
        id: `${idPrefix}-csp`,
        title: 'HTML response missing Content-Security-Policy',
        severity: 'medium',
        host: exchange.host,
        path: exchange.path,
        confidence: 'firm',
        status: 'open',
        detail: 'A rendered HTML response was observed without a Content-Security-Policy header, increasing exposure to script injection impact.',
        remediation: 'Define a restrictive Content-Security-Policy and tune it per application surface.',
        checkId: 'passive-csp',
        checkLabel: 'CSP missing',
        confidenceReason: 'HTML response observed and no CSP header was present in the captured response.',
      });
    }

    if (exchange.mime.includes('javascript') && !response.includes('x-content-type-options:')) {
      issues.push({
        id: `${idPrefix}-nosniff`,
        title: 'JavaScript response missing X-Content-Type-Options',
        severity: 'low',
        host: exchange.host,
        path: exchange.path,
        confidence: 'firm',
        status: 'open',
        detail: 'A JavaScript response did not include X-Content-Type-Options: nosniff, which can weaken content-type isolation in some clients.',
        remediation: 'Serve script assets with X-Content-Type-Options: nosniff.',
        checkId: 'passive-nosniff',
        checkLabel: 'Nosniff missing',
        confidenceReason: 'JavaScript response observed and no X-Content-Type-Options header was present.',
      });
    }

    if (/support_admin|featureflags|internal\/export/i.test(exchange.responseRaw)) {
      issues.push({
        id: `${idPrefix}-metadata`,
        title: 'Privileged workflow metadata exposed',
        severity: 'medium',
        host: exchange.host,
        path: exchange.path,
        confidence: 'firm',
        status: 'open',
        detail: 'The response contains role, feature flag, or internal route strings that can accelerate authorization testing.',
        remediation: 'Avoid returning internal authorization labels to clients unless they are required for the visible user workflow.',
        checkId: 'passive-auth-metadata',
        checkLabel: 'Auth metadata',
        confidenceReason: 'Role, feature flag, or internal-route markers matched in captured response evidence.',
      });
    }

    if (exchange.status >= 500) {
      issues.push({
        id: `${idPrefix}-server-error`,
        title: 'Server error observed during assessment',
        severity: 'high',
        host: exchange.host,
        path: exchange.path,
        confidence: 'tentative',
        status: 'open',
        detail: 'A 5xx response was captured and should be reviewed for instability, stack traces, or exploitable edge cases.',
        remediation: 'Review application logs, normalize error handling, and ensure no sensitive diagnostic data is returned.',
        checkId: 'passive-server-error',
        checkLabel: 'Server error',
        confidenceReason: 'Captured response status was 5xx; manual validation is needed to classify impact.',
      });
    }

    return issues;
  });

  const checkStats = new Map<string, { id: string; label: string; count: number; duplicates: number }>();
  const byKey = new Map<string, PassiveIssueCandidate>();
  for (const issue of candidates) {
    const stat = checkStats.get(issue.checkId) ?? { id: issue.checkId, label: issue.checkLabel, count: 0, duplicates: 0 };
    stat.count += 1;
    checkStats.set(issue.checkId, stat);
    const key = passiveIssueDedupeKey(issue);
    const existing = byKey.get(key);
    if (!existing || severityRank[issue.severity] > severityRank[existing.severity] || confidenceRank(issue.confidence) > confidenceRank(existing.confidence)) {
      byKey.set(key, issue);
    }
    if (existing) stat.duplicates += 1;
  }

  const issues = Array.from(byKey.values()).map((issue) => {
    const duplicateCount = candidates.filter((candidate) => passiveIssueDedupeKey(candidate) === passiveIssueDedupeKey(issue)).length - 1;
    return {
      ...issue,
      detail: `${issue.detail} Confidence reason: ${issue.confidenceReason}${duplicateCount > 0 ? `; ${duplicateCount} duplicate passive signal${duplicateCount === 1 ? '' : 's'} folded into this finding.` : '.'}`,
      triageNote: issue.triageNote ?? `Passive dedupe key ${passiveIssueDedupeKey(issue)}.`,
    };
  });

  return {
    issues,
    totalCandidates: candidates.length,
    duplicateCandidates: Math.max(0, candidates.length - issues.length),
    confidenceCounts: {
      certain: issues.filter((issue) => issue.confidence === 'certain').length,
      firm: issues.filter((issue) => issue.confidence === 'firm').length,
      tentative: issues.filter((issue) => issue.confidence === 'tentative').length,
    },
    checkCounts: Array.from(checkStats.values()),
  };
}

function passiveIssueDedupeKey(issue: Pick<Issue, 'title' | 'host' | 'path'>) {
  return `${issue.title}:${issue.host}:${issue.path}`.toLowerCase();
}

function confidenceRank(confidence: Issue['confidence']) {
  return confidence === 'certain' ? 3 : confidence === 'firm' ? 2 : 1;
}

function issuesFromActiveScan(summary: ActiveScanSummary | CrawlAuditSummary | null): Issue[] {
  return (summary?.findings ?? []).map((finding) => ({
    id: finding.id,
    title: finding.title,
    severity: finding.severity,
    host: finding.host,
    path: finding.path,
    confidence: finding.confidence,
    status: 'open' as const,
    detail: finding.detail,
    remediation: finding.remediation,
  }));
}

type ScannerCoverageRow = {
  id: string;
  label: string;
  type: string;
  status: 'covered' | 'untested' | 'skipped' | 'duplicate';
  checks: ActiveScanCheckId[];
};

function buildScannerCoverageRows(
  crawlSummary: CrawlSummary | null,
  activeScanSummary: ActiveScanSummary | CrawlAuditSummary | null,
  activeScanChecks: ActiveScanCheckId[],
): ScannerCoverageRow[] {
  const insertionPoints = crawlSummary?.insertionPoints ?? [];
  if (!insertionPoints.length) {
    return activeScanChecks.slice(0, 4).map((check, index) => ({
      id: `seed-coverage-${check}`,
      label: `${activeScanCheckLabels[check]} insertion point`,
      type: index === 0 ? 'query' : index === 1 ? 'header' : index === 2 ? 'cookie' : 'path',
      status: index < (activeScanSummary?.totalRequests ?? 0) ? 'covered' : 'untested',
      checks: [check],
    }));
  }

  const auditedCount = activeScanSummary && 'auditedInsertionPoints' in activeScanSummary ? activeScanSummary.auditedInsertionPoints : 0;
  const seen = new Set<string>();
  return insertionPoints.slice(0, 24).map((point, index) => {
    const pointPath = new URL(point.url).pathname;
    const dedupeKey = `${point.type}:${point.name}:${pointPath}`;
    const duplicate = seen.has(dedupeKey);
    seen.add(dedupeKey);
    return {
      id: point.id,
      label: `${point.method} ${pointPath} ${point.name}`,
      type: point.type,
      status: duplicate ? 'duplicate' : index < auditedCount ? 'covered' : index < activeScanChecks.length ? 'untested' : 'skipped',
      checks: activeScanChecks.slice(index % Math.max(activeScanChecks.length, 1), index % Math.max(activeScanChecks.length, 1) + 1),
    };
  });
}

function buildScannerIssueRule(activeScanChecks: ActiveScanCheckId[], selectedPackId: ScannerCheckPackId, createdAt = new Date().toISOString()): ScannerIssueRule {
  const checkId = activeScanChecks[0] ?? 'security-headers';
  const pack = scannerCheckPacks.find((item) => item.id === selectedPackId) ?? scannerCheckPacks[0];
  return {
    id: `scanner-rule-${Date.now()}-${Math.random().toString(16).slice(2)}`,
    name: `${pack.label} confidence severity rule`,
    createdAt,
    checkId,
    severity: activeScanCheckSeverity(checkId),
    confidence: activeScanCheckConfidence(checkId),
    action: 'require-review',
    status: 'active',
    summary: `${pack.label} keeps ${activeScanCheckLabels[checkId]} at ${activeScanCheckConfidence(checkId)} confidence and ${activeScanCheckSeverity(checkId)} severity until retest evidence confirms fixed or regressed state.`,
  };
}

function buildScannerEvidenceDeltaContent(delta: Omit<ScannerEvidenceDelta, 'content'>, retest: ScannerRetestWorkflow, digestPreview: string) {
  return JSON.stringify({
    kind: 'proxyforge-scanner-evidence-delta',
    createdAt: delta.createdAt,
    reportReady: delta.reportReady,
    issue: {
      id: delta.issueId,
      title: delta.issueTitle,
      host: delta.host,
      path: delta.issuePath,
      severity: delta.severity,
      confidence: delta.confidence,
    },
    retest: {
      id: retest.id,
      outcome: retest.outcome,
      baselineStatus: retest.baselineStatus,
      retestStatus: delta.retestStatus,
      fixed: retest.outcome === 'fixed',
      regressed: retest.outcome === 'regressed',
      summary: retest.summary,
    },
    evidence: {
      baselineExchangeId: delta.baselineExchangeId,
      retestExchangeId: delta.retestExchangeId,
      normalizedDelta: `${delta.outcome} scanner evidence delta from ${delta.baselineStatus} to ${delta.retestStatus}`,
      metadata: {
        ruleIds: delta.ruleIds,
        reportReady: delta.reportReady,
        redaction: 'report-ready metadata',
      },
    },
    signature: {
      ...delta.signature,
      digestPreview,
    },
  }, null, 2);
}

function extractAnvilQuotedField(source: string, field: string, fallback = '') {
  const quoted = source.match(new RegExp(`${field}:\\s*"([^"]+)"`, 'i'));
  if (quoted?.[1]?.trim()) return quoted[1].trim();
  const unquoted = source.match(new RegExp(`${field}:\\s*([^\\n]+)`, 'i'));
  return unquoted?.[1]?.trim().replace(/^['"]|['"]$/g, '') || fallback;
}

function extractAnvilListField(source: string, field: string, fallback: string[]) {
  const match = source.match(new RegExp(`${field}:\\s*([^\\n]+)`, 'i'));
  if (!match) return fallback;
  const values = Array.from(match[1].matchAll(/"([^"]+)"/g)).map((item) => item[1].trim()).filter(Boolean);
  if (values.length) return values;
  const bareValues = match[1].split(',').map((item) => item.trim().replace(/^['"]|['"]$/g, '')).filter(Boolean);
  return bareValues.length ? bareValues : fallback;
}

function extractAnvilSeverity(source: string): Severity {
  const match = source.match(/severity:\s*(info|low|medium|high)/i);
  return (match?.[1]?.toLowerCase() as Severity | undefined) ?? 'medium';
}

function extractAnvilConfidence(source: string): Issue['confidence'] {
  const match = source.match(/confidence:\s*(certain|firm|tentative)/i);
  return (match?.[1]?.toLowerCase() as Issue['confidence'] | undefined) ?? 'firm';
}

function detectAnvilPhase(source: string): AnvilDefinition['phase'] {
  const normalized = source.toLowerCase();
  if (normalized.includes('send request') || normalized.includes('send payload') || normalized.includes('given insertion point')) return 'active';
  if (normalized.includes('given response') || normalized.includes('given request')) return 'passive';
  return 'unspecified';
}

function detectAnvilRunScope(source: string): AnvilDefinition['runScope'] {
  const normalized = source.toLowerCase();
  if (normalized.includes('insertion point')) return 'per-insertion-point';
  if (normalized.includes('given host')) return 'per-host';
  if (normalized.includes('given path')) return 'per-path';
  return 'per-request';
}

function buildDefaultAnvilSource(exchange: HttpExchange) {
  const marker = /support_admin|featureflags|internal\/export/i.test(exchange.responseRaw) ? 'support_admin|featureflags|internal/export' : 'admin|debug|internal';
  return `metadata:
  language: v2-beta
  name: "ProxyForge privileged workflow metadata"
  description: "Flags privileged workflow strings in audited responses before authorization replay."
  author: "ProxyForge"
  tags: "proxyforge", "passive", "metadata"

define:
  workflow_markers = "${marker}"

given response then
  if {latest.response.body} matches "${marker}" then
    report issue:
      name: "Anvil privileged workflow metadata exposed"
      severity: medium
      confidence: firm
      remediation: "Avoid returning internal authorization labels or feature flags to clients unless required for the visible workflow."
      detail: "A custom Anvil matched privileged workflow metadata in the audited response."
  end if`;
}

function buildAnvilDefinitionFromSource(source: string, exchange: HttpExchange, createdAt = new Date().toISOString()): AnvilDefinition {
  const name = extractAnvilQuotedField(source, 'name', 'ProxyForge custom Anvil');
  const description = extractAnvilQuotedField(source, 'description', `Custom scan check seeded from ${exchange.method} ${exchange.path}.`);
  const tags = extractAnvilListField(source, 'tags', ['proxyforge', 'custom']);
  return {
    id: `anvil-${Date.now()}-${Math.random().toString(16).slice(2)}`,
    name,
    language: 'v2-beta',
    createdAt,
    updatedAt: createdAt,
    author: extractAnvilQuotedField(source, 'author', 'ProxyForge'),
    description,
    tags,
    phase: detectAnvilPhase(source),
    runScope: detectAnvilRunScope(source),
    enabled: true,
    severity: extractAnvilSeverity(source),
    confidence: extractAnvilConfidence(source),
    fixtureIds: [],
    headlessRunIds: [],
    reportReady: false,
    summary: `${name} is enabled as a ${anvilPhaseLabels[detectAnvilPhase(source)].toLowerCase()} custom scan check using ${anvilRunScopeLabels[detectAnvilRunScope(source)].toLowerCase()} execution.`,
    source,
  };
}

function buildAnvilRuleLibrary(check: AnvilDefinition, createdAt = new Date().toISOString()): AnvilRuleLibrary {
  const content = JSON.stringify({
    kind: 'proxyforge-anvil-rule-library',
    createdAt,
    importable: true,
    ruleIds: [check.id],
    checks: [{
      id: check.id,
      name: check.name,
      language: check.language,
      phase: check.phase,
      runScope: check.runScope,
      tags: check.tags,
      source: check.source,
    }],
  }, null, 2);
  return {
    id: `anvil-library-${Date.now()}-${Math.random().toString(16).slice(2)}`,
    name: `${check.name} library`,
    description: `Reusable Anvil library seeded from ${check.name}.`,
    createdAt,
    updatedAt: createdAt,
    ruleIds: [check.id],
    tags: Array.from(new Set(['anvil', 'custom-scan-check', ...check.tags])),
    trust: 'local',
    summary: `${check.name} exported into a reusable custom scan-check library with importable .anvil source.`,
    content,
  };
}

function buildAnvilFixture(check: AnvilDefinition, exchange: HttpExchange, createdAt = new Date().toISOString()): AnvilFixture {
  const evaluation = evaluateAnvilSource(check.source, {
    requestRaw: exchange.requestRaw,
    responseRaw: exchange.responseRaw,
    targetUrl: exchange.url,
  });
  const expected: AnvilFixture['expected'] = evaluation.conditionCount
    ? (evaluation.matched ? 'match' : 'no-match')
    : (/support_admin|featureflags|internal\/export|admin|debug|internal/i.test(`${check.source}\n${exchange.responseRaw}`) ? 'match' : 'no-match');
  return {
    id: `anvil-fixture-${Date.now()}-${Math.random().toString(16).slice(2)}`,
    checkId: check.id,
    name: `${exchange.method} ${exchange.path} selected-message fixture`,
    createdAt,
    enabled: true,
    requestRaw: exchange.requestRaw,
    responseRaw: exchange.responseRaw,
    expected,
    status: 'untested',
    summary: `${expected === 'match' ? 'Positive' : 'Negative'} fixture from ${exchange.host}${exchange.path}; editable request and response test case for the custom scan checks editor.`,
    evidence: JSON.stringify({
      kind: 'proxyforge-anvil-fixture',
      checkId: check.id,
      exchangeId: exchange.id,
      expected,
      selectedMessage: `${exchange.method} ${exchange.url}`,
      compatibility: {
        mode: evaluation.mode,
        conditionCount: evaluation.conditionCount,
        operators: evaluation.operators,
        fields: evaluation.fields,
        evidence: evaluation.evidence,
      },
    }, null, 2),
  };
}

function fallbackAnvilEvaluation(matched: boolean, evidence: string): AnvilEvaluationResult {
  return {
    matched,
    conditionCount: 0,
    passedCount: matched ? 1 : 0,
    failedCount: matched ? 0 : 1,
    evidence: [evidence],
    fields: [],
    operators: [],
    mode: 'no-conditions',
  };
}

function evaluateAnvilFixture(check: AnvilDefinition, fixture: AnvilFixture): AnvilEvaluationResult {
  const compatibility = evaluateAnvilSource(check.source, {
    requestRaw: fixture.requestRaw,
    responseRaw: fixture.responseRaw,
  });
  if (compatibility.conditionCount) return compatibility;
  const corpus = `${fixture.requestRaw}\n${fixture.responseRaw}`;
  const source = check.source.toLowerCase();
  if (/support_admin|featureflags|internal\/export/i.test(check.source)) {
    const matched = /support_admin|featureflags|internal\/export/i.test(corpus);
    return fallbackAnvilEvaluation(matched, `${matched ? 'Matched' : 'Did not match'} privileged workflow marker fallback.`);
  }
  if (source.includes('content-security-policy')) {
    const matched = !/content-security-policy:/i.test(fixture.responseRaw);
    return fallbackAnvilEvaluation(matched, `${matched ? 'Missing' : 'Found'} Content-Security-Policy fallback.`);
  }
  if (source.includes('status_code') || source.includes('5[0-9][0-9]')) {
    const matched = /^HTTP\/\d(?:\.\d)?\s+5\d\d/im.test(fixture.responseRaw);
    return fallbackAnvilEvaluation(matched, `${matched ? 'Matched' : 'Did not match'} 5xx status fallback.`);
  }
  if (source.includes('x-content-type-options')) {
    const matched = !/x-content-type-options:/i.test(fixture.responseRaw);
    return fallbackAnvilEvaluation(matched, `${matched ? 'Missing' : 'Found'} X-Content-Type-Options fallback.`);
  }
  const matched = corpus.toLowerCase().includes(check.name.toLowerCase().split(/\s+/)[0] ?? 'proxyforge') || /internal|admin|debug/i.test(corpus);
  return fallbackAnvilEvaluation(matched, `${matched ? 'Matched' : 'Did not match'} generic Anvil fallback.`);
}

function buildAnvilValidationRun(check: AnvilDefinition, fixtures: AnvilFixture[], createdAt = new Date().toISOString()): AnvilValidationRun {
  const enabledFixtures = fixtures.filter((fixture) => fixture.checkId === check.id && fixture.enabled);
  if (!enabledFixtures.length) {
    return {
      id: `anvil-validation-${Date.now()}-${Math.random().toString(16).slice(2)}`,
      checkId: check.id,
      checkName: check.name,
      createdAt,
      status: 'blocked',
      fixtureCount: 0,
      passedCount: 0,
      failedCount: 0,
      requestCount: 0,
      issueCount: 0,
      errorCount: 1,
      auditItemCount: 0,
      loggerCount: 0,
      reportReady: false,
      summary: `${check.name} validation blocked because no enabled Anvil fixture test cases are available.`,
      fixtureResults: [],
      content: JSON.stringify({ kind: 'proxyforge-anvil-validation', blocked: true, reason: 'missing-fixtures', checkId: check.id }, null, 2),
    };
  }
  const evaluatedFixtures = enabledFixtures.map((fixture) => ({
    fixture,
    evaluation: evaluateAnvilFixture(check, fixture),
  }));
  const fixtureResults = evaluatedFixtures.map(({ fixture, evaluation }) => {
    const matched = evaluation.matched;
    const status = matched === (fixture.expected === 'match') ? 'passed' as const : 'failed' as const;
    return {
      fixtureId: fixture.id,
      name: fixture.name,
      expected: fixture.expected,
      matched,
      status,
      evidence: `${matched ? 'Matched' : 'Did not match'} fixture expectation ${fixture.expected}. ${evaluation.evidence.slice(0, 3).join(' ')}`,
    };
  });
  const passedCount = fixtureResults.filter((result) => result.status === 'passed').length;
  const failedCount = fixtureResults.length - passedCount;
  const issueCount = fixtureResults.filter((result) => result.matched).length;
  const runBase = {
    kind: 'proxyforge-anvil-validation',
    createdAt,
    check: {
      id: check.id,
      name: check.name,
      phase: check.phase,
      runScope: check.runScope,
      language: check.language,
    },
    editorPanels: ['audit items', 'issues', 'event log', 'logger'],
    fixtures: fixtureResults,
    metrics: {
      requestsSent: enabledFixtures.length,
      issuesRaised: issueCount,
      errorsFound: failedCount,
      auditItems: enabledFixtures.length,
      loggerEntries: enabledFixtures.length + issueCount,
    },
    compatibility: {
      conditionCount: evaluatedFixtures.reduce((total, item) => total + item.evaluation.conditionCount, 0),
      operators: Array.from(new Set(evaluatedFixtures.flatMap((item) => item.evaluation.operators))),
      fields: Array.from(new Set(evaluatedFixtures.flatMap((item) => item.evaluation.fields))),
    },
  };
  return {
    id: `anvil-validation-${Date.now()}-${Math.random().toString(16).slice(2)}`,
    checkId: check.id,
    checkName: check.name,
    createdAt,
    status: failedCount ? 'failed' : 'passed',
    fixtureCount: enabledFixtures.length,
    passedCount,
    failedCount,
    requestCount: enabledFixtures.length,
    issueCount,
    errorCount: failedCount,
    auditItemCount: enabledFixtures.length,
    loggerCount: enabledFixtures.length + issueCount,
    reportReady: failedCount === 0 && issueCount > 0,
    summary: `${check.name} fixture validation ${failedCount ? 'found errors' : 'passed'}: ${passedCount}/${enabledFixtures.length} test cases, ${issueCount} issue${issueCount === 1 ? '' : 's'} raised, logger evidence captured.`,
    fixtureResults,
    content: JSON.stringify(runBase, null, 2),
  };
}

function buildAnvilHeadlessRun(check: AnvilDefinition, targetUrl: string, exchanges: HttpExchange[], createdAt = new Date().toISOString()): AnvilHeadlessRun {
  const { host, path } = safeUrlParts(targetUrl);
  const scopedExchanges = exchanges.filter((exchange) => exchange.host === host || exchange.url === targetUrl).slice(0, 5);
  const candidateExchanges = scopedExchanges.length ? scopedExchanges : exchanges.slice(0, 1);
  const evaluatedExchanges = candidateExchanges.map((exchange) => ({
    exchange,
    evaluation: evaluateAnvilFixture(check, {
      id: `anvil-headless-fixture-${exchange.id}`,
      checkId: check.id,
      name: `${exchange.method} ${exchange.path} headless candidate`,
      createdAt,
      enabled: true,
      requestRaw: exchange.requestRaw,
      responseRaw: exchange.responseRaw,
      expected: 'match',
      status: 'untested',
      summary: `Headless Anvil candidate from ${exchange.host}${exchange.path}.`,
      evidence: '',
    }),
  }));
  const matchedExchanges = evaluatedExchanges.filter((item) => item.evaluation.matched);
  const requestCount = Math.max(1, candidateExchanges.length);
  const issueCount = matchedExchanges.length;
  const run = {
    kind: 'proxyforge-anvil-headless-run',
    createdAt,
    targetUrl,
    customOnlyScan: true,
    builtInChecksDisabled: true,
    extensionChecksDisabled: true,
    customChecks: [{
      id: check.id,
      name: check.name,
      phase: check.phase,
      runScope: check.runScope,
    }],
    scannerTabs: {
      auditItems: requestCount,
      issues: issueCount,
      eventLog: [
        `Queued ${check.name}`,
        `Audited ${host}${path}`,
        `Evaluated ${evaluatedExchanges.reduce((total, item) => total + item.evaluation.conditionCount, 0)} Anvil compatibility condition(s)`,
        'Saved logger traffic',
      ],
      logger: requestCount + issueCount,
    },
    compatibility: {
      mode: evaluatedExchanges.some((item) => item.evaluation.conditionCount > 0) ? 'source-conditions' : 'fallback',
      conditionCount: evaluatedExchanges.reduce((total, item) => total + item.evaluation.conditionCount, 0),
      operators: Array.from(new Set(evaluatedExchanges.flatMap((item) => item.evaluation.operators))),
      fields: Array.from(new Set(evaluatedExchanges.flatMap((item) => item.evaluation.fields))),
      matchedExchangeIds: matchedExchanges.map((item) => item.exchange.id),
      evidence: evaluatedExchanges.map((item) => ({
        exchangeId: item.exchange.id,
        matched: item.evaluation.matched,
        evidence: item.evaluation.evidence.slice(0, 4),
      })),
    },
  };
  return {
    id: `anvil-headless-${Date.now()}-${Math.random().toString(16).slice(2)}`,
    checkId: check.id,
    checkName: check.name,
    createdAt,
    targetUrl,
    status: 'complete',
    requestCount,
    issueCount,
    auditItemCount: requestCount,
    loggerCount: requestCount + issueCount,
    builtInChecksDisabled: true,
    extensionChecksDisabled: true,
    issueIds: matchedExchanges.map((item) => `anvil-issue-${check.id}-${item.exchange.id}`),
    exchangeIds: candidateExchanges.map((exchange) => exchange.id),
    reportReady: issueCount > 0,
    summary: `${check.name} headless custom-only scan completed for ${host}${path}: ${requestCount} request${requestCount === 1 ? '' : 's'}, ${issueCount} matched exchange${issueCount === 1 ? '' : 's'}, built-in and extension checks disabled.`,
    content: JSON.stringify(run, null, 2),
  };
}

function buildAnvilPackageReview(
  check: AnvilDefinition,
  library: AnvilRuleLibrary | undefined,
  validationRun: AnvilValidationRun | undefined,
  headlessRun: AnvilHeadlessRun | undefined,
  createdAt = new Date().toISOString(),
): AnvilPackageReview {
  const packageContent = JSON.stringify({
    check,
    library,
    validationRun,
    headlessRun,
  }, null, 2);
  const digestPreview = getSimpleDigestPreview(packageContent);
  const status: AnvilPackageReview['status'] = validationRun?.status === 'failed' ? 'warning' : 'trusted';
  const review: AnvilPackageReview = {
    id: `anvil-package-${Date.now()}-${Math.random().toString(16).slice(2)}`,
    checkId: check.id,
    libraryId: library?.id,
    title: `${check.name} signed package review`,
    fileName: `proxyforge-anvil-package-${createdAt.replace(/[:.]/g, '-')}.json`,
    path: `scanner/proxyforge-anvil-package-${createdAt.replace(/[:.]/g, '-')}.json`,
    reviewedAt: createdAt,
    status,
    packageDigest: digestPreview,
    signature: {
      algorithm: 'HMAC-SHA256',
      signerName: 'ProxyForge custom checks',
      keyId: 'anvil-local',
      status: 'verified',
      digestPreview,
    },
    reusableRuleCount: library?.ruleIds.length ?? 1,
    fixtureCount: validationRun?.fixtureCount ?? 0,
    findingCount: headlessRun?.issueCount ?? validationRun?.issueCount ?? 0,
    summary: `${check.name} package review ${status}: digest ${digestPreview}, ${library?.ruleIds.length ?? 1} reusable rule${(library?.ruleIds.length ?? 1) === 1 ? '' : 's'}, ${validationRun?.fixtureCount ?? 0} fixture${(validationRun?.fixtureCount ?? 0) === 1 ? '' : 's'}, ${headlessRun?.issueCount ?? validationRun?.issueCount ?? 0} finding${(headlessRun?.issueCount ?? validationRun?.issueCount ?? 0) === 1 ? '' : 's'}.`,
    content: '',
  };
  return {
    ...review,
    content: JSON.stringify({
      kind: 'proxyforge-anvil-package-review',
      reviewedAt: createdAt,
      status,
      digest: digestPreview,
      signature: review.signature,
      trust: {
        reusableRuleCount: review.reusableRuleCount,
        fixtureCount: review.fixtureCount,
        findingCount: review.findingCount,
        importedSource: library?.trust ?? 'local',
      },
      check: {
        id: check.id,
        name: check.name,
        language: check.language,
        phase: check.phase,
        runScope: check.runScope,
        tags: check.tags,
      },
    }, null, 2),
  };
}

function buildAnvilPromotedIssue(check: AnvilDefinition, run: AnvilHeadlessRun | AnvilValidationRun | undefined, exchange: HttpExchange): Issue {
  return {
    id: `anvil-promoted-${check.id}`,
    title: `Anvil: ${check.name}`,
    severity: check.severity,
    host: exchange.host,
    path: exchange.path,
    confidence: check.confidence,
    status: 'open',
    detail: `Anvil custom scan check evidence promoted from ${run ? ('targetUrl' in run ? 'headless execution' : 'fixture validation') : 'authoring review'}. ${run?.summary ?? check.summary}`,
    remediation: 'Review the reusable Anvil source, validate positive and negative fixtures, then remediate the matching application behavior before marking the report finding fixed.',
    triageNote: `Declarative Scan Check Generated via ProxyForge Anvil workflow. ${anvilPhaseLabels[check.phase]} · ${anvilRunScopeLabels[check.runScope]}.`,
  };
}

function buildAiContextBundle(
  projectName: string,
  scopeAllowlist: string[],
  task: AiTaskKind,
  selectedExchange: HttpExchange,
  exchanges: HttpExchange[],
  issues: Issue[],
) {
  const related = exchanges
    .filter((exchange) => exchange.id === selectedExchange.id || exchange.host === selectedExchange.host || exchange.tags.some((tag) => selectedExchange.tags.includes(tag)))
    .slice(0, 6);
  const selectedIssues = issues
    .filter((issue) => issue.host === selectedExchange.host || issue.path === selectedExchange.path || severityRank[issue.severity] >= severityRank.high)
    .slice(0, 8);

  return {
    projectName,
    scopeAllowlist,
    taskHint: aiTaskLabels[task],
    exchanges: related.map((exchange) => ({
      method: exchange.method,
      host: exchange.host,
      path: exchange.path,
      status: exchange.status,
      risk: exchange.risk,
      notes: exchange.notes,
      requestRaw: exchange.requestRaw,
      responseRaw: exchange.responseRaw,
      tags: exchange.tags,
    })),
    issues: selectedIssues.map((issue) => ({
      title: issue.title,
      severity: issue.severity,
      host: issue.host,
      path: issue.path,
      detail: issue.detail,
      remediation: issue.remediation,
    })),
  };
}

function mergeAiPromptTemplates(savedTemplates: AiPromptTemplate[]) {
  const byId = new Map(defaultAiPromptTemplates.map((template) => [template.id, template]));
  for (const template of savedTemplates) {
    if (!template.id || !template.prompt) continue;
    byId.set(template.id, { ...byId.get(template.id), ...template });
  }
  return Array.from(byId.values());
}

function estimateTokenCount(value: string) {
  return Math.max(1, Math.ceil(value.length / 4));
}

function estimateAiRunUsage(prompt: string, output: string, startedAt: string, completedAt: string, provider?: AiProviderRuntime): NonNullable<AiRunResult['usage']> {
  const promptTokens = estimateTokenCount(prompt);
  const completionTokens = estimateTokenCount(output);
  const inputRate = provider?.inputCostPerMillionTokens ?? 0;
  const outputRate = provider?.outputCostPerMillionTokens ?? 0;
  const started = new Date(startedAt).getTime();
  const completed = new Date(completedAt).getTime();

  return {
    promptTokens,
    completionTokens,
    totalTokens: promptTokens + completionTokens,
    estimatedCostUsd: (promptTokens / 1_000_000) * inputRate + (completionTokens / 1_000_000) * outputRate,
    latencyMs: Number.isFinite(started) && Number.isFinite(completed) ? Math.max(0, completed - started) : 0,
    source: 'estimated',
  };
}

function buildPromptEvaluation(prompt: string, provider: AiProviderRuntime | undefined, task: AiTaskKind, context: ReturnType<typeof buildAiContextBundle>): NonNullable<AiRunResult['promptEvaluation']> {
  const providerId = provider?.id ?? 'local';
  const model = provider?.model ?? 'unconfigured';
  const fullPrompt = `${prompt}\n${task}\n${context.taskHint}`;
  const checks: NonNullable<AiRunResult['promptEvaluation']>['checks'] = [
    {
      label: 'Scope boundary',
      status: /scope|authorized|allowlist|engagement/i.test(fullPrompt) ? 'ready' : 'warning',
      detail: /scope|authorized|allowlist|engagement/i.test(fullPrompt) ? 'Scope or authorization is explicit.' : 'Add explicit scope and authorization boundaries.',
    },
    {
      label: 'Evidence request',
      status: /evidence|request|response|finding|issue/i.test(fullPrompt) ? 'ready' : 'warning',
      detail: /evidence|request|response|finding|issue/i.test(fullPrompt) ? 'Evidence-linked reasoning is requested.' : 'Ask for request, response, finding, or issue references.',
    },
    {
      label: 'Safety gates',
      status: /safe|non-destructive|approval|rate|throttle|stop/i.test(fullPrompt) ? 'ready' : 'warning',
      detail: /safe|non-destructive|approval|rate|throttle|stop/i.test(fullPrompt) ? 'Safety or stop-condition language is present.' : 'Add stop conditions, approval gates, or throttling expectations.',
    },
    {
      label: providerId === 'codex' ? 'Codex execution shape' : providerId === 'claude' ? 'Claude structure' : 'Local model brevity',
      status: providerId === 'local'
        ? fullPrompt.length < 2400 ? 'ready' : 'warning'
        : providerId === 'codex'
          ? /file|command|test|diff|implement|verify/i.test(fullPrompt) ? 'ready' : 'warning'
          : /section|bullet|assumption|xml/i.test(fullPrompt) ? 'ready' : 'warning',
      detail: providerId === 'local'
        ? fullPrompt.length < 2400 ? 'Prompt is compact enough for smaller local models.' : 'Shorten local-model prompts or reduce context.'
        : providerId === 'codex'
          ? /file|command|test|diff|implement|verify/i.test(fullPrompt) ? 'Codex has implementation or verification shape.' : 'Codex prompts work better with files, commands, expected diffs, or verification gates.'
          : /section|bullet|assumption|xml/i.test(fullPrompt) ? 'Claude has structure or assumption-handling cues.' : 'Claude prompts work better with sections and explicit assumptions.',
    },
  ];
  const ready = checks.filter((check) => check.status === 'ready').length;
  return {
    score: Math.round((ready / checks.length) * 100),
    providerId,
    model,
    checks,
    recommendations: checks.filter((check) => check.status !== 'ready').map((check) => check.detail).slice(0, 5),
  };
}

function buildAiEvaluationBaseline(
  provider: AiProviderRuntime,
  task: AiTaskKind,
  prompt: string,
  contextDigest: string,
  evaluation: AiRunResult['promptEvaluation'],
  usage?: AiRunResult['usage'],
  existing?: AiEvaluationBaseline,
): AiEvaluationBaseline {
  const now = new Date().toISOString();
  const name = `${provider.label} ${aiTaskLabels[task]} baseline`;
  return {
    id: existing?.id ?? `ai-baseline-${Date.now()}-${Math.random().toString(16).slice(2)}`,
    name,
    providerId: provider.id,
    providerLabel: provider.label,
    model: provider.model,
    task,
    prompt,
    contextDigest,
    score: evaluation?.score ?? 0,
    usage,
    checks: evaluation?.checks ?? [],
    notes: `${name} saved with score ${evaluation?.score ?? 0}.`,
    createdAt: existing?.createdAt ?? now,
    updatedAt: now,
  };
}

function buildAiPromptComparisons(
  providers: AiProviderRuntime[],
  task: AiTaskKind,
  prompt: string,
  context: ReturnType<typeof buildAiContextBundle>,
  contextDigest: string,
  baseline?: AiEvaluationBaseline,
): AiPromptComparison[] {
  const createdAt = new Date().toISOString();
  const baselineChecks = new Map((baseline?.checks ?? []).map((check) => [check.label, check.status]));
  return providers.map((provider) => {
    const evaluation = buildPromptEvaluation(prompt, provider, task, context);
    const usage = estimateAiRunUsage(prompt, '', createdAt, createdAt, provider);
    const scoreDelta = baseline ? evaluation.score - baseline.score : 0;
    const checkDelta = evaluation.checks
      .filter((check) => baselineChecks.get(check.label) !== undefined && baselineChecks.get(check.label) !== check.status)
      .map((check) => `${check.label}: ${baselineChecks.get(check.label)} -> ${check.status}`);
    const verdict: AiPromptComparison['verdict'] = baseline === undefined
      ? 'unbaselined'
      : scoreDelta >= 10
        ? 'improved'
        : scoreDelta <= -10
          ? 'regressed'
          : 'similar';
    return {
      id: `ai-compare-${provider.id}-${Date.now()}-${Math.random().toString(16).slice(2)}`,
      createdAt,
      baselineId: baseline?.id,
      providerId: provider.id,
      providerLabel: provider.label,
      model: provider.model,
      task,
      score: evaluation.score,
      scoreDelta,
      promptTokens: usage.promptTokens,
      estimatedCostUsd: usage.estimatedCostUsd,
      checkDelta,
      verdict,
      notes: baseline
        ? `${provider.label} ${aiTaskLabels[task]} scored ${evaluation.score}, ${formatSignedDelta(scoreDelta)} from ${baseline.providerLabel} baseline.`
        : `${provider.label} ${aiTaskLabels[task]} scored ${evaluation.score} without a saved baseline.`,
    } satisfies AiPromptComparison;
  }).sort((left, right) => right.score - left.score);
}

function buildAiBaselineLibraryPackage(
  projectName: string,
  scopeAllowlist: string[],
  baselines: AiEvaluationBaseline[],
  comparisons: AiPromptComparison[],
  benchmarkRuns: AiBenchmarkRun[],
) {
  return {
    version: 1,
    kind: 'proxyforge-ai-baseline-library',
    exportedAt: new Date().toISOString(),
    projectName,
    scopeAllowlist,
    baselines,
    comparisons,
    benchmarkRuns,
  };
}

function isAiEvaluationBaseline(value: unknown): value is AiEvaluationBaseline {
  const candidate = value as Partial<AiEvaluationBaseline> | undefined;
  return Boolean(candidate?.id && candidate.providerId && candidate.task && typeof candidate.prompt === 'string' && typeof candidate.score === 'number');
}

function isAiPromptComparison(value: unknown): value is AiPromptComparison {
  const candidate = value as Partial<AiPromptComparison> | undefined;
  return Boolean(candidate?.id && candidate.providerId && candidate.task && typeof candidate.score === 'number' && typeof candidate.notes === 'string');
}

function isAiBenchmarkRun(value: unknown): value is AiBenchmarkRun {
  const candidate = value as Partial<AiBenchmarkRun> | undefined;
  return Boolean(candidate?.id && candidate.projectName && Array.isArray(candidate.results) && typeof candidate.averageScore === 'number');
}

function parseAiBaselineLibraryText(value: string) {
  const parsed = JSON.parse(value) as {
    kind?: string;
    projectName?: string;
    baselines?: unknown[];
    comparisons?: unknown[];
    benchmarkRuns?: unknown[];
    aiEvaluationBaselines?: unknown[];
    aiPromptComparisons?: unknown[];
    aiBenchmarkRuns?: unknown[];
  };
  const baselineItems = parsed.kind === 'proxyforge-ai-baseline-library'
    ? parsed.baselines ?? []
    : parsed.aiEvaluationBaselines ?? parsed.baselines ?? [];
  const comparisonItems = parsed.kind === 'proxyforge-ai-baseline-library'
    ? parsed.comparisons ?? []
    : parsed.aiPromptComparisons ?? parsed.comparisons ?? [];
  const benchmarkItems = parsed.kind === 'proxyforge-ai-baseline-library'
    ? parsed.benchmarkRuns ?? []
    : parsed.aiBenchmarkRuns ?? parsed.benchmarkRuns ?? [];

  return {
    projectName: parsed.projectName,
    baselines: baselineItems.filter(isAiEvaluationBaseline).slice(0, 80),
    comparisons: comparisonItems.filter(isAiPromptComparison).slice(0, 120),
    benchmarkRuns: benchmarkItems.filter(isAiBenchmarkRun).slice(0, 30),
  };
}

function mergeById<T extends { id: string }>(current: T[], imported: T[], limit: number) {
  const byId = new Map(current.map((item) => [item.id, item]));
  for (const item of imported) byId.set(item.id, item);
  return Array.from(byId.values()).slice(0, limit);
}

function selectBenchmarkExchange(exchanges: HttpExchange[], baseline: AiEvaluationBaseline) {
  const target = baseline.contextDigest.split(' · ')[0];
  return exchanges.find((exchange) => `${exchange.method} ${exchange.host}${exchange.path}` === target) ?? exchanges[0] ?? seedExchanges[0];
}

function buildAiBenchmarkReplayRun(providers: AiProviderRuntime[], snapshot: ProjectSnapshot): AiBenchmarkRun {
  const projectBaselines = (snapshot.aiEvaluationBaselines ?? []).filter(isAiEvaluationBaseline).slice(0, 80);
  const projectExchanges = snapshot.exchanges.length ? snapshot.exchanges : seedExchanges;
  const projectIssues = mergeIssues(seedIssues, [
    ...buildPassiveIssues(projectExchanges),
    ...(snapshot.importedBundleIssues ?? []),
  ]);
  const projectName = snapshot.projectName || 'Imported project';
  const scope = snapshot.scopeAllowlist;
  const results = projectBaselines.flatMap((baseline) => {
    const selected = selectBenchmarkExchange(projectExchanges, baseline);
    const context = buildAiContextBundle(projectName, scope, baseline.task, selected, projectExchanges, projectIssues);
    const contextDigest = aiContextDigest(context);
    return buildAiPromptComparisons(providers, baseline.task, baseline.prompt, context, contextDigest, baseline).map((comparison) => ({
      ...comparison,
      id: `ai-benchmark-${baseline.id}-${comparison.providerId}-${Date.now()}-${Math.random().toString(16).slice(2)}`,
      baselineName: baseline.name,
      baselineScore: baseline.score,
      projectName,
      contextDigest,
    }));
  });
  const averageScore = results.length
    ? Math.round(results.reduce((sum, result) => sum + result.score, 0) / results.length)
    : 0;
  const improvedCount = results.filter((result) => result.verdict === 'improved').length;
  const regressedCount = results.filter((result) => result.verdict === 'regressed').length;
  const unbaselinedCount = results.filter((result) => result.verdict === 'unbaselined').length;

  return {
    id: `ai-benchmark-${Date.now()}-${Math.random().toString(16).slice(2)}`,
    createdAt: new Date().toISOString(),
    projectName,
    projectSavedAt: snapshot.savedAt,
    providerCount: providers.length,
    baselineCount: projectBaselines.length,
    resultCount: results.length,
    averageScore,
    improvedCount,
    regressedCount,
    unbaselinedCount,
    results,
    notes: `${projectBaselines.length} baseline case${projectBaselines.length === 1 ? '' : 's'} replayed across ${providers.length} provider profile${providers.length === 1 ? '' : 's'}.`,
  };
}

function formatUsd(value: number) {
  if (value === 0) return '$0.0000';
  if (value < 0.0001) return '<$0.0001';
  return `$${value.toFixed(4)}`;
}

function aiContextDigest(context: ReturnType<typeof buildAiContextBundle>) {
  const selected = context.exchanges[0];
  return [
    selected ? `${selected.method} ${selected.host}${selected.path}` : 'No exchange',
    `${context.exchanges.length} exchanges`,
    `${context.issues.length} issues`,
  ].join(' · ');
}

function splitHttpMessage(raw: string) {
  const [head, ...rest] = raw.split(/\r?\n\r?\n/);
  return {
    head: head ?? '',
    body: rest.join('\n\n'),
  };
}

function parseJsonBody(raw: string) {
  const { body } = splitHttpMessage(raw);
  const candidate = body.trim() || raw.trim();
  if (!candidate) return null;
  try {
    return JSON.stringify(JSON.parse(candidate), null, 2);
  } catch {
    return null;
  }
}

function decodeBase64Url(value: string) {
  const normalized = value.replace(/-/g, '+').replace(/_/g, '/');
  const padded = normalized.padEnd(Math.ceil(normalized.length / 4) * 4, '=');
  try {
    return decodeURIComponent(Array.from(atob(padded), (char) => `%${char.charCodeAt(0).toString(16).padStart(2, '0')}`).join(''));
  } catch {
    return '';
  }
}

function buildJwtViewer(exchange: HttpExchange) {
  const haystack = `${exchange.requestRaw}\n${exchange.responseRaw}`;
  const token = haystack.match(/\b[A-Za-z0-9_-]{8,}\.[A-Za-z0-9_-]{8,}\.[A-Za-z0-9_-]{8,}\b/)?.[0];
  if (!token) {
    return 'No complete JWT was found in the selected request or response. Use Decoder for pasted tokens, or select traffic with an Authorization bearer/JWT cookie.';
  }
  const [header, payload, signature] = token.split('.');
  const decodedHeader = decodeBase64Url(header);
  const decodedPayload = decodeBase64Url(payload);
  return [
    'JWT token decoded from selected traffic',
    '',
    'Header:',
    prettyJsonOrRaw(decodedHeader),
    '',
    'Payload:',
    prettyJsonOrRaw(decodedPayload),
    '',
    `Signature: ${signature ? `${signature.slice(0, 16)}... (${signature.length} chars)` : 'none'}`,
  ].join('\n');
}

function prettyJsonOrRaw(value: string) {
  if (!value) return '[decode failed]';
  try {
    return JSON.stringify(JSON.parse(value), null, 2);
  } catch {
    return value;
  }
}

function buildGraphQlViewer(exchange: HttpExchange) {
  const { body } = splitHttpMessage(exchange.requestRaw);
  const parsed = body.trim() ? safeParseJson(body) : null;
  const query = typeof parsed?.query === 'string' ? parsed.query : body.match(/\b(query|mutation|subscription)\b[\s\S]+/)?.[0];
  if (!query) {
    return [
      'No GraphQL document was detected in the selected request body.',
      '',
      `Selected target: ${exchange.method} ${exchange.host}${exchange.path}`,
      'GraphQL requests with JSON bodies render query, variables, and operation name here.',
    ].join('\n');
  }
  return [
    `Operation: ${typeof parsed?.operationName === 'string' ? parsed.operationName : 'not specified'}`,
    '',
    'Query:',
    query,
    '',
    'Variables:',
    parsed?.variables ? JSON.stringify(parsed.variables, null, 2) : '{}',
  ].join('\n');
}

function safeParseJson(value: string): Record<string, unknown> | null {
  try {
    const parsed = JSON.parse(value) as unknown;
    return parsed && typeof parsed === 'object' && !Array.isArray(parsed) ? parsed as Record<string, unknown> : null;
  } catch {
    return null;
  }
}

function hexDump(value: string) {
  const bytes = Array.from(new TextEncoder().encode(value));
  return bytes.slice(0, 2048).reduce<string[]>((rows, byte, index) => {
    if (index % 16 === 0) rows.push(`${index.toString(16).padStart(8, '0')}  `);
    rows[rows.length - 1] += `${byte.toString(16).padStart(2, '0')} `;
    if (index % 16 === 15) {
      const start = index - 15;
      const ascii = bytes.slice(start, index + 1).map((item) => (item >= 32 && item < 127 ? String.fromCharCode(item) : '.')).join('');
      rows[rows.length - 1] += ` ${ascii}`;
    }
    return rows;
  }, []).join('\n') || 'No bytes available.';
}

function buildHttpViewerOutput(mode: ViewerMode, exchange: HttpExchange) {
  const requestBodyJson = parseJsonBody(exchange.requestRaw);
  const responseBodyJson = parseJsonBody(exchange.responseRaw);
  const responseBody = splitHttpMessage(exchange.responseRaw).body.trim();

  if (mode === 'json') {
    return {
      title: 'Pretty JSON',
      output: [
        'Request JSON:',
        requestBodyJson ?? 'No JSON request body detected.',
        '',
        'Response JSON:',
        responseBodyJson ?? 'No JSON response body detected.',
      ].join('\n'),
    };
  }
  if (mode === 'html') {
    return {
      title: 'HTML Viewer',
      output: exchange.mime.includes('html')
        ? responseBody
        : `Selected response MIME is ${exchange.mime}; no HTML body was detected.`,
    };
  }
  if (mode === 'jwt') {
    return { title: 'JWT Viewer', output: buildJwtViewer(exchange) };
  }
  if (mode === 'graphql') {
    return { title: 'GraphQL Viewer', output: buildGraphQlViewer(exchange) };
  }
  if (mode === 'image') {
    return {
      title: 'Image Viewer',
      output: exchange.mime.startsWith('image/')
        ? `Image response selected: ${exchange.mime}, ${formatBytes(exchange.length)} from ${exchange.url}`
        : `Selected response MIME is ${exchange.mime}; image preview is available for image/* responses.`,
    };
  }
  if (mode === 'binary') {
    return {
      title: 'Binary Viewer',
      output: [
        `Hex dump of response bytes (${Math.min(new TextEncoder().encode(exchange.responseRaw).length, 2048)} byte preview)`,
        '',
        hexDump(exchange.responseRaw),
      ].join('\n'),
    };
  }
  return {
    title: 'Raw Request / Response',
    output: [exchange.requestRaw.trim(), '', '--- response ---', '', exchange.responseRaw.trim()].join('\n'),
  };
}

interface BundleVerificationState {
  status: 'idle' | 'valid' | 'invalid' | 'error';
  message: string;
  signerName?: string;
  keyId?: string;
  digest?: string;
  signedAt?: string;
  findings?: number;
  evidence?: number;
  governanceAttestation?: ReportGovernanceAttestation;
}

type BundleMergeMode = 'new-only' | 'replace-conflicts';

interface BundleMergeFindingPreview {
  key: string;
  title: string;
  host: string;
  path: string;
  severity: Severity;
  state: 'new' | 'conflict';
  localSeverity?: Severity;
  localStatus?: Issue['status'];
}

interface BundleMergeEvidencePreview {
  key: string;
  method: string;
  url: string;
  status: number;
  state: 'new' | 'duplicate';
}

interface BundleMergePreview {
  status: 'idle' | 'ready' | 'error';
  message: string;
  projectName?: string;
  totalFindings: number;
  newFindings: number;
  conflictFindings: number;
  totalEvidence: number;
  newEvidence: number;
  duplicateEvidence: number;
  findings: BundleMergeFindingPreview[];
  evidence: BundleMergeEvidencePreview[];
}

interface ReportTemplateTransfer {
  kind: 'proxyforge-report-template';
  version: 1;
  exportedAt: string;
  name: string;
  body: string;
  placeholders: string[];
}

interface EvidenceBundleSignature {
  algorithm?: string;
  canonicalization?: string;
  signerName?: string;
  keyId?: string;
  signedAt?: string;
  bundleDigestSha256?: string;
  signature?: string;
}

interface ImportedEvidenceBundle {
  manifest?: {
    kind?: string;
    projectName?: string;
    brandName?: string;
    engagementId?: string;
  };
  signature?: EvidenceBundleSignature;
  governanceAttestation?: ReportGovernanceAttestation;
  findings?: Array<Record<string, unknown>>;
  evidence?: Array<Record<string, unknown>>;
}

function emptyBundleMergePreview(message = 'Verify a signed evidence bundle, then preview the merge before importing.') : BundleMergePreview {
  return {
    status: 'idle',
    message,
    totalFindings: 0,
    newFindings: 0,
    conflictFindings: 0,
    totalEvidence: 0,
    newEvidence: 0,
    duplicateEvidence: 0,
    findings: [],
    evidence: [],
  };
}

function buildReportTemplateTransfer(name: string, body: string): ReportTemplateTransfer {
  return {
    kind: 'proxyforge-report-template',
    version: 1,
    exportedAt: new Date().toISOString(),
    name: name.trim() || 'Custom operator template',
    body: body.trim() || defaultReportCustomTemplate,
    placeholders: [
      'projectName',
      'preparedFor',
      'brandName',
      'engagementId',
      'generatedAt',
      'scope',
      'summary.totalIssues',
      'summary.openIssues',
      'summary.highOrCritical',
      'summary.affectedHosts',
      'summary.evidenceItems',
      'executiveMarkdown',
      'findingsMarkdown',
      'evidenceMarkdown',
      'appendixMarkdown',
    ],
  };
}

function parseReportTemplateTransfer(templateText: string): ReportTemplateTransfer {
  const parsed = JSON.parse(templateText) as Partial<ReportTemplateTransfer>;
  if (parsed.kind !== 'proxyforge-report-template' || parsed.version !== 1) {
    throw new Error('Template JSON must be a ProxyForge report template v1.');
  }
  if (typeof parsed.name !== 'string' || typeof parsed.body !== 'string' || !parsed.body.trim()) {
    throw new Error('Template JSON must include a name and body.');
  }
  return {
    kind: 'proxyforge-report-template',
    version: 1,
    exportedAt: typeof parsed.exportedAt === 'string' ? parsed.exportedAt : new Date().toISOString(),
    name: parsed.name.trim().slice(0, 120) || 'Custom operator template',
    body: parsed.body.slice(0, 30000),
    placeholders: Array.isArray(parsed.placeholders) ? parsed.placeholders.filter((item): item is string => typeof item === 'string') : [],
  };
}

async function verifyEvidenceBundleSignature(bundleText: string, secret: string): Promise<BundleVerificationState> {
  let bundle: Record<string, unknown>;
  try {
    bundle = JSON.parse(bundleText) as Record<string, unknown>;
  } catch {
    return { status: 'error', message: 'Bundle JSON could not be parsed.' };
  }

  const manifest = bundle.manifest as Record<string, unknown> | undefined;
  const signature = bundle.signature as EvidenceBundleSignature | undefined;
  if (manifest?.kind !== 'proxyforge-evidence-bundle') {
    return { status: 'error', message: 'This is not a ProxyForge evidence bundle.' };
  }
  if (!signature?.signature || !signature.bundleDigestSha256) {
    return { status: 'invalid', message: 'Bundle has no signature block to verify.' };
  }
  if (signature.algorithm !== 'HMAC-SHA256') {
    return { status: 'invalid', message: `Unsupported signature algorithm: ${signature.algorithm ?? 'unknown'}.` };
  }
  if (!secret.trim()) {
    return { status: 'invalid', message: 'Verification secret is required for HMAC-SHA256 bundles.' };
  }
  if (!globalThis.crypto?.subtle) {
    return { status: 'error', message: 'Web Crypto is unavailable in this runtime.' };
  }

  const unsignedBundle = { ...bundle };
  delete unsignedBundle.signature;
  const canonical = canonicalizeEvidenceBundle(unsignedBundle);
  const digest = await sha256Hex(canonical);
  const key = await globalThis.crypto.subtle.importKey(
    'raw',
    new TextEncoder().encode(secret),
    { name: 'HMAC', hash: 'SHA-256' },
    false,
    ['sign'],
  );
  const computedSignature = bufferToHex(await globalThis.crypto.subtle.sign('HMAC', key, new TextEncoder().encode(canonical)));
  const digestMatches = digest.toLowerCase() === signature.bundleDigestSha256.toLowerCase();
  const signatureMatches = computedSignature.toLowerCase() === signature.signature.toLowerCase();
  const findings = Array.isArray(bundle.findings) ? bundle.findings.length : 0;
  const evidence = Array.isArray(bundle.evidence) ? bundle.evidence.length : 0;
  const governanceAttestation = normalizeReportGovernanceAttestation(bundle.governanceAttestation);

  return {
    status: digestMatches && signatureMatches ? 'valid' : 'invalid',
    message: digestMatches && signatureMatches
      ? `Signature valid. Bundle contents match the signed digest.${governanceAttestation ? ` Governance attestation ${governanceAttestation.status} for ${governanceAttestation.teamName} with ${governanceAttestation.runnerBindingCount} runner binding(s).` : ''}`
      : 'Signature invalid. Bundle content or signing key does not match.',
    signerName: signature.signerName,
    keyId: signature.keyId,
    digest,
    signedAt: signature.signedAt,
    findings,
    evidence,
    governanceAttestation,
  };
}

function parseImportedEvidenceBundle(bundleText: string) {
  const bundle = JSON.parse(bundleText) as ImportedEvidenceBundle;
  if (bundle.manifest?.kind !== 'proxyforge-evidence-bundle') {
    throw new Error('This is not a ProxyForge evidence bundle.');
  }
  return bundle;
}

function normalizeReportGovernanceAttestation(value: unknown): ReportGovernanceAttestation | undefined {
  if (!value || typeof value !== 'object' || Array.isArray(value)) return undefined;
  const candidate = value as Partial<ReportGovernanceAttestation>;
  const signature = candidate.signature && typeof candidate.signature === 'object' ? candidate.signature : undefined;
  const status = ['active', 'reviewed', 'signed', 'missing'].includes(String(candidate.status)) ? candidate.status as ReportGovernanceAttestation['status'] : 'missing';
  const signatureStatus = ['active', 'reviewed', 'signed', 'missing'].includes(String(signature?.status))
    ? signature?.status as ReportGovernanceAttestation['signature']['status']
    : status === 'active' || status === 'reviewed' || status === 'signed' ? status : 'missing';
  return {
    packageId: stringValue(candidate.packageId, 'no-active-governance-package'),
    title: stringValue(candidate.title, 'No active governance policy'),
    teamName: stringValue(candidate.teamName, 'Local project policy'),
    activeOperator: stringValue(candidate.activeOperator, 'unassigned'),
    operatorRole: stringValue(candidate.operatorRole, 'operator'),
    status,
    exportedAt: typeof candidate.exportedAt === 'string' ? candidate.exportedAt : undefined,
    reviewedAt: typeof candidate.reviewedAt === 'string' ? candidate.reviewedAt : undefined,
    activatedAt: typeof candidate.activatedAt === 'string' ? candidate.activatedAt : undefined,
    signature: {
      algorithm: 'HMAC-SHA256',
      signerName: stringValue(signature?.signerName, 'ProxyForge Governance'),
      keyId: stringValue(signature?.keyId, 'missing-governance-key'),
      status: signatureStatus,
      digestPreview: stringValue(signature?.digestPreview, 'missing'),
    },
    runnerBindingCount: numberValue(candidate.runnerBindingCount, 0),
    approvalRequiredCount: numberValue(candidate.approvalRequiredCount, 0),
    scopeGateSummary: stringValue(candidate.scopeGateSummary, 'Scope gate not attested'),
    rateGateSummary: stringValue(candidate.rateGateSummary, 'Rate gate not attested'),
    approvalGateSummary: stringValue(candidate.approvalGateSummary, 'Approval gate not attested'),
    ciHeadlessSummary: stringValue(candidate.ciHeadlessSummary, 'CI/headless gate not attested'),
  };
}

function buildEvidenceBundleMergePreview(
  bundleText: string,
  verified: BundleVerificationState,
  currentIssues: Issue[],
  currentExchanges: HttpExchange[],
): BundleMergePreview {
  if (verified.status !== 'valid') {
    throw new Error('Verify the bundle before previewing merge impact.');
  }
  const bundle = parseImportedEvidenceBundle(bundleText);
  const localIssues = new Map(currentIssues.map((issue) => [issueMergeKey(issue), issue]));
  const localEvidence = new Set(currentExchanges.map(exchangeMergeKey));
  const findings = (bundle.findings ?? []).map((finding, index) => {
    const preview = bundleFindingPreview(finding, index);
    const local = localIssues.get(preview.key);
    return {
      ...preview,
      state: local ? 'conflict' : 'new',
      localSeverity: local?.severity,
      localStatus: local?.status,
    } satisfies BundleMergeFindingPreview;
  });
  const evidence = (bundle.evidence ?? []).map((item, index) => {
    const preview = bundleEvidencePreview(item, index);
    return {
      ...preview,
      state: localEvidence.has(preview.key) ? 'duplicate' : 'new',
    } satisfies BundleMergeEvidencePreview;
  });
  const newFindings = findings.filter((finding) => finding.state === 'new').length;
  const conflictFindings = findings.length - newFindings;
  const newEvidence = evidence.filter((item) => item.state === 'new').length;
  const duplicateEvidence = evidence.length - newEvidence;
  return {
    status: 'ready',
    message: `${newFindings} new findings, ${conflictFindings} finding conflicts, ${newEvidence} new evidence items, ${duplicateEvidence} duplicate evidence items.`,
    projectName: bundle.manifest?.projectName,
    totalFindings: findings.length,
    newFindings,
    conflictFindings,
    totalEvidence: evidence.length,
    newEvidence,
    duplicateEvidence,
    findings: findings.slice(0, 8),
    evidence: evidence.slice(0, 8),
  };
}

function importVerifiedEvidenceBundle(bundleText: string, verified: BundleVerificationState) {
  if (verified.status !== 'valid') {
    throw new Error('Verify the bundle before importing findings and evidence.');
  }
  const bundle = parseImportedEvidenceBundle(bundleText);
  const stamp = Date.now();
  const keyId = sanitizeImportId(verified.keyId ?? bundle.signature?.keyId ?? 'bundle');
  const importedIssues = (bundle.findings ?? []).map((finding, index) => importedIssueFromBundleFinding(finding, keyId, stamp, index, verified, bundle));
  const importedExchanges = (bundle.evidence ?? []).map((evidence, index) => importedExchangeFromBundleEvidence(evidence, keyId, stamp, index, verified, bundle));
  return { importedIssues, importedExchanges };
}

function issueMergeKey(issue: Pick<Issue, 'title' | 'host' | 'path'>) {
  return `${normalizeMergeValue(issue.title)}:${normalizeMergeValue(issue.host)}:${normalizeMergeValue(issue.path)}`;
}

function exchangeMergeKey(exchange: Pick<HttpExchange, 'method' | 'url' | 'status'>) {
  return `${normalizeMergeValue(exchange.method)}:${normalizeMergeValue(exchange.url)}:${exchange.status}`;
}

function bundleFindingPreview(finding: Record<string, unknown>, index: number) {
  const title = stringValue(finding.title, `Imported bundle finding ${index + 1}`);
  const host = stringValue(finding.host, 'imported.bundle.local');
  const path = stringValue(finding.path, '/imported-evidence');
  return {
    key: issueMergeKey({ title, host, path }),
    title,
    host,
    path,
    severity: severityValue(finding.severity, 'info'),
  };
}

function bundleEvidencePreview(evidence: Record<string, unknown>, index: number) {
  const request = objectValue(evidence.request);
  const response = objectValue(evidence.response);
  const metadata = objectValue(evidence.metadata);
  const fallbackUrl = `https://${stringValue(metadata.host, 'imported.bundle.local')}${stringValue(metadata.path, `/imported-evidence-${index + 1}`)}`;
  const url = stringValue(request.url, fallbackUrl);
  const method = stringValue(request.method, 'GET').toUpperCase();
  const status = numberValue(response.status, 0);
  return {
    key: `${normalizeMergeValue(method)}:${normalizeMergeValue(url)}:${status}`,
    method,
    url,
    status,
  };
}

function normalizeMergeValue(value: string) {
  return value.trim().toLowerCase().replace(/\s+/g, ' ');
}

function importedIssueFromBundleFinding(
  finding: Record<string, unknown>,
  keyId: string,
  stamp: number,
  index: number,
  verified: BundleVerificationState,
  bundle: ImportedEvidenceBundle,
): Issue {
  const host = stringValue(finding.host, 'imported.bundle.local');
  const path = stringValue(finding.path, '/imported-evidence');
  const title = stringValue(finding.title, `Imported bundle finding ${index + 1}`);
  return {
    id: `bundle-issue-${keyId}-${stamp}-${sanitizeImportId(stringValue(finding.id, String(index)))}`,
    title,
    severity: severityValue(finding.severity, 'info'),
    host,
    path,
    confidence: confidenceValue(finding.confidence, 'firm'),
    status: issueStatusValue(finding.status, 'open'),
    detail: stringValue(
      finding.detail,
      `Imported from verified evidence bundle${bundle.manifest?.projectName ? ` for ${bundle.manifest.projectName}` : ''}. Signature signer: ${verified.signerName ?? 'unknown'}.`,
    ),
    remediation: stringValue(finding.remediation, 'Review the imported evidence and attach local validation before closure.'),
    triageNote: `Imported verified bundle ${verified.keyId ?? keyId}; digest ${verified.digest?.slice(0, 16) ?? 'unknown'}.`,
    lastTriagedAt: new Date(stamp).toISOString(),
  };
}

function importedExchangeFromBundleEvidence(
  evidence: Record<string, unknown>,
  keyId: string,
  stamp: number,
  index: number,
  verified: BundleVerificationState,
  bundle: ImportedEvidenceBundle,
): HttpExchange {
  const request = objectValue(evidence.request);
  const response = objectValue(evidence.response);
  const metadata = objectValue(evidence.metadata);
  const url = stringValue(request.url, `https://${stringValue(metadata.host, 'imported.bundle.local')}${stringValue(metadata.path, '/imported-evidence')}`);
  const parsed = parseUrlParts(url);
  const host = stringValue(metadata.host, parsed.host);
  const path = stringValue(metadata.path, parsed.path);
  const rawResponse = stringValue(response.raw, `HTTP/2 ${numberValue(response.status, 0)} Imported\r\n\r\n`);
  return {
    id: `bundle-evidence-${keyId}-${stamp}-${sanitizeImportId(stringValue(evidence.id, String(index)))}`,
    method: stringValue(request.method, 'GET'),
    host,
    path,
    url,
    status: numberValue(response.status, 0),
    length: numberValue(response.length, rawResponse.length),
    mime: stringValue(response.mime, 'application/octet-stream'),
    risk: severityValue(metadata.risk, 'info'),
    timing: 0,
    notes: `${stringValue(metadata.notes, 'Imported evidence bundle item')} · verified ${verified.keyId ?? bundle.signature?.keyId ?? keyId}`,
    source: 'demo',
    time: new Date(stamp).toLocaleTimeString([], { hour12: false }),
    requestRaw: stringValue(request.raw, `${stringValue(request.method, 'GET')} ${path} HTTP/2\r\nHost: ${host}\r\n\r\n`),
    responseRaw: rawResponse,
    tags: [...arrayOfStrings(metadata.tags), 'bundle-import', 'verified-evidence'],
  };
}

function parseUrlParts(value: string) {
  try {
    const url = new URL(value);
    return { host: url.host, path: `${url.pathname}${url.search}` || '/' };
  } catch {
    return { host: 'imported.bundle.local', path: '/imported-evidence' };
  }
}

function stringValue(value: unknown, fallback: string) {
  return typeof value === 'string' && value.trim() ? value : fallback;
}

function numberValue(value: unknown, fallback: number) {
  return typeof value === 'number' && Number.isFinite(value) ? value : fallback;
}

function objectValue(value: unknown): Record<string, unknown> {
  return value && typeof value === 'object' && !Array.isArray(value) ? value as Record<string, unknown> : {};
}

function arrayOfStrings(value: unknown) {
  return Array.isArray(value) ? value.filter((item): item is string => typeof item === 'string') : [];
}

function severityValue(value: unknown, fallback: Severity): Severity {
  return ['critical', 'high', 'medium', 'low', 'info'].includes(String(value)) ? value as Severity : fallback;
}

function confidenceValue(value: unknown, fallback: Issue['confidence']): Issue['confidence'] {
  return ['certain', 'firm', 'tentative'].includes(String(value)) ? value as Issue['confidence'] : fallback;
}

function issueStatusValue(value: unknown, fallback: Issue['status']): Issue['status'] {
  return ['open', 'triaged', 'false-positive', 'fixed'].includes(String(value)) ? value as Issue['status'] : fallback;
}

function sanitizeImportId(value: string) {
  return value.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '') || 'item';
}

async function sha256Hex(value: string) {
  return bufferToHex(await globalThis.crypto.subtle.digest('SHA-256', new TextEncoder().encode(value)));
}

function bufferToHex(value: ArrayBuffer) {
  return Array.from(new Uint8Array(value)).map((byte) => byte.toString(16).padStart(2, '0')).join('');
}

function canonicalizeEvidenceBundle(value: unknown): string {
  if (Array.isArray(value)) return `[${value.map(canonicalizeEvidenceBundle).join(',')}]`;
  if (value && typeof value === 'object') {
    return `{${Object.keys(value as Record<string, unknown>).sort().map((key) => (
      `${JSON.stringify(key)}:${canonicalizeEvidenceBundle((value as Record<string, unknown>)[key])}`
    )).join(',')}}`;
  }
  return JSON.stringify(value) ?? 'null';
}

function reportExchangeMatchesIssue(exchange: HttpExchange, issue: Issue) {
  if (exchange.host !== issue.host) return false;
  if (exchange.path === issue.path) return true;
  if (exchange.url.includes(issue.path)) return true;
  return issue.path !== '/' && exchange.path.startsWith(issue.path);
}

function reportRemediationPriority(severity: Severity) {
  if (severity === 'critical') return 'P0 - immediate containment';
  if (severity === 'high') return 'P1 - next release';
  if (severity === 'medium') return 'P2 - planned fix';
  if (severity === 'low') return 'P3 - backlog';
  return 'P4 - informational';
}

function reportRemediationValidation(issue: Issue, evidenceCount: number) {
  if (issue.status === 'fixed') return 'Attach fixed-state replay evidence and close after owner signoff.';
  if (issue.status === 'false-positive') return 'Retain reviewer rationale and exclude from retest queue.';
  if (evidenceCount > 0) return 'Replay linked evidence after the fix and compare response/status deltas.';
  return 'Add at least one scoped request/response proof before retest.';
}

function buildReportRemediationPlan(issues: Issue[], exchanges: HttpExchange[]) {
  return issues.map((issue) => {
    const evidenceCount = exchanges.filter((exchange) => reportExchangeMatchesIssue(exchange, issue)).length;
    return {
      id: issue.id,
      finding: issue.title,
      severity: issue.severity,
      priority: reportRemediationPriority(issue.severity),
      owner: issue.assignee?.trim() || 'Unassigned',
      status: issue.status,
      host: issue.host,
      path: issue.path,
      evidenceCount,
      validation: reportRemediationValidation(issue, evidenceCount),
      triageNote: issue.triageNote?.trim() || '',
      lastTriagedAt: issue.lastTriagedAt ?? '',
    };
  });
}

function markdownTableCell(value: string) {
  return value.replace(/\|/g, '\\|').replace(/\r?\n/g, ' ').trim();
}

function getSimpleDigestPreview(value: string) {
  let hash = 0x811c9dc5;
  for (let index = 0; index < value.length; index += 1) {
    hash ^= value.charCodeAt(index);
    hash = Math.imul(hash, 0x01000193) >>> 0;
  }
  return `${hash.toString(16).padStart(8, '0')}${value.length.toString(16).padStart(8, '0')}`;
}

function buildExtensionApiCapabilities(extension: Pick<InstalledExtension, 'hooks' | 'permissions'>): ExtensionApiCapabilities {
  return {
    trafficMutationApi: extension.permissions.includes('modify-traffic'),
    replayApi: extension.permissions.includes('read-traffic') && (
      extension.hooks.includes('passive-scan')
      || extension.hooks.includes('traffic-enrichment')
      || extension.hooks.includes('scanner-check')
      || extension.hooks.includes('headless-runner')
    ),
    issueHandoff: extension.permissions.includes('create-issues'),
    evidenceHandoff: extension.permissions.includes('read-traffic'),
  };
}

const extenderApiHooks = Object.keys(extensionHookLabels) as ExtensionHook[];

function extensionDependencyReviewStatus(extension: InstalledExtension): ExtensionDependencyReview['status'] {
  if (extension.trustLevel === 'local') return 'pending';
  return extension.enabled ? 'approved' : 'pending';
}

function buildExtensionRuntimeApiPolicy(extension: InstalledExtension, reviewedAt: string): ExtensionRuntimeApiPolicy {
  const allowedHooks = Array.from(new Set(extension.hooks));
  const deniedHooks = extenderApiHooks.filter((hook) => !allowedHooks.includes(hook));
  const dependencyReviewStatus = extensionDependencyReviewStatus(extension);
  return {
    id: `ext-api-policy-${extension.id}`,
    extensionId: extension.id,
    extensionName: extension.name,
    reviewedAt,
    apiVersion: 'proxyforge-extender-api/v1',
    sandbox: extension.trustLevel === 'built-in' ? 'isolated-worker' : extension.trustLevel === 'verified' ? 'node-disabled' : 'headless-ci',
    allowedHooks,
    deniedHooks,
    networkAccess: extension.permissions.includes('callback-access') ? 'callback-only' : extension.trustLevel === 'local' ? 'blocked' : 'scoped-targets',
    filesystemAccess: extension.trustLevel === 'local' ? 'workspace-readonly' : 'evidence-write',
    dependencyReviewStatus,
    signatureStatus: extension.trustLevel === 'local' ? 'ready-on-export' : 'signed',
    reviewer: 'ProxyForge extension policy engine',
    summary: [
      `${extension.name} exposes request, response, editor, scanner, and headless hook metadata through a sandboxed extension-style API policy.`,
      `Allowed hooks: ${allowedHooks.map((hook) => extensionHookLabels[hook]).join(', ') || 'none'}.`,
      `Denied hooks: ${deniedHooks.map((hook) => extensionHookLabels[hook]).join(', ') || 'none'}.`,
    ].join(' '),
  };
}

function extensionDependenciesForReview(extension: InstalledExtension) {
  return extension.dependencies?.length
    ? extension.dependencies
    : [{ name: '@proxyforge/extender-api', version: '^1.4.0' }];
}

function buildExtensionDependencyReviewContent(
  extension: InstalledExtension,
  reviewedAt: string,
  digestPreview: string,
) {
  const status = extensionDependencyReviewStatus(extension);
  const dependencies = extensionDependenciesForReview(extension).map((dependency) => ({
    name: dependency.name,
    version: dependency.version,
    policy: dependency.name.startsWith('@proxyforge/') ? 'metadata allowlist' : 'manual metadata review',
    status: extension.trustLevel === 'local' && !dependency.name.startsWith('@proxyforge/') ? 'needs-review' : 'approved',
  }));
  return JSON.stringify({
    kind: 'proxyforge-extension-dependency-review',
    reviewedAt,
    apiVersion: 'proxyforge-extender-api/v1',
    extension: {
      id: extension.id,
      name: extension.name,
      version: extension.version,
      trustLevel: extension.trustLevel,
    },
    dependencyReview: {
      status,
      dependencies,
      metadata: {
        manifestHooks: extension.hooks,
        permissions: extension.permissions,
        sandboxedApi: true,
      },
    },
    signature: {
      algorithm: 'HMAC-SHA256',
      signerName: 'ProxyForge extension policy engine',
      keyId: 'extension-policy-local',
      status: extension.trustLevel === 'local' ? 'ready-on-export' : 'signed',
      digestPreview,
    },
  }, null, 2);
}

function buildExtensionDependencyReview(
  extension: InstalledExtension,
  reviewedAt = new Date().toISOString(),
): ExtensionDependencyReview {
  const unsignedContent = buildExtensionDependencyReviewContent(extension, reviewedAt, 'pending');
  const digestPreview = getSimpleDigestPreview(unsignedContent);
  const content = buildExtensionDependencyReviewContent(extension, reviewedAt, digestPreview);
  const parsed = JSON.parse(content) as {
    dependencyReview: {
      status: ExtensionDependencyReview['status'];
      dependencies: ExtensionDependencyReview['dependencies'];
    };
  };
  return {
    id: `ext-dependency-review-${Date.now()}-${Math.random().toString(16).slice(2)}`,
    extensionId: extension.id,
    extensionName: extension.name,
    reviewedAt,
    status: parsed.dependencyReview.status,
    apiVersion: 'proxyforge-extender-api/v1',
    dependencies: parsed.dependencyReview.dependencies,
    summary: `${extension.name} dependency metadata review ${parsed.dependencyReview.status}; ${parsed.dependencyReview.dependencies.length} dependency policy record(s) captured.`,
    signature: {
      algorithm: 'HMAC-SHA256',
      signerName: 'ProxyForge extension policy engine',
      keyId: 'extension-policy-local',
      status: extension.trustLevel === 'local' ? 'ready-on-export' : 'signed',
      digestPreview,
    },
    content,
  };
}

function buildExtensionHeadlessEvidenceContent(
  extension: InstalledExtension,
  policy: ExtensionRuntimeApiPolicy,
  dependencyReview: ExtensionDependencyReview,
  runIds: string[],
  createdAt: string,
  digestPreview: string,
) {
  const hookCoverage = Array.from(new Set<ExtensionHook>([
    ...extension.hooks,
    'request-editor',
    'response-editor',
    'message-editor',
    'scanner-check',
    'headless-runner',
  ]));
  return JSON.stringify({
    kind: 'proxyforge-extension-headless-evidence',
    createdAt,
    extension: {
      id: extension.id,
      name: extension.name,
      version: extension.version,
      trustLevel: extension.trustLevel,
    },
    apiPolicy: policy,
    dependencyReview: {
      id: dependencyReview.id,
      status: dependencyReview.status,
      dependencyCount: dependencyReview.dependencies.length,
      metadata: dependencyReview.dependencies,
    },
    headlessExecution: {
      command: `proxyforge headless --extension ${extension.id} --hooks ${hookCoverage.join(',')} --project-file proxyforge-workspace.json`,
      ciProfile: 'CI headless extension replay',
      runIds,
      hookCoverage,
      metadata: {
        requestHook: hookCoverage.includes('request-editor'),
        responseHook: hookCoverage.includes('response-editor'),
        editorHook: hookCoverage.includes('message-editor'),
        scannerHook: hookCoverage.includes('scanner-check'),
        sandbox: policy.sandbox,
      },
    },
    reportReady: true,
    signature: {
      algorithm: 'HMAC-SHA256',
      signerName: 'ProxyForge extension policy engine',
      keyId: 'extension-policy-local',
      status: 'signed',
      digestPreview,
    },
  }, null, 2);
}

function nextExtensionVersion(version: string) {
  const parts = version.split('.').map((part) => Number.parseInt(part, 10));
  if (parts.length >= 3 && parts.every((part) => Number.isFinite(part))) {
    return `${parts[0]}.${parts[1]}.${parts[2] + 1}`;
  }
  return `${version}.1`;
}

function buildExtensionSignedUpdateContent(extension: InstalledExtension, checkedAt: string, digestPreview: string) {
  const availableVersion = extension.trustLevel === 'local' ? extension.version : nextExtensionVersion(extension.version);
  const status: ExtensionSignedUpdate['status'] = extension.trustLevel === 'local' ? 'blocked' : availableVersion === extension.version ? 'current' : 'available';
  const channel: ExtensionSignedUpdate['channel'] = extension.trustLevel === 'built-in' ? 'stable' : extension.trustLevel === 'local' ? 'local' : 'beta';
  return JSON.stringify({
    kind: 'proxyforge-extension-signed-update',
    checkedAt,
    apiVersion: 'proxyforge-extender-api/v1',
    extension: {
      id: extension.id,
      name: extension.name,
      currentVersion: extension.version,
      availableVersion,
      trustLevel: extension.trustLevel,
    },
    signedUpdate: {
      status,
      channel,
      compatibility: 'legacy proxy-compatible extension compatibility metadata verified',
      evidence: 'signed update metadata is ready for diagnostics and migration evidence',
    },
    signature: {
      algorithm: 'HMAC-SHA256',
      signerName: 'ProxyForge extension update signer',
      keyId: 'extension-update-local',
      status: extension.trustLevel === 'local' ? 'ready-on-export' : 'signed',
      digestPreview,
    },
  }, null, 2);
}

function buildExtensionSignedUpdate(extension: InstalledExtension, checkedAt = new Date().toISOString()): ExtensionSignedUpdate {
  const unsignedContent = buildExtensionSignedUpdateContent(extension, checkedAt, 'pending');
  const digestPreview = getSimpleDigestPreview(unsignedContent);
  const content = buildExtensionSignedUpdateContent(extension, checkedAt, digestPreview);
  const parsed = JSON.parse(content) as {
    signedUpdate: { status: ExtensionSignedUpdate['status']; channel: ExtensionSignedUpdate['channel'] };
    extension: { availableVersion: string };
  };
  return {
    id: `ext-update-${Date.now()}-${Math.random().toString(16).slice(2)}`,
    extensionId: extension.id,
    extensionName: extension.name,
    checkedAt,
    channel: parsed.signedUpdate.channel,
    currentVersion: extension.version,
    availableVersion: parsed.extension.availableVersion,
    status: parsed.signedUpdate.status,
    apiVersion: 'proxyforge-extender-api/v1',
    signature: {
      algorithm: 'HMAC-SHA256',
      signerName: 'ProxyForge extension update signer',
      keyId: 'extension-update-local',
      status: extension.trustLevel === 'local' ? 'ready-on-export' : 'signed',
      digestPreview,
    },
    summary: `${extension.name} signed update check ${parsed.signedUpdate.status}: ${extension.version} to ${parsed.extension.availableVersion}.`,
    content,
  };
}

function buildExtensionCompatibilityFixtures(extension: InstalledExtension, executedAt = new Date().toISOString()): ExtensionCompatibilityFixture[] {
  const fixtureHooks = Array.from(new Set<ExtensionHook>([
    'request-editor',
    'response-editor',
    'message-editor',
    'scanner-check',
    'headless-runner',
    ...extension.hooks,
  ]));
  return fixtureHooks.map((hook, index) => ({
    id: `ext-fixture-${extension.id}-${hook}-${Date.now()}-${index}`,
    extensionId: extension.id,
    extensionName: extension.name,
    executedAt,
    name: `${extensionHookLabels[hook]} compatibility fixture`,
    hook,
    apiVersion: 'proxyforge-extender-api/v1',
    legacyExtensionApi: legacyExtensionApiForExtensionHook(hook),
    operation: legacyProxyOperationForExtensionHook(hook),
    expectedOutcome: hook === 'headless-runner'
      ? 'Policy-denied callbacks fail closed unless an operator grants an explicit scoped runtime capability.'
      : extension.hooks.includes(hook)
        ? 'Runtime hook is implemented and can produce compatibility evidence.'
        : 'Adapter guidance required before migrated legacy proxy code reaches this hook.',
    policyOutcome: hook === 'headless-runner' && !extension.hooks.includes(hook)
      ? 'denied'
      : extension.hooks.includes(hook) ? 'allowed' : 'adapter-required',
    status: extension.hooks.includes(hook) ? 'pass' : hook === 'headless-runner' ? 'pass' : 'warning',
    summary: `${extension.name} ${extensionHookLabels[hook]} compatibility ${extension.hooks.includes(hook) ? 'passed' : hook === 'headless-runner' ? 'proved policy-denied safety' : 'needs adapter'} for legacy proxy-compatible ${legacyExtensionApiForExtensionHook(hook)} migration parity.`,
  }));
}

function legacyExtensionApiForExtensionHook(hook: ExtensionHook) {
  if (hook === 'request-editor' || hook === 'response-editor') return 'IHttpListener';
  if (hook === 'message-editor') return 'IMessageEditorTab';
  if (hook === 'scanner-check' || hook === 'passive-scan') return 'IScannerCheck';
  if (hook === 'headless-runner') return 'ILegacyExtensionCallbacks';
  if (hook === 'intruder-payload') return 'IIntruderPayloadProcessor';
  if (hook === 'report-transform') return 'IExtensionStateListener';
  return 'ILegacyExtensionCallbacks';
}

function legacyProxyOperationForExtensionHook(hook: ExtensionHook) {
  if (hook === 'request-editor') return 'processHttpMessage(request)';
  if (hook === 'response-editor') return 'processHttpMessage(response)';
  if (hook === 'message-editor') return 'createNewInstance / getTabCaption';
  if (hook === 'scanner-check' || hook === 'passive-scan') return 'doPassiveScan / doActiveScan evidence handoff';
  if (hook === 'headless-runner') return 'makeHttpRequest policy-denied probe';
  if (hook === 'intruder-payload') return 'processPayload';
  if (hook === 'traffic-enrichment') return 'registerHttpListener metadata enrichment';
  if (hook === 'report-transform') return 'extension state and report transform adapter';
  return 'sandboxed callback adapter';
}

function buildExtensionRuntimeDiagnosticsContent(
  extension: InstalledExtension,
  fixtures: ExtensionCompatibilityFixture[],
  update: ExtensionSignedUpdate | undefined,
  runIds: string[],
  createdAt: string,
  digestPreview: string,
) {
  return JSON.stringify({
    kind: 'proxyforge-extension-runtime-diagnostics',
    createdAt,
    reportReady: true,
    apiVersion: 'proxyforge-extender-api/v1',
    extension: {
      id: extension.id,
      name: extension.name,
      version: extension.version,
      trustLevel: extension.trustLevel,
    },
    signedUpdate: update ? {
      id: update.id,
      status: update.status,
      currentVersion: update.currentVersion,
      availableVersion: update.availableVersion,
      signature: update.signature,
    } : undefined,
    compatibilityFixtures: fixtures.map((fixture) => ({
      id: fixture.id,
      name: fixture.name,
      hook: fixture.hook,
      status: fixture.status,
      summary: fixture.summary,
    })),
    diagnostics: {
      runIds,
      compatibility: fixtures.every((fixture) => fixture.status !== 'fail') ? 'compatible' : 'blocked',
      migration: 'legacy extension migration diagnostics captured',
      evidenceMetadata: 'report-ready diagnostics metadata',
    },
    signature: {
      algorithm: 'HMAC-SHA256',
      signerName: 'ProxyForge extension diagnostics signer',
      keyId: 'extension-diagnostics-local',
      status: 'signed',
      digestPreview,
    },
  }, null, 2);
}

function buildExtensionMigrationGuideContent(
  extension: InstalledExtension,
  diagnostic: ExtensionRuntimeDiagnosticPackage | undefined,
  createdAt: string,
  digestPreview: string,
) {
  return JSON.stringify({
    kind: 'proxyforge-extension-migration-guide',
    createdAt,
    reportReady: true,
    apiVersion: 'proxyforge-extender-api/v1',
    extension: {
      id: extension.id,
      name: extension.name,
      version: extension.version,
      hooks: extension.hooks,
      permissions: extension.permissions,
    },
    legacyMigration: {
      source: 'legacy extension',
      mapping: [
        'IHttpListener -> request-editor, response-editor, message-editor hooks',
        'IScannerCheck -> scanner-check hooks',
        'ITab/IMessageEditorTab -> editor metadata fixtures',
        'ILegacyExtensionCallbacks -> sandboxed ProxyForge API capability review',
      ],
      diagnosticsId: diagnostic?.id,
      evidenceMetadata: 'report-ready migration guidance metadata',
    },
    signature: {
      algorithm: 'HMAC-SHA256',
      signerName: 'ProxyForge extension migration signer',
      keyId: 'extension-migration-local',
      status: 'signed',
      digestPreview,
    },
  }, null, 2);
}

