      `| ${item.priority} | ${markdownTableCell(item.finding)} | ${markdownTableCell(item.owner)} | ${markdownTableCell(issueStatusLabels[item.status])} | ${item.evidenceCount} | ${markdownTableCell(item.validation)} |`
