function renderReportLoggerImportJobsMarkdown(loggerImportJobs: ReportLoggerImportAttachment[]) {
  if (!loggerImportJobs.length) return '';
  const provenanceRows = loggerImportJobs.filter((job) => job.provenanceManifest).map((job) => {
    const manifest = job.provenanceManifest;
    const signature = manifest?.signature;
    return `- ${job.mappingPresetName}: ${signature?.status ?? 'unsigned'} signed Logger provenance manifest, ${signature?.algorithm ?? 'no algorithm'}, digest ${(manifest?.manifestDigestSha256 ?? 'pending').slice(0, 16)}..., ${manifest?.exchangeCount ?? job.exchangeCount} exchange(s).`;
  });
  const redactionRows = loggerImportJobs.map((job) => (
    `- ${job.mappingPresetName}: ${job.redactionControl ? 'applied' : 'pending'} Logger redaction summary: ${loggerRedactionRuleSummary(job.redactionControl)}.`
  ));
  return [
    '### Logger Import Jobs',
    '',
    '| Imported | Mapping | Hosts | Adds | Variants | Duplicates | Replays | Notes |',
    '| --- | --- | --- | ---: | ---: | ---: | ---: | --- |',
    ...loggerImportJobs.map((job) => (
      `| ${markdownTableCell(job.importedAt)} | ${markdownTableCell(job.mappingPresetName)} | ${markdownTableCell(job.sourceHosts.join(', ') || 'none')} | ${job.addedEntries} | ${job.changedEntries} | ${job.duplicateEntries} | ${job.replayCount} | ${markdownTableCell(job.notes || 'No reviewer notes')} |`
    )),
    '',
    '#### Signed Logger Provenance',
    '',
    ...(provenanceRows.length ? provenanceRows : ['- No signed Logger provenance manifests have been generated for attached import jobs yet.']),
    '',
    '#### Logger Redaction Summary',
    '',
    ...redactionRows,
  ].join('\n');
}

