function buildReportCallbackArtifactManifest(
  signedPollBatches: CallbackSignedPollBatch[],
  correlationReplays: CallbackCorrelationReplayPackage[],
  replayExecutionBatches: CallbackReplayExecutionBatch[],
  lifecycleReviews: CallbackPayloadLifecycleReview[],
  ciHandoffPackages: CallbackCiHandoffPackage[],
  publicRelaySoakPackages: CallbackPublicRelaySoakPackage[],
): ReportFullPackage['callbackArtifactManifest'] {
  const readySignedPollBatches = signedPollBatches.filter((item) => item.reportReady);
  const readyCorrelationReplays = correlationReplays.filter((item) => item.reportReady);
  const readyReplayExecutionBatches = replayExecutionBatches.filter((item) => item.reportReady);
  const readyLifecycleReviews = lifecycleReviews.filter((item) => item.reportReady);
  const readyCiHandoffPackages = ciHandoffPackages.filter((item) => item.reportReady);
  const readyPublicRelaySoakPackages = publicRelaySoakPackages.filter((item) => item.reportReady);
  const totalArtifactCount = readySignedPollBatches.length
    + readyCorrelationReplays.length
    + readyReplayExecutionBatches.length
    + readyLifecycleReviews.length
    + readyCiHandoffPackages.length
    + readyPublicRelaySoakPackages.length;
  return {
    signedPollBatchIds: readySignedPollBatches.map((item) => item.id),
    correlationReplayIds: readyCorrelationReplays.map((item) => item.id),
    replayExecutionBatchIds: readyReplayExecutionBatches.map((item) => item.id),
    lifecycleReviewIds: readyLifecycleReviews.map((item) => item.id),
    ciHandoffPackageIds: readyCiHandoffPackages.map((item) => item.id),
    publicRelaySoakPackageIds: readyPublicRelaySoakPackages.map((item) => item.id),
    externalRelayIntegrationPackageIds: [],
    externalProviderDiversityPackageIds: [],
    totalArtifactCount,
    summary: `${totalArtifactCount} report-ready callback artifact(s): ${readySignedPollBatches.length} signed poll batch(es), ${readyCorrelationReplays.length} replay package(s), ${readyReplayExecutionBatches.length} execution batch(es), ${readyLifecycleReviews.length} lifecycle review(s), ${readyCiHandoffPackages.length} CI handoff(s), and ${readyPublicRelaySoakPackages.length} public relay soak package(s).`,
  };
}

function normalizeImportedCallbackArtifactManifest(parsed: {
  callbackArtifactManifest?: ReportFullPackage['callbackArtifactManifest'];
  callbackSignedPollBatches?: unknown[];
  callbackCorrelationReplays?: unknown[];
  callbackReplayExecutionBatches?: unknown[];
  callbackLifecycleReviews?: unknown[];
  callbackCiHandoffPackages?: unknown[];
  callbackPublicRelaySoakPackages?: unknown[];
}): ReportFullPackage['callbackArtifactManifest'] | undefined {
  if (parsed.callbackArtifactManifest) {
    return {
      ...parsed.callbackArtifactManifest,
      publicRelaySoakPackageIds: parsed.callbackArtifactManifest.publicRelaySoakPackageIds ?? [],
      externalRelayIntegrationPackageIds: parsed.callbackArtifactManifest.externalRelayIntegrationPackageIds ?? [],
      externalProviderDiversityPackageIds: parsed.callbackArtifactManifest.externalProviderDiversityPackageIds ?? [],
    };
  }
  const signedPollBatchIds = extractArtifactIds(parsed.callbackSignedPollBatches);
  const correlationReplayIds = extractArtifactIds(parsed.callbackCorrelationReplays);
  const replayExecutionBatchIds = extractArtifactIds(parsed.callbackReplayExecutionBatches);
  const lifecycleReviewIds = extractArtifactIds(parsed.callbackLifecycleReviews);
  const ciHandoffPackageIds = extractArtifactIds(parsed.callbackCiHandoffPackages);
  const publicRelaySoakPackageIds = extractArtifactIds(parsed.callbackPublicRelaySoakPackages);
  const totalArtifactCount = signedPollBatchIds.length
    + correlationReplayIds.length
    + replayExecutionBatchIds.length
    + lifecycleReviewIds.length
    + ciHandoffPackageIds.length
    + publicRelaySoakPackageIds.length;
  if (!totalArtifactCount) return undefined;
  return {
    signedPollBatchIds,
    correlationReplayIds,
    replayExecutionBatchIds,
    lifecycleReviewIds,
    ciHandoffPackageIds,
    publicRelaySoakPackageIds,
    externalRelayIntegrationPackageIds: [],
    externalProviderDiversityPackageIds: [],
    totalArtifactCount,
    summary: `${totalArtifactCount} callback artifact(s) restored from imported report package content.`,
  };
}

function extractArtifactIds(values: unknown[] | undefined) {
  return (Array.isArray(values) ? values : [])
    .map((item) => (item && typeof item === 'object' && 'id' in item ? String(item.id) : ''))
    .filter(Boolean);
}

function renderReportExtensionEvidenceHandoffsMarkdown(handoffs: ExtensionEvidenceHandoff[]) {
  const reportReadyHandoffs = handoffs.filter((item) => item.reportReady);
  if (!reportReadyHandoffs.length) return '';

  return [
    '### Extension Evidence Handoffs',
    '',
    '| Handoff | Extension | Signature | Summary |',
    '| --- | --- | --- | --- |',
    ...reportReadyHandoffs.map((item) => (
      `| ${markdownTableCell(item.fileName)} | ${markdownTableCell(item.extensionName)} | ${markdownTableCell(item.signature.algorithm)} | ${markdownTableCell(item.summary)} |`
    )),
    '',
    ...reportReadyHandoffs.map((item) => [
      `#### ${item.title}`,
      '',
      item.summary,
      '',
      '```',
      item.content.trim(),
      '```',
    ].join('\n')),
  ].join('\n');
}

