function buildReportAffectedAssets(issues: Issue[], exchanges: HttpExchange[]): ReportAffectedAsset[] {
  const assetMap = new Map<string, ReportAffectedAsset>();
  for (const exchange of exchanges) {
    const current = assetMap.get(exchange.host) ?? {
      host: exchange.host,
      issueCount: 0,
      evidenceCount: 0,
      highestSeverity: 'info' as Severity,
      paths: [],
    };
    current.evidenceCount += 1;
    current.paths = Array.from(new Set([...current.paths, exchange.path])).slice(0, 8);
    assetMap.set(exchange.host, current);
  }
  for (const issue of issues) {
    const current = assetMap.get(issue.host) ?? {
      host: issue.host,
      issueCount: 0,
      evidenceCount: 0,
      highestSeverity: 'info' as Severity,
      paths: [],
    };
    current.issueCount += 1;
    current.highestSeverity = severityRank[issue.severity] > severityRank[current.highestSeverity]
      ? issue.severity
      : current.highestSeverity;
    current.paths = Array.from(new Set([...current.paths, issue.path])).slice(0, 8);
    assetMap.set(issue.host, current);
  }
  return Array.from(assetMap.values()).sort((left, right) => (
    severityRank[right.highestSeverity] - severityRank[left.highestSeverity]
    || right.issueCount - left.issueCount
    || right.evidenceCount - left.evidenceCount
    || left.host.localeCompare(right.host)
  ));
}

function buildReportEvidenceManifestEntries(issues: Issue[], exchanges: HttpExchange[]): ReportEvidenceManifestEntry[] {
  return exchanges.map((exchange, index) => {
    const linkedIssueIds = issues
      .filter((issue) => issue.host === exchange.host && issue.path === exchange.path)
      .map((issue) => issue.id);
    return {
      id: `report-evidence-${exchange.id}`,
      label: `${index + 1}. ${exchange.method} ${exchange.host}${exchange.path}`,
      method: exchange.method,
      host: exchange.host,
      path: exchange.path,
      status: exchange.status,
      source: exchange.source,
      linkedIssueIds,
    };
  });
}

function buildReportReadinessChecks(
  issues: Issue[],
  exchanges: HttpExchange[],
  sections: ReportSection[],
  signEvidenceBundle: boolean,
  affectedAssets: ReportAffectedAsset[],
  evidenceManifest: ReportEvidenceManifestEntry[],
  governanceAttestation: ReportGovernanceAttestation,
): ReportReadinessCheck[] {
  return [
    {
      id: 'executive-appendix',
      label: 'Executive Appendix',
      status: sections.includes('executive') ? 'ready' : 'warning',
      detail: sections.includes('executive') ? 'Executive narrative selected' : 'Executive section is not selected',
    },
    {
      id: 'technical-appendix',
      label: 'Technical Appendix',
      status: sections.includes('technical') ? 'ready' : 'warning',
      detail: `${issues.length} finding${issues.length === 1 ? '' : 's'} available for technical detail`,
    },
    {
      id: 'affected-assets',
      label: 'Affected assets',
      status: affectedAssets.length ? 'ready' : 'blocked',
      detail: `${affectedAssets.length} host${affectedAssets.length === 1 ? '' : 's'} mapped from findings and evidence`,
    },
    {
      id: 'evidence-manifest',
      label: 'Evidence manifest',
      status: evidenceManifest.length ? 'ready' : 'blocked',
      detail: `${evidenceManifest.length} evidence attachment${evidenceManifest.length === 1 ? '' : 's'} indexed`,
    },
    {
      id: 'signature-metadata',
      label: 'Signature metadata',
      status: signEvidenceBundle ? 'ready' : 'warning',
      detail: signEvidenceBundle ? 'HMAC-SHA256 metadata ready for export' : 'Enable signed evidence bundle for strongest package verification',
    },
    {
      id: 'governance-attestation',
      label: 'Governance attestation',
      status: governanceAttestation.status === 'active' ? 'ready' : governanceAttestation.status === 'reviewed' ? 'warning' : 'warning',
      detail: governanceAttestation.status === 'active'
        ? `Active governance policy ${governanceAttestation.signature.digestPreview} controls ${governanceAttestation.runnerBindingCount} runner binding(s), ${governanceAttestation.approvalRequiredCount} approval gate(s), and CI/headless evidence export.`
        : `No active governance policy controls this export; current attestation is ${governanceAttestation.status}.`,
    },
  ];
}

function buildFullReportPackageContent(
  projectName: string,
  brandName: string,
  preparedFor: string,
  engagementId: string,
  issues: Issue[],
  exchanges: HttpExchange[],
  affectedAssets: ReportAffectedAsset[],
  evidenceManifest: ReportEvidenceManifestEntry[],
  readiness: ReportReadinessCheck[],
  governanceAttestation: ReportGovernanceAttestation,
  scannerEvidenceDeltas: ScannerEvidenceDelta[],
  scannerActiveScanEvidencePackages: ScannerActiveScanEvidencePackage[],
  callbackSignedPollBatches: CallbackSignedPollBatch[],
  callbackCorrelationReplays: CallbackCorrelationReplayPackage[],
  callbackReplayExecutionBatches: CallbackReplayExecutionBatch[],
  callbackLifecycleReviews: CallbackPayloadLifecycleReview[],
  callbackCiHandoffPackages: CallbackCiHandoffPackage[],
  callbackPublicRelaySoakPackages: CallbackPublicRelaySoakPackage[],
  reportMarkdown: string,
  signerName: string,
  signingKeyId: string,
  status: ReportFullPackage['signature']['status'],
  digestPreview: string,
) {
  const callbackArtifactManifest = buildReportCallbackArtifactManifest(
    callbackSignedPollBatches,
    callbackCorrelationReplays,
    callbackReplayExecutionBatches,
    callbackLifecycleReviews,
    callbackCiHandoffPackages,
    callbackPublicRelaySoakPackages,
  );
  return JSON.stringify({
    kind: 'proxyforge-full-report-package',
    projectName,
    brandName,
    preparedFor,
    engagementId,
    generatedAt: new Date().toISOString(),
    exportReadiness: readiness,
    governanceAttestation,
    executiveAppendix: {
      title: 'Executive Appendix',
      summary: `${issues.length} included finding(s), ${affectedAssets.length} affected asset(s), ${exchanges.length} evidence attachment(s).`,
      highRiskFindings: issues.filter((issue) => severityRank[issue.severity] >= severityRank.high).map((issue) => issue.title),
    },
    technicalAppendix: {
      title: 'Technical Appendix',
      findings: issues.map((issue) => ({
        title: issue.title,
        severity: issue.severity,
        host: issue.host,
        path: issue.path,
        status: issue.status,
        confidence: issue.confidence,
        remediation: issue.remediation,
      })),
    },
    affectedAssets,
    evidenceManifest,
    callbackArtifactManifest,
    callbackSignedPollBatches: callbackSignedPollBatches.filter((item) => item.reportReady),
    callbackCorrelationReplays: callbackCorrelationReplays.filter((item) => item.reportReady),
    callbackReplayExecutionBatches: callbackReplayExecutionBatches.filter((item) => item.reportReady),
    callbackLifecycleReviews: callbackLifecycleReviews.filter((item) => item.reportReady),
    callbackCiHandoffPackages: callbackCiHandoffPackages.filter((item) => item.reportReady),
    callbackPublicRelaySoakPackages: callbackPublicRelaySoakPackages.filter((item) => item.reportReady),
    scannerEvidenceDeltas: scannerEvidenceDeltas.filter((item) => item.reportReady),
    scannerActiveScanEvidencePackages: scannerActiveScanEvidencePackages.filter((item) => item.reportReady),
    attachmentsManifest: evidenceManifest.map((item) => ({
      id: item.id,
      label: item.label,
      source: item.source,
      linkedIssueIds: item.linkedIssueIds,
    })),
    reportMarkdown,
    signature: {
      algorithm: 'HMAC-SHA256',
      signerName,
      keyId: signingKeyId || 'report-local',
      status,
      digestPreview,
    },
  }, null, 2);
}

function renderCustomReportTemplatePreview(
  projectName: string,
  scopeAllowlist: string[],
  issues: Issue[],
  exchanges: HttpExchange[],
  loggerImportJobs: ReportLoggerImportAttachment[],
  replayComparisonExports: ViewerReplayComparisonExport[],
  comparerDiffPackages: ComparerDiffPackage[],
  comparerEvidenceAttachments: ComparerEvidenceAttachment[],
  targetSiteMapEvidenceAttachments: TargetSiteMapEvidenceAttachment[],
  proxyHistoryEvidenceAttachments: ProxyHistoryEvidenceAttachment[],
  callbackEvidencePackages: CallbackEvidencePackage[],
  extensionEvidenceHandoffs: ExtensionEvidenceHandoff[],
  scannerEvidenceDeltas: ScannerEvidenceDelta[],
  scannerActiveScanEvidencePackages: ScannerActiveScanEvidencePackage[],
  sections: ReportSection[],
  templateName: string,
  templateBody: string,
  brandName: string,
  preparedFor: string,
  engagementId: string,
  generatedAt = new Date(),
) {
  const selectedSections = sections.length ? sections : ['executive', 'technical', 'remediation', 'evidence', 'appendix'];
  const highOrCritical = issues.filter((issue) => severityRank[issue.severity] >= severityRank.high).length;
  const affectedHosts = Array.from(new Set(issues.map((issue) => issue.host))).length;
  const openIssues = issues.filter((issue) => issue.status === 'open').length;
  const topIssues = issues.slice().sort((a, b) => severityRank[b.severity] - severityRank[a.severity]).slice(0, 8);
  const evidence = exchanges.slice(0, 12);
  const replacements: Record<string, string | number> = {
    projectName,
    brandName,
    preparedFor,
    engagementId,
    generatedAt: generatedAt.toISOString(),
    scope: scopeAllowlist.join(', ') || 'Not specified',
    sections: selectedSections.join(', '),
    templateName: templateName.trim() || reportTemplateLabels.custom,
    'summary.totalIssues': issues.length,
    'summary.openIssues': openIssues,
    'summary.highOrCritical': highOrCritical,
    'summary.affectedHosts': affectedHosts,
    'summary.evidenceItems': exchanges.length,
    'summary.loggerImportJobs': loggerImportJobs.length,
    'summary.replayComparisonExports': replayComparisonExports.filter((item) => item.reportReady).length,
    'summary.comparerDiffPackages': comparerDiffPackages.filter((item) => item.reportReady).length,
    'summary.comparerEvidenceAttachments': comparerEvidenceAttachments.filter((item) => item.reportReady).length,
    'summary.targetSiteMapEvidence': targetSiteMapEvidenceAttachments.filter((item) => item.reportReady).length,
    'summary.proxyHistoryEvidence': proxyHistoryEvidenceAttachments.filter((item) => item.reportReady).length,
    'summary.callbackEvidencePackages': callbackEvidencePackages.filter((item) => item.reportReady).length,
    'summary.extensionEvidenceHandoffs': extensionEvidenceHandoffs.filter((item) => item.reportReady).length,
    'summary.scannerEvidenceDeltas': scannerEvidenceDeltas.filter((item) => item.reportReady).length,
    'summary.scannerActiveScanEvidencePackages': scannerActiveScanEvidencePackages.filter((item) => item.reportReady).length,
    executiveMarkdown: selectedSections.includes('executive')
      ? [
          '## Executive Summary',
          '',
          `${brandName} found ${issues.length} issue(s), ${highOrCritical} high-or-critical priority item(s), ${affectedHosts} affected host(s), ${exchanges.length} evidence item(s).`,
        ].join('\n')
      : '',
    findingsMarkdown: selectedSections.includes('technical')
      ? [
          '## Technical Findings',
          '',
          ...topIssues.map((issue) => [
            `### ${severityLabel[issue.severity]}: ${issue.title}`,
            `${issue.host}${issue.path} · ${issue.confidence} · ${issueStatusLabels[issue.status]}${issue.assignee ? ` · ${issue.assignee}` : ''}`,
            issue.detail,
            issue.triageNote ? `Triage note: ${issue.triageNote}` : '',
            `Remediation: ${issue.remediation}`,
          ].filter(Boolean).join('\n\n')),
        ].join('\n\n').trim()
      : '',
    remediationMarkdown: selectedSections.includes('remediation') ? renderReportRemediationMarkdown(issues, exchanges) : '',
    evidenceMarkdown: selectedSections.includes('evidence')
      ? [
          '## Evidence',
          '',
          ...evidence.map((exchange) => `- ${exchange.method} ${exchange.host}${exchange.path} ${exchange.status} ${exchange.source} ${exchange.notes}`),
          '',
          renderReportLoggerImportJobsMarkdown(loggerImportJobs),
          '',
          renderReportReplayComparisonExportsMarkdown(replayComparisonExports),
          '',
          renderReportComparerDiffPackagesMarkdown(comparerDiffPackages),
          '',
          renderReportComparerEvidenceAttachmentsMarkdown(comparerEvidenceAttachments),
          '',
          renderReportTargetSiteMapEvidenceMarkdown(targetSiteMapEvidenceAttachments),
          '',
          renderReportProxyHistoryEvidenceMarkdown(proxyHistoryEvidenceAttachments),
          '',
          renderReportCallbackEvidencePackagesMarkdown(callbackEvidencePackages),
          '',
          renderReportExtensionEvidenceHandoffsMarkdown(extensionEvidenceHandoffs),
          '',
          renderReportScannerEvidenceDeltasMarkdown(scannerEvidenceDeltas),
          '',
          renderReportScannerActiveScanEvidencePackagesMarkdown(scannerActiveScanEvidencePackages),
        ].join('\n').trim()
      : '',
    appendixMarkdown: selectedSections.includes('appendix')
      ? [
          '## Appendix',
          '',
          `- Generated by ${brandName}`,
          `- Prepared for ${preparedFor}`,
          `- Engagement ID: ${engagementId}`,
          '- Active traffic remains gated to project scope.',
        ].join('\n')
      : '',
  };

  return `${(templateBody.trim() || defaultReportCustomTemplate).replace(/{{\s*([a-zA-Z0-9_.]+)\s*}}/g, (_match, key: string) => String(replacements[key] ?? ''))}\n`;
}

function passesReportSeverityFloor(severity: Severity, floor: Severity | 'all') {
  return floor === 'all' || severityRank[severity] >= severityRank[floor];
}

function passesReportIssueStatus(issue: Issue, filter: ReportIssueStatusFilter) {
  if (filter === 'all') return true;
  if (filter === 'open-triaged') return issue.status === 'open' || issue.status === 'triaged';
  return issue.status === filter;
}

function buildReportCurationSummary(
  issues: Issue[],
  exchanges: HttpExchange[],
  issueSeverityFloor: Severity | 'all',
  issueStatusFilter: ReportIssueStatusFilter,
  evidenceSeverityFloor: Severity | 'all',
  evidenceSourceFilter: ReportEvidenceSourceFilter,
  evidenceMode: ReportEvidenceMode,
): ReportCurationSummary {
  const includedIssues = issues.filter((issue) => (
    passesReportSeverityFloor(issue.severity, issueSeverityFloor)
    && passesReportIssueStatus(issue, issueStatusFilter)
  ));
  const filteredEvidence = exchanges.filter((exchange) => (
    passesReportSeverityFloor(exchange.risk, evidenceSeverityFloor)
    && (evidenceSourceFilter === 'all' || exchange.source === evidenceSourceFilter)
  ));
  const linkedEvidenceIds = new Set<string>();
  const coverageRows = includedIssues.map((issue) => {
    const linkedEvidence = filteredEvidence.filter((exchange) => reportExchangeMatchesIssue(exchange, issue));
    for (const exchange of linkedEvidence) linkedEvidenceIds.add(exchange.id);
    return {
      issueId: issue.id,
      title: issue.title,
      severity: issue.severity,
      host: issue.host,
      path: issue.path,
      evidenceCount: linkedEvidence.length,
      evidenceLabels: linkedEvidence.slice(0, 3).map((exchange) => `${exchange.method} ${exchange.path} ${exchange.status}`),
    };
  });
  const includedEvidence = evidenceMode === 'linked-findings'
    ? filteredEvidence.filter((exchange) => linkedEvidenceIds.has(exchange.id))
    : filteredEvidence;
  const orphanEvidenceCount = includedEvidence.filter((exchange) => (
    !includedIssues.some((issue) => reportExchangeMatchesIssue(exchange, issue))
  )).length;

  return {
    issues: includedIssues,
    exchanges: includedEvidence,
    excludedIssueCount: issues.length - includedIssues.length,
    excludedExchangeCount: exchanges.length - includedEvidence.length,
    linkedIssueCount: coverageRows.filter((row) => row.evidenceCount > 0).length,
    unlinkedIssueCount: coverageRows.filter((row) => row.evidenceCount === 0).length,
    linkedEvidenceCount: includedEvidence.filter((exchange) => linkedEvidenceIds.has(exchange.id)).length,
    orphanEvidenceCount,
    coverageRows: coverageRows.slice(0, 12),
  };
}

function buildReportPreview(
  projectName: string,
  scopeAllowlist: string[],
  issues: Issue[],
  exchanges: HttpExchange[],
  loggerImportJobs: ReportLoggerImportAttachment[],
  replayComparisonExports: ViewerReplayComparisonExport[],
  comparerDiffPackages: ComparerDiffPackage[],
  comparerEvidenceAttachments: ComparerEvidenceAttachment[],
  targetSiteMapEvidenceAttachments: TargetSiteMapEvidenceAttachment[],
  proxyHistoryEvidenceAttachments: ProxyHistoryEvidenceAttachment[],
  callbackEvidencePackages: CallbackEvidencePackage[],
  extensionEvidenceHandoffs: ExtensionEvidenceHandoff[],
  scannerEvidenceDeltas: ScannerEvidenceDelta[],
  scannerActiveScanEvidencePackages: ScannerActiveScanEvidencePackage[],
  sections: ReportSection[],
  format: ReportFormat,
  templateId: ReportTemplateId,
  brandName: string,
  preparedFor: string,
  engagementId: string,
  customTemplateName: string,
  customTemplateBody: string,
  signEvidenceBundle: boolean,
  signingKeyId: string,
  signerName: string,
  governanceAttestation: ReportGovernanceAttestation,
) {
  const selectedSections: ReportSection[] = sections.length ? sections : ['executive', 'technical', 'remediation', 'evidence'];
  const highOrCritical = issues.filter((issue) => severityRank[issue.severity] >= severityRank.high).length;
  const affectedHosts = Array.from(new Set(issues.map((issue) => issue.host))).length;
  const topIssues = issues.slice().sort((a, b) => severityRank[b.severity] - severityRank[a.severity]).slice(0, 8);
  const evidence = exchanges.slice(0, 12);
  const remediationPlan = buildReportRemediationPlan(topIssues, exchanges);
  const templateName = templateId === 'custom' ? customTemplateName.trim() || reportTemplateLabels.custom : reportTemplateLabels[templateId];
  const customMarkdown = templateId === 'custom'
    ? renderCustomReportTemplatePreview(
        projectName,
        scopeAllowlist,
        issues,
        exchanges,
        loggerImportJobs,
        replayComparisonExports,
        comparerDiffPackages,
        comparerEvidenceAttachments,
        targetSiteMapEvidenceAttachments,
        proxyHistoryEvidenceAttachments,
        callbackEvidencePackages,
        extensionEvidenceHandoffs,
        scannerEvidenceDeltas,
        scannerActiveScanEvidencePackages,
        selectedSections,
        templateName,
        customTemplateBody,
        brandName,
        preparedFor,
        engagementId,
      )
    : '';

  if (format === 'json') {
    return JSON.stringify({
      projectName,
      brandName,
      preparedFor,
      engagementId,
      templateId,
      templateName,
      scopeAllowlist,
      sections: selectedSections,
      governanceAttestation,
      summary: {
        totalIssues: issues.length,
        highOrCritical,
        affectedHosts,
        evidenceItems: exchanges.length,
        loggerImportJobs: loggerImportJobs.length,
        replayComparisonExports: replayComparisonExports.filter((item) => item.reportReady).length,
        comparerDiffPackages: comparerDiffPackages.filter((item) => item.reportReady).length,
        comparerEvidenceAttachments: comparerEvidenceAttachments.filter((item) => item.reportReady).length,
        targetSiteMapEvidence: targetSiteMapEvidenceAttachments.filter((item) => item.reportReady).length,
        proxyHistoryEvidence: proxyHistoryEvidenceAttachments.filter((item) => item.reportReady).length,
        callbackEvidencePackages: callbackEvidencePackages.filter((item) => item.reportReady).length,
        extensionEvidenceHandoffs: extensionEvidenceHandoffs.filter((item) => item.reportReady).length,
        scannerEvidenceDeltas: scannerEvidenceDeltas.filter((item) => item.reportReady).length,
        scannerActiveScanEvidencePackages: scannerActiveScanEvidencePackages.filter((item) => item.reportReady).length,
      },
      issues: topIssues.map((issue) => ({
        title: issue.title,
        severity: issue.severity,
        host: issue.host,
        path: issue.path,
        confidence: issue.confidence,
        status: issue.status,
        assignee: issue.assignee ?? '',
        triageNote: issue.triageNote ?? '',
        remediation: issue.remediation,
      })),
      remediationPlan: selectedSections.includes('remediation') ? remediationPlan : [],
      evidence: selectedSections.includes('evidence')
        ? evidence.map((exchange) => ({
            method: exchange.method,
            host: exchange.host,
            path: exchange.path,
            status: exchange.status,
            source: exchange.source,
            risk: exchange.risk,
          }))
        : [],
      loggerImportJobs: selectedSections.includes('evidence') ? loggerImportJobs : [],
      replayComparisonExports: selectedSections.includes('evidence') ? replayComparisonExports.filter((item) => item.reportReady) : [],
      comparerDiffPackages: selectedSections.includes('evidence') ? comparerDiffPackages.filter((item) => item.reportReady) : [],
      comparerEvidenceAttachments: selectedSections.includes('evidence') ? comparerEvidenceAttachments.filter((item) => item.reportReady) : [],
      targetSiteMapEvidenceAttachments: selectedSections.includes('evidence') ? targetSiteMapEvidenceAttachments.filter((item) => item.reportReady) : [],
      proxyHistoryEvidenceAttachments: selectedSections.includes('evidence') ? proxyHistoryEvidenceAttachments.filter((item) => item.reportReady) : [],
      callbackEvidencePackages: selectedSections.includes('evidence') ? callbackEvidencePackages.filter((item) => item.reportReady) : [],
      extensionEvidenceHandoffs: selectedSections.includes('evidence') ? extensionEvidenceHandoffs.filter((item) => item.reportReady) : [],
      scannerEvidenceDeltas: selectedSections.includes('evidence') ? scannerEvidenceDeltas.filter((item) => item.reportReady) : [],
      scannerActiveScanEvidencePackages: selectedSections.includes('evidence') ? scannerActiveScanEvidencePackages.filter((item) => item.reportReady) : [],
      ...(templateId === 'custom' ? { reportMarkdown: customMarkdown } : {}),
    }, null, 2);
  }

  if (format === 'bundle') {
    const bundle: Record<string, unknown> = {
      manifest: {
        version: 1,
        kind: 'proxyforge-evidence-bundle',
        projectName,
        brandName,
        preparedFor,
        engagementId,
        templateId,
        templateName,
        sections: selectedSections,
        summary: {
          totalIssues: issues.length,
          highOrCritical,
          affectedHosts,
          evidenceItems: exchanges.length,
          loggerImportJobs: loggerImportJobs.length,
          replayComparisonExports: replayComparisonExports.filter((item) => item.reportReady).length,
          comparerDiffPackages: comparerDiffPackages.filter((item) => item.reportReady).length,
          comparerEvidenceAttachments: comparerEvidenceAttachments.filter((item) => item.reportReady).length,
          targetSiteMapEvidence: targetSiteMapEvidenceAttachments.filter((item) => item.reportReady).length,
          proxyHistoryEvidence: proxyHistoryEvidenceAttachments.filter((item) => item.reportReady).length,
          callbackEvidencePackages: callbackEvidencePackages.filter((item) => item.reportReady).length,
          extensionEvidenceHandoffs: extensionEvidenceHandoffs.filter((item) => item.reportReady).length,
          scannerEvidenceDeltas: scannerEvidenceDeltas.filter((item) => item.reportReady).length,
          scannerActiveScanEvidencePackages: scannerActiveScanEvidencePackages.filter((item) => item.reportReady).length,
        },
        governanceAttestation,
      },
      governanceAttestation,
      findings: topIssues.map((issue) => ({
        title: issue.title,
        severity: issue.severity,
        host: issue.host,
        path: issue.path,
        evidenceIds: evidence.filter((exchange) => exchange.host === issue.host || exchange.path === issue.path).map((exchange) => exchange.id),
      })),
      remediationPlan: selectedSections.includes('remediation') ? remediationPlan : [],
      evidence: selectedSections.includes('evidence')
        ? evidence.map((exchange) => ({
            id: exchange.id,
            request: { method: exchange.method, url: exchange.url },
            response: { status: exchange.status, mime: exchange.mime, length: exchange.length },
            metadata: { risk: exchange.risk, source: exchange.source, notes: exchange.notes },
          }))
        : [],
      loggerImportJobs: selectedSections.includes('evidence') ? loggerImportJobs : [],
      replayComparisonExports: selectedSections.includes('evidence') ? replayComparisonExports.filter((item) => item.reportReady) : [],
      comparerDiffPackages: selectedSections.includes('evidence') ? comparerDiffPackages.filter((item) => item.reportReady) : [],
      comparerEvidenceAttachments: selectedSections.includes('evidence') ? comparerEvidenceAttachments.filter((item) => item.reportReady) : [],
      targetSiteMapEvidenceAttachments: selectedSections.includes('evidence') ? targetSiteMapEvidenceAttachments.filter((item) => item.reportReady) : [],
      proxyHistoryEvidenceAttachments: selectedSections.includes('evidence') ? proxyHistoryEvidenceAttachments.filter((item) => item.reportReady) : [],
      callbackEvidencePackages: selectedSections.includes('evidence') ? callbackEvidencePackages.filter((item) => item.reportReady) : [],
      extensionEvidenceHandoffs: selectedSections.includes('evidence') ? extensionEvidenceHandoffs.filter((item) => item.reportReady) : [],
      scannerEvidenceDeltas: selectedSections.includes('evidence') ? scannerEvidenceDeltas.filter((item) => item.reportReady) : [],
      scannerActiveScanEvidencePackages: selectedSections.includes('evidence') ? scannerActiveScanEvidencePackages.filter((item) => item.reportReady) : [],
      reportMarkdown: templateId === 'custom' ? customMarkdown : undefined,
    };
    if (signEvidenceBundle) {
      bundle.signature = {
        version: 1,
        algorithm: 'HMAC-SHA256',
        canonicalization: 'proxyforge-evidence-bundle-v1',
        signerName: signerName.trim() || brandName,
        keyId: signingKeyId.trim() || 'proxyforge-local',
        bundleDigestSha256: '[computed on export]',
        signature: '[computed on export]',
        status: 'ready-on-export',
        covers: ['manifest', 'governanceAttestation', 'findings', 'evidence', 'loggerImportJobs', 'replayComparisonExports', 'comparerDiffPackages', 'comparerEvidenceAttachments', 'targetSiteMapEvidenceAttachments', 'proxyHistoryEvidenceAttachments', 'callbackEvidencePackages', 'extensionEvidenceHandoffs', 'scannerEvidenceDeltas', 'scannerActiveScanEvidencePackages', 'remediationPlan', 'reportMarkdown'],
      };
    }
    return JSON.stringify(bundle, null, 2);
  }

  if (format === 'pdf') {
    return [
      'PDF report package',
      '',
      `Project: ${projectName}`,
      `Prepared for: ${preparedFor}`,
      `Brand: ${brandName}`,
      `Engagement: ${engagementId}`,
      `Template: ${templateName}`,
      `Sections: ${selectedSections.join(', ')}`,
      '',
      `Findings: ${issues.length}`,
      `High/Critical: ${highOrCritical}`,
      `Affected hosts: ${affectedHosts}`,
      `Remediation items: ${selectedSections.includes('remediation') ? remediationPlan.length : 0}`,
      `Evidence items: ${exchanges.length}`,
      `Logger import jobs: ${loggerImportJobs.length}`,
      `Replay comparison exports: ${replayComparisonExports.filter((item) => item.reportReady).length}`,
      `Comparer diff packages: ${comparerDiffPackages.filter((item) => item.reportReady).length}`,
      `Comparer advanced evidence: ${comparerEvidenceAttachments.filter((item) => item.reportReady).length}`,
      `Target site-map evidence: ${targetSiteMapEvidenceAttachments.filter((item) => item.reportReady).length}`,
      `Proxy history evidence: ${proxyHistoryEvidenceAttachments.filter((item) => item.reportReady).length}`,
      `Callback evidence packages: ${callbackEvidencePackages.filter((item) => item.reportReady).length}`,
      `Extension evidence handoffs: ${extensionEvidenceHandoffs.filter((item) => item.reportReady).length}`,
      `Scanner evidence deltas: ${scannerEvidenceDeltas.filter((item) => item.reportReady).length}`,
      `Scanner active scan evidence packages: ${scannerActiveScanEvidencePackages.filter((item) => item.reportReady).length}`,
      `Governance attestation: ${governanceAttestation.status} ${governanceAttestation.signature.digestPreview}`,
      '',
      'Desktop exports render a paginated PDF through Electron printToPDF with redacted evidence.',
      'Browser preview exports a manifest with the same report metadata for deterministic testing.',
    ].join('\n');
  }

  const lines = [
    `# ${projectName} Security Assessment`,
    '',
    `Prepared for: ${preparedFor}`,
    `Brand: ${brandName}`,
    `Engagement: ${engagementId}`,
    `Template: ${templateName}`,
    `Governance: ${governanceAttestation.status} ${governanceAttestation.teamName} ${governanceAttestation.signature.digestPreview}`,
    `Scope: ${scopeAllowlist.join(', ') || 'Not specified'}`,
    '',
  ];

  if (templateId === 'custom') {
    if (format === 'html') {
      return `<!doctype html>\n<html>\n<body>\n<pre>${customMarkdown.replace(/&/g, '&amp;').replace(/</g, '&lt;')}</pre>\n</body>\n</html>\n`;
    }
    return customMarkdown;
  }

  if (selectedSections.includes('executive')) {
    lines.push('## Executive Summary', '');
    lines.push(`${brandName} found ${issues.length} issue(s), ${highOrCritical} high-or-critical priority item(s), ${affectedHosts} affected host(s), ${exchanges.length} evidence item(s).`, '');
    if (templateId === 'executive-board') {
      lines.push('Board Focus:', `- Priority: ${highOrCritical} high-or-critical item(s) need owner review.`, `- Evidence: ${exchanges.length} redacted request/response artifact(s) retained.`, '');
    }
  }

  if (selectedSections.includes('technical')) {
    lines.push('## Technical Findings', '');
    for (const issue of topIssues) {
      lines.push(`### ${severityLabel[issue.severity]}: ${issue.title}`);
      lines.push(`${issue.host}${issue.path} · ${issue.confidence} · ${issueStatusLabels[issue.status]}${issue.assignee ? ` · ${issue.assignee}` : ''}`);
      lines.push(issue.detail, '');
      if (issue.triageNote) lines.push(`Triage note: ${issue.triageNote}`, '');
      lines.push(`Remediation: ${issue.remediation}`, '');
      if (templateId === 'technical-remediation') lines.push('Validation plan: Replay linked evidence, compare deltas, and attach remediation proof before closure.', '');
    }
  }

  if (selectedSections.includes('remediation')) {
    lines.push(renderReportRemediationMarkdown(topIssues, exchanges), '');
  }

  if (selectedSections.includes('evidence')) {
    lines.push('## Evidence', '');
    for (const exchange of evidence) {
      lines.push(`- ${exchange.method} ${exchange.host}${exchange.path} ${exchange.status} ${exchange.source} ${exchange.notes}`);
    }
    const loggerJobsMarkdown = renderReportLoggerImportJobsMarkdown(loggerImportJobs);
    if (loggerJobsMarkdown) lines.push('', loggerJobsMarkdown);
    const replayExportsMarkdown = renderReportReplayComparisonExportsMarkdown(replayComparisonExports);
    if (replayExportsMarkdown) lines.push('', replayExportsMarkdown);
    const comparerPackagesMarkdown = renderReportComparerDiffPackagesMarkdown(comparerDiffPackages);
    if (comparerPackagesMarkdown) lines.push('', comparerPackagesMarkdown);
    const comparerEvidenceMarkdown = renderReportComparerEvidenceAttachmentsMarkdown(comparerEvidenceAttachments);
    if (comparerEvidenceMarkdown) lines.push('', comparerEvidenceMarkdown);
    const targetSiteMapEvidenceMarkdown = renderReportTargetSiteMapEvidenceMarkdown(targetSiteMapEvidenceAttachments);
    if (targetSiteMapEvidenceMarkdown) lines.push('', targetSiteMapEvidenceMarkdown);
    const proxyHistoryEvidenceMarkdown = renderReportProxyHistoryEvidenceMarkdown(proxyHistoryEvidenceAttachments);
    if (proxyHistoryEvidenceMarkdown) lines.push('', proxyHistoryEvidenceMarkdown);
    const callbackPackagesMarkdown = renderReportCallbackEvidencePackagesMarkdown(callbackEvidencePackages);
    if (callbackPackagesMarkdown) lines.push('', callbackPackagesMarkdown);
    const extensionHandoffsMarkdown = renderReportExtensionEvidenceHandoffsMarkdown(extensionEvidenceHandoffs);
    if (extensionHandoffsMarkdown) lines.push('', extensionHandoffsMarkdown);
    const scannerDeltasMarkdown = renderReportScannerEvidenceDeltasMarkdown(scannerEvidenceDeltas);
    if (scannerDeltasMarkdown) lines.push('', scannerDeltasMarkdown);
    const scannerActivePackagesMarkdown = renderReportScannerActiveScanEvidencePackagesMarkdown(scannerActiveScanEvidencePackages);
    if (scannerActivePackagesMarkdown) lines.push('', scannerActivePackagesMarkdown);
    lines.push('');
  }

  if (selectedSections.includes('appendix')) {
    lines.push('## Appendix', '');
    lines.push(`- Generated by ${brandName}`);
    lines.push(`- Prepared for ${preparedFor}`);
    lines.push(`- Engagement ID: ${engagementId}`);
    lines.push('- Active traffic remains gated to project scope.');
  }

  const markdown = `${lines.join('\n')}\n`;
  if (format === 'html') {
    return `<!doctype html>\n<html>\n<body>\n<pre>${markdown.replace(/&/g, '&amp;').replace(/</g, '&lt;')}</pre>\n</body>\n</html>\n`;
  }
  return markdown;
}

