  function appendAuditEvent(event: Omit<AuditEvent, 'id' | 'at' | 'scope'>) {
    if (!safetyPolicy.auditLogging) return;
    setAuditEvents((current) => [
      {
        ...event,
        id: `audit-${Date.now()}-${Math.random().toString(16).slice(2)}`,
        at: new Date().toISOString(),
        operator: activeOperator,
        detail: event.detail,
        scope: effectiveScopeAllowlist,
      },
      ...current,
    ].slice(0, 200));
  }

  function updateSafetyPolicy(patch: Partial<ProjectSafetyPolicy>) {
    const next = { ...safetyPolicy, ...patch };
    setSafetyPolicy(next);
    appendAuditEvent({
      tool: 'settings',
      action: 'Policy updated',
      target: projectName,
      decision: 'updated',
      detail: `Policy updated: scope preflight ${next.requireScopeMatch ? 'on' : 'off'}, audit ${next.auditLogging ? 'on' : 'off'}, min throttle ${next.minThrottleMs}ms, max ${next.maxRequestsPerRun} requests`,
      requestCount: 0,
      risk: 'info',
    });
  }

