  function applyOrganizerPackageTrustPolicy(diff?: OrganizerCollectionDiff) {
    const selected = diff ?? selectedOrganizerDiff;
    const preset = selectedOrganizerTrustPolicyPreset;
    if (!selected) {
      setOrganizerPackageStatus(`Organizer trust policy ${preset.name} selected; review a package to evaluate signature trust.`);
      return;
    }
    const trustEvaluation = evaluateOrganizerPackageTrust(selected, preset);
    setOrganizerCollectionDiffs((current) => current.map((item) => (
      item.id === selected.id ? { ...item, trustEvaluation } : item
    )));
    setOrganizerPackageStatus(`Organizer trust policy ${preset.name} ${organizerTrustDecisionLabels[trustEvaluation.decision]}: ${trustEvaluation.reasons.join('; ')}`);
  }

  async function exportOrganizerCollectionPackage(collection?: OrganizerCollection) {
    const selected = collection ?? selectedOrganizerCollection;
    if (!selected) return;
    try {
      const packageJson = await buildOrganizerCollectionPackage(
        selected,
        organizerPackagePassphrase,
        projectName,
        organizerPackageSignerName,
        organizerPackageSigningKeyId,
        organizerPackageSigningSecret,
      );
      const content = JSON.stringify(packageJson, null, 2);
      setOrganizerPackageText(content);
      updateOrganizerCollection(selected.id, {
        lastPackageDigest: packageJson.digestSha256,
        lastPackageExportedAt: packageJson.exportedAt,
      });
      setOrganizerPackageStatus(`Exported ${selected.name} package · ${packageJson.mode} · ${packageJson.itemCount} item${packageJson.itemCount === 1 ? '' : 's'} · signature ${packageJson.signature.status}`);
    } catch (error) {
      setOrganizerPackageStatus(error instanceof Error ? error.message : 'Organizer package export failed');
    }
  }

  async function reviewOrganizerCollectionPackage() {
    const target = selectedOrganizerCollection ?? organizerCollections[0];
    if (!target) return;
    try {
      const parsed = await parseOrganizerCollectionPackage(organizerPackageText, organizerPackagePassphrase, organizerPackageSigningSecret);
      const baseDiff = buildOrganizerCollectionDiff(parsed.collection, target, parsed.digestSha256, parsed.mode, parsed);
      const trustEvaluation = evaluateOrganizerPackageTrust(baseDiff, selectedOrganizerTrustPolicyPreset);
      const reviewEntries = buildOrganizerPackageConflictAuditEntries(
        baseDiff,
        'reviewed',
        organizerPackageMergeMode,
        `reviewed package with signature ${baseDiff.signatureStatus ?? 'unsigned'}; trust policy ${organizerTrustDecisionLabels[trustEvaluation.decision]} via ${trustEvaluation.presetName}`,
      );
      const diff: OrganizerCollectionDiff = {
        ...baseDiff,
        trustEvaluation,
        conflictAuditTrail: reviewEntries,
      };
      setOrganizerCollectionDiffs((current) => [diff, ...current.filter((item) => item.packageDigest !== diff.packageDigest)].slice(0, 12));
      if (reviewEntries.length > 0) {
        setOrganizerPackageConflictAuditTrail((current) => [...reviewEntries, ...current].slice(0, 100));
      }
      setSelectedOrganizerDiffId(diff.id);
      setOrganizerPackageStatus(`Reviewed package: ${diff.addedItems} add, ${diff.changedItems} change, ${diff.duplicateItems} duplicate · signature ${diff.signatureStatus} · trust policy ${organizerTrustDecisionLabels[trustEvaluation.decision]}`);
    } catch (error) {
      setOrganizerPackageStatus(error instanceof Error ? error.message : 'Organizer package review failed');
    }
  }

  function mergeOrganizerCollectionDiff(diff?: OrganizerCollectionDiff) {
    const selected = diff ?? selectedOrganizerDiff;
    if (!selected) return;
    setOrganizerCollections((current) => current.map((collection) => {
      if (collection.id !== selected.targetCollectionId) return collection;
      const exactKeys = new Set(collection.items.map(organizerItemExactKey));
      const routeKeys = new Set(collection.items.map(organizerItemRouteKey));
      const replaceRouteKeys = new Set<string>();
      const importedItems = selected.collection.items
        .filter((item) => {
          const exactKey = organizerItemExactKey(item);
          const routeKey = organizerItemRouteKey(item);
          if (organizerPackageMergeMode === 'new-only') return !routeKeys.has(routeKey);
          if (organizerPackageMergeMode === 'replace-conflicts' && routeKeys.has(routeKey)) {
            replaceRouteKeys.add(routeKey);
            return true;
          }
          return !exactKeys.has(exactKey);
        })
        .map((item) => ({
          ...item,
          id: `organizer-merge-${Date.now()}-${Math.random().toString(16).slice(2)}`,
          collectionId: collection.id,
          addedAt: new Date().toISOString(),
          notes: routeKeys.has(organizerItemRouteKey(item)) ? `${item.notes} (merged package variant)` : item.notes,
        }));
      const retainedItems = organizerPackageMergeMode === 'replace-conflicts'
        ? collection.items.filter((item) => !replaceRouteKeys.has(organizerItemRouteKey(item)))
        : collection.items;
      return {
        ...collection,
        updatedAt: new Date().toISOString(),
        lastPackageDigest: selected.packageDigest,
        lastPackageExportedAt: selected.importedAt,
        items: [...importedItems, ...retainedItems].slice(0, 500),
      };
    }));
    setSelectedOrganizerCollectionId(selected.targetCollectionId);
    setSelectedOrganizerItemId('');
    setOrganizerPackageStatus(`Merged package into ${selected.targetCollectionName} with ${organizerPackageMergeModeLabels[organizerPackageMergeMode]}: ${selected.addedItems} add, ${selected.changedItems} change, ${selected.duplicateItems} duplicate`);
    const mergeEntries = buildOrganizerPackageConflictAuditEntries(
      selected,
      'merged',
      organizerPackageMergeMode,
      `merged package conflicts with ${organizerPackageMergeModeLabels[organizerPackageMergeMode]}`,
    );
    if (mergeEntries.length > 0) {
      setOrganizerCollectionDiffs((current) => current.map((item) => (
        item.id === selected.id
          ? { ...item, conflictAuditTrail: [...mergeEntries, ...(item.conflictAuditTrail ?? [])].slice(0, 20) }
          : item
      )));
      setOrganizerPackageConflictAuditTrail((current) => [...mergeEntries, ...current].slice(0, 100));
    }
    appendAuditEvent({
      tool: 'organizer',
      action: 'Merge organizer package',
      target: selected.targetCollectionName,
      decision: 'completed',
      detail: `Merged Organizer package ${selected.packageDigest.slice(0, 12)} with ${selected.addedItems} additions and ${selected.changedItems} changed routes`,
      requestCount: selected.collection.items.length,
      risk: selected.collection.items.some((item) => severityRank[item.risk] >= severityRank.medium) ? 'medium' : 'info',
    });
  }

