  function exportLoggerRawArchive() {
    const sourceEntries = filteredLoggerEntries.length ? filteredLoggerEntries : loggerEntries;
    setLoggerArchiveText(JSON.stringify(buildLoggerRawHttpArchive(sourceEntries.slice(0, 200)), null, 2));
    setLoggerArchiveStatus(`Exported ${sourceEntries.length} captured Logger entr${sourceEntries.length === 1 ? 'y' : 'ies'} as raw HTTP archive JSON`);
  }

  function reviewLoggerRawArchive() {
    try {
      const imported = parseLoggerRawHttpArchive(loggerArchiveText);
      const preset = effectiveLoggerArchiveMappingPreset ?? defaultLoggerArchiveMappingPresets[0];
      const format = detectLoggerArchiveFormat(loggerArchiveText);
      const review = buildLoggerArchiveImportReview(imported, exchanges, preset, format);
      setLoggerArchiveImportReviews((current) => [review, ...current.filter((item) => item.id !== review.id)].slice(0, 12));
      setSelectedLoggerArchiveReviewId(review.id);
      setSelectedLoggerArchiveConflictId(review.conflictDetails[0]?.id ?? '');
      setLoggerArchiveStatus(`Reviewed ${review.exchanges.length} ${loggerArchiveFormatLabel(format)} archive entr${review.exchanges.length === 1 ? 'y' : 'ies'}: ${review.addedEntries} add, ${review.changedEntries} route variant${review.changedEntries === 1 ? '' : 's'}, ${review.duplicateEntries} duplicate${review.duplicateEntries === 1 ? '' : 's'}`);
    } catch (error) {
      setLoggerArchiveStatus(error instanceof Error ? error.message : 'Raw HTTP archive review failed');
    }
  }

  function mergeLoggerArchiveImport(review = selectedLoggerArchiveReview) {
    if (!review) {
      setLoggerArchiveStatus('Review an archive before merging it');
      return;
    }
    const exactKeys = new Set(exchanges.map(loggerArchiveEntryExactKey));
    const routeKeys = new Set(exchanges.map(loggerArchiveEntryRouteKey));
    const replaceRouteKeys = new Set<string>();
    const imported = review.exchanges.filter((exchange) => {
      const key = loggerArchiveEntryExactKey(exchange);
      if (exactKeys.has(key)) return false;
      const routeKey = loggerArchiveEntryRouteKey(exchange);
      if (loggerArchiveMergeStrategy === 'add-only' && routeKeys.has(routeKey)) return false;
      if (loggerArchiveMergeStrategy === 'replace-route' && routeKeys.has(routeKey)) replaceRouteKeys.add(routeKey);
      exactKeys.add(key);
      routeKeys.add(routeKey);
      return true;
    });
    if (!imported.length) {
      setLoggerArchiveStatus(`No entries matched ${loggerArchiveMergeStrategyLabels[loggerArchiveMergeStrategy]} merge criteria from ${review.mappingPresetName}`);
      return;
    }
    enableCaptureForImportedExchanges(imported);
    setExchanges((current) => {
      const base = loggerArchiveMergeStrategy === 'replace-route'
        ? current.filter((exchange) => !replaceRouteKeys.has(loggerArchiveEntryRouteKey(exchange)))
        : current;
      return imported.reduce((next, exchange) => mergeExchanges(exchange, next), base);
    });
    setSelectedExchangeId(imported[0].id);
    setSelectedLoggerEntryId(`logger-${imported[0].id}`);
    setLoggerToolFilter('all');
    setLoggerSearchQuery(imported[0].host);
    const message = `Merged ${imported.length} ${loggerArchiveFormatLabel(review.format)} archive entr${imported.length === 1 ? 'y' : 'ies'} via ${review.mappingPresetName} using ${loggerArchiveMergeStrategyLabels[loggerArchiveMergeStrategy]}: ${review.addedEntries} add, ${review.changedEntries} route variant${review.changedEntries === 1 ? '' : 's'}, ${review.duplicateEntries} duplicate${review.duplicateEntries === 1 ? '' : 's'}`;
    setLoggerArchiveStatus(message);
    appendAuditEvent({
      tool: 'logger',
      action: 'Merge raw HTTP archive',
      target: imported[0].host,
      decision: 'completed',
      detail: message,
      requestCount: imported.length,
      risk: imported.some((exchange) => severityRank[exchange.risk] >= severityRank.medium) ? 'medium' : 'info',
    });
  }

  function importLoggerRawArchive() {
    try {
      const imported = parseLoggerRawHttpArchive(loggerArchiveText);
      const preset = effectiveLoggerArchiveMappingPreset ?? defaultLoggerArchiveMappingPresets[0];
      const format = detectLoggerArchiveFormat(loggerArchiveText);
      const review = buildLoggerArchiveImportReview(imported, exchanges, preset, format);
      setLoggerArchiveImportReviews((current) => [review, ...current.filter((item) => item.id !== review.id)].slice(0, 12));
      setSelectedLoggerArchiveReviewId(review.id);
      setSelectedLoggerArchiveConflictId(review.conflictDetails[0]?.id ?? '');
      mergeLoggerArchiveImport(review);
    } catch (error) {
      setLoggerArchiveStatus(error instanceof Error ? error.message : 'Raw HTTP archive import failed');
    }
  }

  function replayLoggerArchiveReview(review = selectedLoggerArchiveReview) {
    if (!review) {
      setLoggerArchiveStatus('Choose a Logger archive review to replay');
      return;
    }
    const basePreset = loggerArchiveMappingPresets.find((preset) => preset.id === review.mappingPresetId) ?? defaultLoggerArchiveMappingPresets[0];
    const replayPreset: LoggerArchiveMappingPreset = {
      ...basePreset,
      id: review.mappingPresetId,
      name: review.mappingPresetName,
      normalization: review.normalization,
    };
    const replay = buildLoggerArchiveImportReview(review.exchanges, exchanges, replayPreset, review.format);
    replay.replayCount = review.replayCount + 1;
    replay.replayedAt = new Date().toISOString();
    setLoggerArchiveImportReviews((current) => [replay, ...current.filter((item) => item.id !== replay.id)].slice(0, 12));
    setSelectedLoggerArchiveReviewId(replay.id);
    setSelectedLoggerArchiveConflictId(replay.conflictDetails[0]?.id ?? '');
    setSelectedLoggerArchiveMappingPresetId(replay.mappingPresetId);
    setSelectedLoggerArchiveNormalization(replay.normalization);
    setLoggerArchiveText(JSON.stringify({
      kind: 'proxyforge-raw-http-archive',
      version: 1,
      replayedFromReviewId: review.id,
      entries: review.exchanges.map((exchange) => ({
        url: exchange.url,
        source: exchange.source,
        notes: exchange.notes,
        tags: exchange.tags,
        timing: exchange.timing,
        requestRaw: exchange.requestRaw,
        responseRaw: exchange.responseRaw,
      })),
    }, null, 2));
    setLoggerArchiveStatus(`Replayed archive import job ${review.mappingPresetName}: ${replay.addedEntries} add, ${replay.changedEntries} route variant${replay.changedEntries === 1 ? '' : 's'}, ${replay.duplicateEntries} duplicate${replay.duplicateEntries === 1 ? '' : 's'}`);
  }

  function updateLoggerArchiveReviewNotes(reviewId: string, notes: string) {
    setLoggerArchiveImportReviews((current) => current.map((review) => (
      review.id === reviewId ? { ...review, notes } : review
    )));
    setLoggerArchiveStatus('Logger import job notes updated');
  }

