  function batchReplayLoggerArchiveReviews(reviews = filteredLoggerArchiveImportReviews) {
    const selectedReviews = reviews.slice(0, 12);
    if (!selectedReviews.length) {
      setLoggerArchiveStatus('No Logger import jobs match the current timeline filter');
      return;
    }
    const replays = selectedReviews.map((review) => {
      const basePreset = loggerArchiveMappingPresets.find((preset) => preset.id === review.mappingPresetId) ?? defaultLoggerArchiveMappingPresets[0];
      const replayPreset: LoggerArchiveMappingPreset = {
        ...basePreset,
        id: review.mappingPresetId,
        name: review.mappingPresetName,
        normalization: review.normalization,
      };
      const replay = buildLoggerArchiveImportReview(review.exchanges, exchanges, replayPreset, review.format);
      replay.replayCount = review.replayCount + 1;
      replay.replayedAt = new Date().toISOString();
      replay.notes = archiveNoteWithSuffix(review.notes, `Batch replayed from ${loggerArchiveFormatLabel(review.format)} import job.`);
      return replay;
    });
    setLoggerArchiveImportReviews((current) => normalizeLoggerArchiveImportReviews([...replays, ...current]).slice(0, 30));
    setSelectedLoggerArchiveReviewId(replays[0].id);
    setSelectedLoggerArchiveConflictId(replays[0].conflictDetails[0]?.id ?? '');
    setLoggerArchiveText(JSON.stringify({
      kind: 'proxyforge-raw-http-archive',
      version: 1,
      replayedFromReviewIds: selectedReviews.map((review) => review.id),
      entries: selectedReviews.flatMap((review) => review.exchanges).slice(0, 200).map((exchange) => ({
        url: exchange.url,
        source: exchange.source,
        notes: exchange.notes,
        tags: exchange.tags,
        timing: exchange.timing,
        requestRaw: exchange.requestRaw,
        responseRaw: exchange.responseRaw,
      })),
    }, null, 2));
    const replayedExchangeCount = selectedReviews.reduce((total, review) => total + review.exchanges.length, 0);
    const message = `Batch replayed ${selectedReviews.length} Logger import job${selectedReviews.length === 1 ? '' : 's'} with ${replayedExchangeCount} archived exchange${replayedExchangeCount === 1 ? '' : 's'}`;
    setLoggerArchiveStatus(message);
    appendAuditEvent({
      tool: 'logger',
      action: 'Batch replay import history',
      target: selectedReviews.map((review) => review.mappingPresetName).join(', '),
      decision: 'completed',
      detail: message,
      requestCount: replayedExchangeCount,
      risk: selectedReviews.some((review) => review.exchanges.some((exchange) => severityRank[exchange.risk] >= severityRank.medium)) ? 'medium' : 'info',
    });
  }

  function toggleLoggerArchiveReviewReportAttachment(reviewId = selectedLoggerArchiveReview?.id ?? '') {
    if (!reviewId) {
      setLoggerArchiveStatus('Choose a Logger import job before changing report attachment');
      return;
    }
    const isAttached = reportLoggerArchiveReviewIds.includes(reviewId);
    setReportLoggerArchiveReviewIds((current) => {
      const next = current.includes(reviewId) ? current.filter((id) => id !== reviewId) : [reviewId, ...current];
      return normalizeLoggerArchiveReviewIdSelection(next, loggerArchiveImportReviews);
    });
    setLoggerArchiveStatus(isAttached ? 'Detached Logger import job from report evidence' : 'Attached Logger import job to report evidence');
  }

  function attachFilteredLoggerArchiveReviewsToReport() {
    const reviewIds = filteredLoggerArchiveImportReviews.map((review) => review.id);
    if (!reviewIds.length) {
      setLoggerArchiveStatus('No filtered Logger import jobs to attach to reports');
      return;
    }
    setReportLoggerArchiveReviewIds((current) => normalizeLoggerArchiveReviewIdSelection([...reviewIds, ...current], loggerArchiveImportReviews));
    setLoggerArchiveStatus(`Attached ${reviewIds.length} filtered Logger import job${reviewIds.length === 1 ? '' : 's'} to report evidence`);
  }

  async function applyLoggerReportRedactionAndProvenance() {
    const attached = loggerArchiveImportReviews.filter((review) => reportLoggerArchiveReviewIds.includes(review.id));
    if (!attached.length) {
      setReportStatus('Attach a Logger import job before applying provenance and redaction controls');
      return;
    }
    setReportStatus('Applying Logger redaction controls and provenance manifests');
    try {
      const updated = await Promise.all(attached.map(async (review) => {
        const control = loggerRedactionControlForReview(review);
        const redacted = applyLoggerImportJobRedaction(review, control);
        const provenanceManifest = await buildLoggerImportJobProvenanceManifest(
          redacted,
          signLoggerProvenance,
          reportSignerName,
          reportSigningKeyId,
          reportSigningSecret,
        );
        return { ...redacted, provenanceManifest };
      }));
      const byId = new Map(updated.map((review) => [review.id, review]));
      setLoggerArchiveImportReviews((current) => normalizeLoggerArchiveImportReviews(current.map((review) => byId.get(review.id) ?? review)));
      const signedCount = updated.filter((review) => /signed/i.test(review.provenanceManifest?.signature?.status ?? '')).length;
      const message = `Applied Logger redaction to ${updated.length} report job${updated.length === 1 ? '' : 's'}; ${signedCount} signed provenance manifest${signedCount === 1 ? '' : 's'}`;
      setLoggerArchiveStatus(message);
      setReportStatus(message);
      appendAuditEvent({
        tool: 'logger',
        action: 'Apply Logger report provenance',
        target: updated.map((review) => review.mappingPresetName).join(', '),
        decision: 'completed',
        detail: `${message}. Rules: ${loggerRedactionRuleSummary(updated[0]?.redactionControl)}`,
        requestCount: updated.reduce((total, review) => total + review.exchanges.length, 0),
        risk: 'info',
      });
    } catch (error) {
      const message = error instanceof Error ? error.message : 'Logger provenance signing failed';
      setLoggerArchiveStatus(message);
      setReportStatus(message);
    }
  }

  function saveLoggerArchiveMappingPreset() {
    const now = new Date().toISOString();
    const base = effectiveLoggerArchiveMappingPreset ?? defaultLoggerArchiveMappingPresets[0];
    const preset: LoggerArchiveMappingPreset = {
      ...base,
      id: `logger-archive-map-${Date.now()}-${Math.random().toString(16).slice(2)}`,
      name: `${base.name} copy`,
      normalization: selectedLoggerArchiveNormalization,
      pinned: true,
      createdAt: now,
      updatedAt: now,
    };
    setLoggerArchiveMappingPresets((current) => [preset, ...normalizeLoggerArchiveMappingPresets(current)].slice(0, 24));
    setSelectedLoggerArchiveMappingPresetId(preset.id);
    setLoggerArchiveStatus(`Saved archive mapping preset ${preset.name}`);
  }

  function toggleLoggerArchiveMappingPresetPin(presetId = selectedLoggerArchiveMappingPresetId) {
    setLoggerArchiveMappingPresets((current) => normalizeLoggerArchiveMappingPresets(current).map((preset) => (
      preset.id === presetId ? { ...preset, pinned: !preset.pinned, updatedAt: new Date().toISOString() } : preset
    )));
  }

  function exportLoggerPresetLibrary() {
    const library = buildLoggerPresetLibrary(loggerCapturePresets, loggerArchiveMappingPresets);
    setLoggerPresetLibraryText(JSON.stringify(library, null, 2));
    const message = `Exported ${library.capturePresets.length} capture preset${library.capturePresets.length === 1 ? '' : 's'} and ${library.archiveMappingPresets.length} archive mapping${library.archiveMappingPresets.length === 1 ? '' : 's'}`;
    setLoggerCaptureStatus(message);
    setLoggerArchiveStatus(message);
  }

  function importLoggerPresetLibrary() {
    try {
      const library = parseLoggerPresetLibrary(loggerPresetLibraryText);
      setLoggerCapturePresets(library.capturePresets);
      setSelectedLoggerCapturePresetId(library.capturePresets[0]?.id ?? '');
      setLoggerArchiveMappingPresets(library.archiveMappingPresets);
      setSelectedLoggerArchiveMappingPresetId(library.archiveMappingPresets[0]?.id ?? '');
      setSelectedLoggerArchiveNormalization(library.archiveMappingPresets[0]?.normalization ?? 'report-evidence');
      const message = `Imported ${library.capturePresets.length} capture preset${library.capturePresets.length === 1 ? '' : 's'} and ${library.archiveMappingPresets.length} archive mapping${library.archiveMappingPresets.length === 1 ? '' : 's'}`;
      setLoggerCaptureStatus(message);
      setLoggerArchiveStatus(message);
    } catch (error) {
      const message = error instanceof Error ? error.message : 'Logger preset library import failed';
      setLoggerCaptureStatus(message);
      setLoggerArchiveStatus(message);
    }
  }

  function safetyMaxRequests() {
    return Math.max(1, effectiveSafetyPolicy.maxRequestsPerRun);
  }

  function effectiveThrottle(value: number) {
    return Math.max(value, Math.max(0, effectiveSafetyPolicy.minThrottleMs));
  }

  function blockIfOutOfPolicyScope(tool: ToolId, action: string, targetUrl: string, requestCount: number, setStatus: (status: string) => void) {
    if (!effectiveSafetyPolicy.requireScopeMatch) return false;
    const host = targetHostFromUrl(targetUrl);
    if (isHostInScope(host, effectiveScopeAllowlist)) return false;
    const message = `Safety policy blocked ${action}: ${host || targetUrl} is outside project scope`;
    setStatus(message);
    appendAuditEvent({
      tool,
      action,
      target: host || targetUrl,
      decision: 'blocked',
      detail: message,
      requestCount,
      risk: 'medium',
    });
    return true;
  }

  function updateRepeaterTab(tabId: string, patch: Partial<Omit<RepeaterWorkspaceTab, 'id' | 'createdAt'>>) {
    setRepeaterTabs((current) => current.map((tab) => (
      tab.id === tabId ? { ...tab, ...patch, updatedAt: new Date().toISOString() } : tab
    )));
  }

  function updateActiveRepeaterTab(patch: Partial<Omit<RepeaterWorkspaceTab, 'id' | 'createdAt'>>) {
    if (!selectedRepeaterTab) return;
    updateRepeaterTab(selectedRepeaterTab.id, patch);
  }

  function setActiveRepeaterRaw(rawRequest: string) {
    setRepeaterRaw(rawRequest);
    updateActiveRepeaterTab({
      rawRequest,
      name: repeaterNameFromRaw(rawRequest, selectedRepeaterTab?.name),
      dirty: true,
    });
  }

  function setActiveRepeaterTargetUrl(targetUrl: string) {
    setRepeaterTargetUrl(targetUrl);
    updateActiveRepeaterTab({ targetUrl, group: repeaterGroupFromUrl(targetUrl, selectedRepeaterTab?.group ?? 'Ungrouped'), dirty: true });
  }

  function updateSelectedRepeaterGroup(group: string) {
    const nextGroup = group.trim() || 'Ungrouped';
    updateActiveRepeaterTab({ group: nextGroup, dirty: true });
    setRepeaterStatus(`Moved tab to ${nextGroup}`);
  }

  function selectRepeaterTab(tabId: string) {
    const tab = repeaterTabs.find((candidate) => candidate.id === tabId);
    if (!tab) return;
    setSelectedRepeaterTabId(tab.id);
    setRepeaterRaw(tab.rawRequest);
    setRepeaterTargetUrl(tab.targetUrl);
    const lastReplay = tab.lastReplayId ? exchanges.find((exchange) => exchange.id === tab.lastReplayId) : null;
    if (lastReplay) setRepeaterResult(lastReplay);
    setRepeaterStatus(`Loaded ${tab.name}`);
  }

  function createRepeaterTabFromExchange(exchange: HttpExchange = selectedExchange) {
    const now = new Date().toISOString();
    const tab: RepeaterWorkspaceTab = {
      ...makeRepeaterTabFromExchange(exchange, Date.now()),
      id: `rt-${Date.now()}-${Math.random().toString(16).slice(2)}`,
      createdAt: now,
      updatedAt: now,
    };
    setRepeaterTabs((current) => [tab, ...current].slice(0, 24));
    setSelectedRepeaterTabId(tab.id);
    setRepeaterRaw(tab.rawRequest);
    setRepeaterTargetUrl(tab.targetUrl);
    setRepeaterResult(exchange);
    setRepeaterStatus(`Created tab ${tab.name}`);
  }

  function duplicateRepeaterTab() {
    if (!selectedRepeaterTab) return;
    const now = new Date().toISOString();
    const duplicateId = `rt-${Date.now()}-${Math.random().toString(16).slice(2)}`;
    const duplicate: RepeaterWorkspaceTab = {
      ...selectedRepeaterTab,
      id: duplicateId,
      name: `${selectedRepeaterTab.name} copy`,
      rawRequest: repeaterRaw,
      targetUrl: repeaterTargetUrl,
      createdAt: now,
      updatedAt: now,
      dirty: true,
      snapshots: selectedRepeaterTab.snapshots.map((snapshot, index) => ({
        ...snapshot,
        id: `rs-${Date.now()}-${index}-${Math.random().toString(16).slice(2)}`,
        tabId: duplicateId,
      })),
    };
    setRepeaterTabs((current) => [duplicate, ...current].slice(0, 24));
    setSelectedRepeaterTabId(duplicate.id);
    setRepeaterStatus(`Duplicated ${selectedRepeaterTab.name}`);
  }

  function closeRepeaterTab(tabId: string) {
    if (repeaterTabs.length <= 1) {
      const reset = makeRepeaterTabFromExchange(selectedExchange, Date.now());
      setRepeaterTabs([reset]);
      setSelectedRepeaterTabId(reset.id);
      setRepeaterRaw(reset.rawRequest);
      setRepeaterTargetUrl(reset.targetUrl);
      setRepeaterResult(selectedExchange);
      setRepeaterStatus('Reset final Repeater tab');
      return;
    }
    const index = repeaterTabs.findIndex((tab) => tab.id === tabId);
    const nextTabs = repeaterTabs.filter((tab) => tab.id !== tabId);
    const nextTab = nextTabs[Math.max(0, Math.min(index, nextTabs.length - 1))];
    setRepeaterTabs(nextTabs);
    if (selectedRepeaterTabId === tabId && nextTab) {
      setSelectedRepeaterTabId(nextTab.id);
      setRepeaterRaw(nextTab.rawRequest);
      setRepeaterTargetUrl(nextTab.targetUrl);
      const lastReplay = nextTab.lastReplayId ? exchanges.find((exchange) => exchange.id === nextTab.lastReplayId) : null;
      if (lastReplay) setRepeaterResult(lastReplay);
    }
    setRepeaterStatus('Closed Repeater tab');
  }

  function snapshotCurrentRepeaterRequest() {
    if (!selectedRepeaterTab) return;
    const now = new Date().toISOString();
    const previous = selectedRepeaterTab.snapshots[0];
    const replayBaseline = selectedRepeaterTab.lastReplayId ? exchanges.find((exchange) => exchange.id === selectedRepeaterTab.lastReplayId) : null;
    const baselineRaw = previous?.rawRequest ?? replayBaseline?.requestRaw ?? selectedRepeaterTab.rawRequest;
    const snapshot: RepeaterRequestSnapshot = {
      id: `rs-${Date.now()}-${Math.random().toString(16).slice(2)}`,
      tabId: selectedRepeaterTab.id,
      label: `Snapshot ${selectedRepeaterTab.snapshots.length + 1}`,
      targetUrl: repeaterTargetUrl,
      rawRequest: repeaterRaw,
      createdAt: now,
      changedLines: countChangedLines(baselineRaw, repeaterRaw),
    };
    const diff = buildRepeaterDiffEntry(
      selectedRepeaterTab,
      baselineRaw,
      repeaterRaw,
      repeaterTargetUrl,
      `${snapshot.label} diff`,
      previous?.label ?? (replayBaseline ? 'Last replay' : 'Tab baseline'),
      snapshot.label,
    );
    updateRepeaterTab(selectedRepeaterTab.id, {
      targetUrl: repeaterTargetUrl,
      rawRequest: repeaterRaw,
      snapshots: [snapshot, ...selectedRepeaterTab.snapshots].slice(0, 12),
      diffs: [diff, ...(selectedRepeaterTab.diffs ?? [])].slice(0, 12),
      dirty: false,
    });
    setRepeaterStatus(`Captured ${snapshot.label} for ${selectedRepeaterTab.name}; diff ${diff.changedLines} changed line${diff.changedLines === 1 ? '' : 's'}`);
    appendAuditEvent({
      tool: 'repeater',
      action: 'Request snapshot',
      target: selectedRepeaterTab.name,
      decision: 'completed',
      detail: `${snapshot.label} captured with ${snapshot.changedLines} changed line${snapshot.changedLines === 1 ? '' : 's'}`,
      requestCount: 0,
      risk: 'info',
    });
  }

  function restoreRepeaterSnapshot(snapshot: RepeaterRequestSnapshot) {
    setRepeaterRaw(snapshot.rawRequest);
    setRepeaterTargetUrl(snapshot.targetUrl);
    updateRepeaterTab(snapshot.tabId, {
      rawRequest: snapshot.rawRequest,
      targetUrl: snapshot.targetUrl,
      name: repeaterNameFromRaw(snapshot.rawRequest, selectedRepeaterTab?.name),
      dirty: true,
    });
    setRepeaterStatus(`Restored ${snapshot.label}`);
  }

  async function toggleCapture() {
    if (proxyStatus.running) {
      setProxyStatus(await stopProxy());
      return;
    }
    const candidatePorts = [listenerPort, 8081, 8181, 9090, 0].filter((port, index, list) => list.indexOf(port) === index);
    let lastError: unknown = null;
    for (const port of candidatePorts) {
      try {
        const next = await startProxy(port);
        setProxyStatus(next);
        if (next.port !== listenerPort) {
          setListenerPort(next.port);
        }
        return;
      } catch (error) {
        lastError = error;
        const message = error instanceof Error ? error.message : String(error);
        if (!/EACCES|EADDRINUSE/.test(message)) break;
      }
    }
    const message = lastError instanceof Error ? lastError.message : String(lastError);
    setProxyStatus({
      ...proxyStatus,
      running: false,
      message: `Could not bind a proxy listener on any tried port. Last error: ${message}. Pick a different port and retry.`,
    });
  }

  async function launchManagedBrowserForCapture() {
    const targetUrl = browserLaunchTarget.trim() || selectedSessionProfile?.targetUrl || crawlStartUrl || repeaterTargetUrl;
    setBrowserLaunchStatus('Preparing managed browser');
    try {
      const nextProxy = proxyStatus.running ? proxyStatus : await startProxy(listenerPort);
      setProxyStatus(nextProxy);
      const result = await launchBrowser({
        targetUrl,
        browser: browserLaunchFamily,
        proxyHost: '127.0.0.1',
        proxyPort: nextProxy.port,
        profileName: selectedSessionProfile?.name ?? projectName,
        ignoreCertificateErrors: httpsStatus.upstreamTlsMode === 'relaxed',
      });
      setBrowserLaunches((current) => [result, ...current.filter((item) => item.id !== result.id)].slice(0, 20));
      setBrowserLaunchTarget(result.targetUrl);
      setBrowserLaunchStatus(result.message);
      appendAuditEvent({
        tool: 'settings',
        action: 'Launch managed browser',
        target: result.targetUrl,
        decision: result.status === 'launched' || result.status === 'preview' ? 'completed' : 'blocked',
        detail: `${result.browserName} ${result.status}; proxy ${result.proxyHost}:${result.proxyPort}; profile ${result.profilePath}`,
        requestCount: 0,
        risk: result.status === 'error' || result.status === 'not-found' ? 'medium' : 'info',
      });
    } catch (error) {
      const message = error instanceof Error ? error.message : 'Managed browser launch failed';
      setBrowserLaunchStatus(message);
      appendAuditEvent({
        tool: 'settings',
        action: 'Launch managed browser',
        target: targetUrl,
        decision: 'blocked',
        detail: message,
        requestCount: 0,
        risk: 'medium',
      });
    }
  }

  async function extractCookiesFromManagedBrowser() {
    const latestLaunch = browserLaunches[0];
    const profilePath = latestLaunch?.profilePath ?? '';
    const targetUrl = browserLaunchTarget.trim() || latestLaunch?.targetUrl || selectedSessionProfile?.targetUrl || crawlStartUrl || repeaterTargetUrl;
    setBrowserCookieCaptureStatus('Extracting browser cookies');
    try {
      const capture = await extractBrowserCookies({
        targetUrl,
        browser: latestLaunch?.browser && latestLaunch.browser !== 'unknown' ? latestLaunch.browser : browserLaunchFamily,
        profilePath,
      });
      setBrowserCookieCapture(capture);
      setBrowserCookieCaptureStatus(capture.message);
      if (capture.cookieHeader) {
        const profile = makeSessionProfileFromBrowserCookies(capture, sessionProfiles.length + 1);
        setSessionProfiles((current) => [profile, ...current.filter((item) => item.id !== profile.id)].slice(0, 20));
        setSelectedSessionProfileId(profile.id);
      }
      appendAuditEvent({
        tool: 'settings',
        action: 'Extract browser cookies',
        target: capture.targetUrl,
        decision: capture.cookieHeader ? 'completed' : 'blocked',
        detail: `${capture.message} ${capture.encryptedCount} encrypted; ${capture.skippedCount} skipped.`,
        requestCount: 0,
        risk: capture.cookieHeader ? 'info' : 'medium',
      });
    } catch (error) {
      const message = error instanceof Error ? error.message : 'Browser cookie extraction failed';
      setBrowserCookieCaptureStatus(message);
      appendAuditEvent({
        tool: 'settings',
        action: 'Extract browser cookies',
        target: targetUrl,
        decision: 'blocked',
        detail: message,
        requestCount: 0,
        risk: 'medium',
      });
    }
  }

  async function refreshSelectedSessionProfile() {
    if (!selectedSessionProfile) {
      setSessionProfileRefreshStatus('No session profile selected');
      return;
    }
    setSessionProfileRefreshStatus(`Refreshing ${selectedSessionProfile.name}`);
    try {
      const result = await refreshSessionProfile({ profile: selectedSessionProfile });
      const refreshedProfile = refreshSessionProfileCounts(result.profile);
      setLastSessionProfileRefresh(result);
      setSessionProfiles((current) => [refreshedProfile, ...current.filter((profile) => profile.id !== refreshedProfile.id)].slice(0, 20));
      setSelectedSessionProfileId(refreshedProfile.id);
      setSessionProfileRefreshStatus(result.message);
      appendAuditEvent({
        tool: 'settings',
        action: 'Refresh session profile',
        target: refreshedProfile.name,
        decision: result.status === 'failed' ? 'blocked' : 'completed',
        detail: `${result.message} ${result.setCookieCount} Set-Cookie header${result.setCookieCount === 1 ? '' : 's'}; ${result.cookieCount} cookie value${result.cookieCount === 1 ? '' : 's'} ready.`,
        requestCount: 1,
        risk: result.status === 'failed' ? 'medium' : 'info',
      });
    } catch (error) {
      const message = error instanceof Error ? error.message : 'Session refresh failed';
      setSessionProfileRefreshStatus(message);
      appendAuditEvent({
        tool: 'settings',
        action: 'Refresh session profile',
        target: selectedSessionProfile.name,
        decision: 'blocked',
        detail: message,
        requestCount: 1,
        risk: 'medium',
      });
    }
  }

  async function toggleIntercept() {
    const next = await setIntercept(!interceptStatus.enabled);
    setInterceptStatus(next);
  }

  async function toggleResponseIntercept() {
    const next = await setResponseIntercept(!interceptStatus.responseEnabled);
    setInterceptStatus(next);
  }

  async function toggleWebSocketFrameIntercept() {
    const next = await setWebSocketIntercept({
      enabled: !webSocketInterceptStatus.enabled,
      clientEnabled: webSocketInterceptClient,
      serverEnabled: webSocketInterceptServer,
    });
    setWebSocketInterceptStatus(next);
    setWebSocketInterceptClient(next.clientEnabled ?? webSocketInterceptClient);
    setWebSocketInterceptServer(next.serverEnabled ?? webSocketInterceptServer);
    const pending = await listWebSocketIntercepts();
    setPendingWebSocketFrames(pending);
    setSelectedWebSocketInterceptId(pending[0]?.id ?? null);
    setWebSocketActionStatus(next.message);
  }

  async function updateWebSocketInterceptDirections(direction: 'client' | 'server', enabled: boolean) {
    const clientEnabled = direction === 'client' ? enabled : webSocketInterceptClient;
    const serverEnabled = direction === 'server' ? enabled : webSocketInterceptServer;
    setWebSocketInterceptClient(clientEnabled);
    setWebSocketInterceptServer(serverEnabled);
    if (!webSocketInterceptStatus.enabled) return;
    const next = await setWebSocketIntercept({
      enabled: true,
      clientEnabled,
      serverEnabled,
    });
    setWebSocketInterceptStatus(next);
    const pending = await listWebSocketIntercepts();
    setPendingWebSocketFrames(pending);
    setSelectedWebSocketInterceptId(pending[0]?.id ?? null);
    setWebSocketActionStatus(next.message);
  }

  function addMatchReplaceRule() {
    setMatchReplaceRules((current) => [
      ...current,
      {
        id: `mr-${Date.now()}-${Math.random().toString(16).slice(2)}`,
        name: 'New rule',
        enabled: true,
        direction: 'request',
        match: '',
        replace: '',
        isRegex: false,
        caseSensitive: false,
      },
    ]);
  }

  function updateMatchReplaceRule(id: string, patch: Partial<MatchReplaceRule>) {
    setMatchReplaceRules((current) => current.map((rule) => (rule.id === id ? { ...rule, ...patch } : rule)));
  }

  function removeMatchReplaceRule(id: string) {
    setMatchReplaceRules((current) => current.filter((rule) => rule.id !== id));
  }

  function addWebSocketRewriteRule() {
    const rule: WebSocketFrameRewriteRule = {
      id: `ws-rule-${Date.now()}-${Math.random().toString(16).slice(2)}`,
      name: 'New frame rule',
      enabled: true,
      direction: 'both',
      frameType: 'text',
      match: '',
      replace: '',
      isRegex: false,
      caseSensitive: false,
    };
    setWebSocketFrameRewriteRules((current) => [
      ...current,
      rule,
    ].slice(0, 30));
  }

  function updateWebSocketRewriteRule(id: string, patch: Partial<WebSocketFrameRewriteRule>) {
    setWebSocketFrameRewriteRules((current) => current.map((rule) => (rule.id === id ? { ...rule, ...patch } : rule)));
  }

  function removeWebSocketRewriteRule(id: string) {
    setWebSocketFrameRewriteRules((current) => current.filter((rule) => rule.id !== id));
  }

  function applyWebSocketRewriteToSelected() {
    const source = selectedWebSocket ?? webSocketMessages[0];
    if (!source) return;
    const result = applyBrowserWebSocketFrameRewriteRules(source, webSocketFrameRewriteRules);
    if (result.applied.length === 0) {
      setWebSocketActionStatus('No WebSocket rewrite rules matched the selected frame');
      return;
    }
    setWebSocketMessages((current) => [result.frame, ...current.filter((frame) => frame.id !== result.frame.id)].slice(0, 1000));
    setSelectedWebSocketId(result.frame.id);
    setWebSocketFrameEditor(result.frame.payload);
    setWebSocketFrameEditorEncoding(result.frame.payloadEncoding ?? 'text');
    setWebSocketActionStatus(`Applied WebSocket rewrite: ${result.applied.join(', ')}`);
  }

  function saveWebSocketNotebook() {
    const source = selectedWebSocket ?? webSocketMessages[0];
    if (!source) return;
    const existing = webSocketConnectionNotebooks.find((notebook) => notebook.connectionId === source.connectionId);
    const connectionFrames = webSocketMessages.filter((frame) => frame.connectionId === source.connectionId);
    const notebook = makeWebSocketNotebookFromFrame(source, webSocketNotebookDraft, existing);
    const nextNotebook = {
      ...notebook,
      frameCount: connectionFrames.length,
    };
    setWebSocketConnectionNotebooks((current) => [nextNotebook, ...current.filter((item) => item.id !== nextNotebook.id)].slice(0, 60));
    setSelectedWebSocketNotebookId(nextNotebook.id);
    setWebSocketActionStatus(`Saved notebook ${nextNotebook.name}`);
  }

  function pinSelectedWebSocketFrameToNotebook() {
    const source = selectedWebSocket ?? webSocketMessages[0];
    if (!source) return;
    const existing = webSocketConnectionNotebooks.find((notebook) => notebook.id === selectedWebSocketNotebookId || notebook.connectionId === source.connectionId);
    const baseNotebook = makeWebSocketNotebookFromFrame(source, webSocketNotebookDraft, existing);
    const connectionFrames = webSocketMessages.filter((frame) => frame.connectionId === source.connectionId);
    const nextNotebook: WebSocketConnectionNotebook = {
      ...baseNotebook,
      frameCount: connectionFrames.length,
      pinnedFrameIds: Array.from(new Set([source.id, ...baseNotebook.pinnedFrameIds])).slice(0, 20),
      updatedAt: new Date().toISOString(),
    };
    setWebSocketConnectionNotebooks((current) => [nextNotebook, ...current.filter((item) => item.id !== nextNotebook.id)].slice(0, 60));
    setSelectedWebSocketNotebookId(nextNotebook.id);
    setWebSocketActionStatus(`Pinned frame ${source.type} to ${nextNotebook.name}`);
  }

  function loadWebSocketNotebook(notebook: WebSocketConnectionNotebook) {
    setSelectedWebSocketNotebookId(notebook.id);
    setWebSocketNotebookDraft(notebook.notes);
    const frame = webSocketMessages.find((message) => notebook.pinnedFrameIds.includes(message.id))
      ?? webSocketMessages.find((message) => message.connectionId === notebook.connectionId);
    if (frame) setSelectedWebSocketId(frame.id);
    setWebSocketActionStatus(`Loaded notebook ${notebook.name}`);
  }

  async function resolvePendingIntercept(action: InterceptDecision['action']) {
    if (!selectedIntercept) return;

    if (isElectronBridgeReady()) {
      const next = await resolveIntercept({
        id: selectedIntercept.id,
        action,
        rawRequest: interceptEditorRaw,
      });
      setInterceptStatus(next);
      const pending = await listIntercepts();
      setPendingIntercepts(pending);
      setSelectedInterceptId(pending[0]?.id ?? null);
      return;
    }

    const exchange = exchangeFromIntercept(selectedIntercept, interceptEditorRaw, action);
    setPendingIntercepts((current) => current.filter((intercept) => intercept.id !== selectedIntercept.id));
    setInterceptStatus((current) => ({
      ...current,
      pendingCount: Math.max(0, current.pendingCount - 1),
      message: action === 'drop' ? 'Browser preview intercepted request dropped' : 'Browser preview intercepted request forwarded',
    }));
    setExchanges((current) => mergeExchanges(exchange, current));
    setSelectedExchangeId(exchange.id);
  }

  async function resolvePendingWebSocketFrame(action: WebSocketFrameDecision['action']) {
    if (!selectedWebSocketIntercept) return;
    const next = await resolveWebSocketIntercept({
      id: selectedWebSocketIntercept.id,
      action,
      payload: webSocketFrameEditor,
      payloadEncoding: webSocketFrameEditorEncoding,
      opcode: selectedWebSocketIntercept.opcode,
    });
    setWebSocketInterceptStatus(next);
    const pending = await listWebSocketIntercepts();
    setPendingWebSocketFrames(pending);
    setSelectedWebSocketInterceptId(pending[0]?.id ?? null);
    setWebSocketActionStatus(next.message);

    if (!isElectronBridgeReady() && action === 'forward') {
      const forwarded = {
        ...selectedWebSocketIntercept,
        id: `ws-forwarded-${Date.now()}`,
        payload: webSocketFrameEditor,
        payloadEncoding: webSocketFrameEditorEncoding,
        length: websocketByteLength({ ...selectedWebSocketIntercept, payload: webSocketFrameEditor, payloadEncoding: webSocketFrameEditorEncoding }),
        tags: [...selectedWebSocketIntercept.tags.filter((tag) => tag !== 'held'), 'forwarded'],
      };
      const rewritten = applyBrowserWebSocketFrameRewriteRules(forwarded, webSocketFrameRewriteRules);
      setWebSocketMessages((current) => [rewritten.frame, ...current].slice(0, 1000));
      setSelectedWebSocketId(rewritten.frame.id);
      if (rewritten.applied.length > 0) setWebSocketActionStatus(`Browser preview forwarded WebSocket frame; rewrote ${rewritten.applied.join(', ')}.`);
    }
  }

  async function replaySelectedWebSocketFrame() {
    const source = selectedWebSocket ?? webSocketMessages[0];
    if (!source) return;
    const replayed = await replayWebSocketFrame({
      connectionId: source.connectionId,
      direction: source.direction,
      payload: webSocketFrameEditor || source.payload,
      payloadEncoding: webSocketFrameEditorEncoding,
      opcode: source.opcode,
    });
    const nextFrame = isElectronBridgeReady() ? { frame: replayed, applied: [] } : applyBrowserWebSocketFrameRewriteRules(replayed, webSocketFrameRewriteRules);
    setWebSocketMessages((current) => [nextFrame.frame, ...current].slice(0, 1000));
    setSelectedWebSocketId(nextFrame.frame.id);
    setWebSocketActionStatus(replayed.tags.includes('replay-failed')
      ? 'Replay failed: connection is closed'
      : `Replay injected as ${nextFrame.frame.direction === 'client' ? 'client' : 'server'} frame${nextFrame.applied.length ? `; rewrote ${nextFrame.applied.join(', ')}` : ''}`);
  }

  function saveSelectedWebSocketReplay() {
    const source = selectedWebSocket ?? webSocketMessages[0];
    if (!source) return;
    const saved = savedWebSocketReplayFromFrame({
      ...source,
      payload: webSocketFrameEditor || source.payload,
      payloadEncoding: webSocketFrameEditorEncoding,
      length: websocketByteLength({ ...source, payload: webSocketFrameEditor || source.payload, payloadEncoding: webSocketFrameEditorEncoding }),
    });
    setSavedWebSocketReplays((current) => [saved, ...current.filter((item) => item.id !== saved.id)].slice(0, 40));
    setSelectedSavedWebSocketReplayId(saved.id);
    setWebSocketActionStatus(`Saved replay ${saved.name}`);
  }

  async function replaySavedWebSocketFrame(replay: WebSocketSavedReplay) {
    const replayed = await replayWebSocketFrame({
      connectionId: replay.connectionId,
      direction: replay.direction,
      payload: replay.payload,
      payloadEncoding: replay.payloadEncoding,
      opcode: replay.opcode,
    });
    const nextFrame = isElectronBridgeReady() ? { frame: replayed, applied: [] } : applyBrowserWebSocketFrameRewriteRules(replayed, webSocketFrameRewriteRules);
    setWebSocketMessages((current) => [nextFrame.frame, ...current].slice(0, 1000));
    setSelectedWebSocketId(nextFrame.frame.id);
    setSelectedSavedWebSocketReplayId(replay.id);
    setWebSocketActionStatus(replayed.tags.includes('replay-failed')
      ? `Saved replay failed: ${replay.name}`
      : `Saved replay sent: ${replay.name}${nextFrame.applied.length ? `; rewrote ${nextFrame.applied.join(', ')}` : ''}`);
  }

  function loadSavedWebSocketReplay(replay: WebSocketSavedReplay) {
    setSelectedSavedWebSocketReplayId(replay.id);
    setWebSocketFrameEditor(replay.payload);
    setWebSocketFrameEditorEncoding(replay.payloadEncoding ?? 'text');
    setWebSocketActionStatus(`Loaded saved replay ${replay.name}`);
  }

  function loadWebSocketAnomalyCluster(cluster: WebSocketAnomalyCluster) {
    const frame = webSocketMessages.find((message) => cluster.frameIds.includes(message.id));
    if (frame) {
      setSelectedWebSocketId(frame.id);
      setWebSocketFrameEditor(frame.payload);
      setWebSocketFrameEditorEncoding(websocketPayloadEncoding(frame));
    }
    setWebSocketSearch(cluster.connectionId);
    setWebSocketActionStatus(`Loaded anomaly cluster: ${cluster.title}`);
  }

  function loadWebSocketFuzzRun(run: WebSocketSequenceFuzzRun) {
    setSelectedWebSocketFuzzRunId(run.id);
    const probeFrameId = run.probes[0]?.requestFrameId ?? run.sourceFrameId;
    const frame = webSocketMessages.find((message) => message.id === probeFrameId)
      ?? webSocketMessages.find((message) => message.id === run.sourceFrameId)
      ?? webSocketMessages.find((message) => message.connectionId === run.connectionId);
    if (frame) {
      setSelectedWebSocketId(frame.id);
      setWebSocketFrameEditor(frame.payload);
      setWebSocketFrameEditorEncoding(websocketPayloadEncoding(frame));
    }
    setWebSocketSearch(run.connectionId);
    setWebSocketActionStatus(`Loaded fuzz run: ${run.summary}`);
  }

  function runWebSocketSequenceFuzz() {
    const source = selectedWebSocket ?? webSocketMessages[0];
    if (!source) {
      setWebSocketActionStatus('Select a WebSocket frame before running sequence fuzzing');
      return;
    }
    const connectionFrames = webSocketMessages.filter((frame) => frame.connectionId === source.connectionId);
    const { run, frames } = buildWebSocketFuzzArtifacts(source, connectionFrames);
    setWebSocketMessages((current) => [...frames, ...current].slice(0, 1000));
    setWebSocketFuzzRuns((current) => [run, ...current.filter((item) => item.id !== run.id)].slice(0, 40));
    setSelectedWebSocketFuzzRunId(run.id);
    setSelectedWebSocketId(frames[0]?.id ?? source.id);
    setWebSocketFrameEditor(frames[0]?.payload ?? source.payload);
    setWebSocketFrameEditorEncoding(websocketPayloadEncoding(frames[0] ?? source));
    setWebSocketActionStatus(`WebSocket sequence fuzz complete: ${run.summary}`);
    appendAuditEvent({
      tool: 'viewer',
      action: 'WebSocket sequence fuzz',
      target: `${source.host}${source.path}`,
      decision: 'completed',
      detail: `${run.summary} Source frame ${source.id}; run ${run.id}`,
      requestCount: run.totalProbes,
      risk: run.highValueProbes ? 'medium' : 'low',
    });
  }

  function exportWebSocketStateGraphImage() {
    const graph = filteredWebSocketStateGraph ?? selectedWebSocketStateGraph;
    if (!graph) {
      setWebSocketActionStatus('Run WS fuzz before exporting a state graph image');
      return;
    }
    const artifact = buildWebSocketStateGraphExportArtifact(graph, webSocketGraphFilter);
    setWebSocketStateGraphExports((current) => [artifact, ...current.filter((item) => item.id !== artifact.id)].slice(0, 40));
    setSelectedWebSocketStateGraphExportId(artifact.id);
    setWebSocketActionStatus(`Exported WebSocket state graph image ${artifact.fileName}`);
    appendAuditEvent({
      tool: 'viewer',
      action: 'Export WebSocket graph image',
      target: `${artifact.host}${artifact.path}`,
      decision: 'completed',
      detail: `${artifact.title}; ${artifact.nodeCount}/${artifact.totalNodeCount ?? artifact.nodeCount} states; ${artifact.edgeCount}/${artifact.totalEdgeCount ?? artifact.edgeCount} transitions; ${artifact.fileName}`,
      requestCount: 0,
      risk: 'info',
    });
  }

  function analyzeWebSocketConnectionClusters() {
    const clusters = buildWebSocketConnectionClusterSummaries(webSocketMessages, webSocketStateDiffs, selectedWebSocketStateDiff);
    setWebSocketConnectionClusterSummaries(clusters);
    setWebSocketActionStatus(`Analyzed ${clusters.length} WebSocket connection cluster${clusters.length === 1 ? '' : 's'}`);
    if (clusters[0]) {
      setWebSocketSearch(clusters[0].connectionIds[0] ?? clusters[0].hosts[0] ?? '');
    }
    appendAuditEvent({
      tool: 'viewer',
      action: 'Analyze WebSocket clusters',
      target: selectedWebSocket ? `${selectedWebSocket.host}${selectedWebSocket.path}` : 'WebSocket history',
      decision: 'completed',
      detail: `${clusters.length} connection cluster${clusters.length === 1 ? '' : 's'} analyzed across ${webSocketMessages.length} frames`,
      requestCount: 0,
      risk: clusters.some((cluster) => severityRank[cluster.severity] >= severityRank.medium) ? 'medium' : 'info',
    });
  }

  async function exportSelectedWebSocketTranscript(format: WebSocketTranscriptExport['format']) {
    const source = selectedWebSocket ?? webSocketMessages[0];
    if (!source) {
      setWebSocketActionStatus('Select a WebSocket connection before exporting a transcript');
      return;
    }
    const artifact = buildWebSocketTranscriptExport(
      projectName,
      source.connectionId,
      webSocketMessages,
      webSocketFuzzRuns,
      webSocketStateDiffs,
      webSocketCloseCodeInsights,
      format,
    );
    if (!artifact) {
      setWebSocketActionStatus('No WebSocket frames were available for transcript export');
      return;
    }
    setWebSocketActionStatus(`Exporting ${format} WebSocket transcript`);
    try {
      const exported = await exportWebSocketTranscript(artifact);
      if (!exported) {
        setWebSocketActionStatus('WebSocket transcript export canceled');
        return;
      }
      setWebSocketTranscriptExports((current) => [exported, ...current.filter((item) => item.id !== exported.id)].slice(0, 40));
      setSelectedWebSocketTranscriptId(exported.id);
      setWebSocketTranscriptTransferText(exported.content);
      setWebSocketActionStatus(`Exported ${exported.format} transcript with ${exported.frameCount} frames`);
      appendAuditEvent({
        tool: 'viewer',
        action: 'Export WebSocket transcript',
        target: `${exported.host}${exported.path}`,
        decision: 'completed',
        detail: `${exported.title}; ${exported.frameCount} frames; ${exported.fuzzRunIds.length} fuzz runs; ${format}; ${exported.filePath}`,
        requestCount: 0,
        risk: 'info',
      });
    } catch (error) {
      setWebSocketActionStatus(error instanceof Error ? `Transcript export failed: ${error.message}` : 'Transcript export failed');
    }
  }

  async function importWebSocketTranscriptArtifact() {
    setWebSocketActionStatus('Importing WebSocket transcript');
    try {
      const imported = await importWebSocketTranscript(webSocketTranscriptTransferText);
      if (!imported) {
        setWebSocketActionStatus('WebSocket transcript import canceled');
        return;
      }
      setWebSocketTranscriptExports((current) => [imported, ...current.filter((item) => item.id !== imported.id)].slice(0, 40));
      setSelectedWebSocketTranscriptId(imported.id);
      setWebSocketTranscriptTransferText(imported.content);
      const restoredFrames = restoreWebSocketTranscriptFrames(webSocketTranscriptTransferText, imported);
      if (restoredFrames.length > 0) {
        setWebSocketRestoredTranscriptFrames((current) => mergeWebSocketMessages(restoredFrames, current, 200) as WebSocketRestoredTranscriptFrame[]);
        setWebSocketMessages((current) => mergeWebSocketMessages(restoredFrames, current));
        setSelectedWebSocketId(restoredFrames[0].id);
        setWebSocketFrameEditor(restoredFrames[0].payload);
        setWebSocketFrameEditorEncoding(websocketPayloadEncoding(restoredFrames[0]));
      }
      setWebSocketSearch(restoredFrames[0]?.connectionId ?? imported.connectionId);
      setWebSocketActionStatus(`Imported transcript ${imported.title}; restored ${restoredFrames.length} frame${restoredFrames.length === 1 ? '' : 's'}`);
      appendAuditEvent({
        tool: 'viewer',
        action: 'Import WebSocket transcript',
        target: `${imported.host}${imported.path}`,
        decision: 'completed',
        detail: `${imported.title}; ${imported.frameCount} frames; restored ${restoredFrames.length}; ${imported.fileName}`,
        requestCount: 0,
        risk: 'info',
      });
    } catch (error) {
      setWebSocketActionStatus(error instanceof Error ? `Transcript import failed: ${error.message}` : 'Transcript import failed');
    }
  }

  function loadWebSocketDeltaIntoComparer(delta = selectedWebSocketReplayDelta) {
    if (!delta) {
      setWebSocketActionStatus('Run WebSocket fuzzing before loading a replay delta');
      return;
    }
    setComparerLeft(delta.baselinePayload);
    setComparerRight(delta.replayPayload);
    setComparerStatus(`Loaded WebSocket replay delta ${delta.title}`);
    setSelectedWebSocketDeltaId(delta.id);
    setActiveTool('comparer');
  }

  function promoteSelectedWebSocketIssue(frame = selectedWebSocket ?? webSocketMessages[0]) {
    if (!frame) {
      setWebSocketActionStatus('Select a WebSocket frame before promoting an issue');
      return;
    }
    const cluster = webSocketAnomalyClusters.find((item) => item.connectionId === frame.connectionId);
    const issue = buildPromotedWebSocketIssue(frame, cluster);
    setWebSocketPromotedIssues((current) => [issue, ...current.filter((item) => item.id !== issue.id)].slice(0, 100));
    setSelectedIssueId(issue.id);
    setActiveTool('scanner');
    setWebSocketActionStatus(`Promoted ${frame.type} frame into Scanner findings`);
    appendAuditEvent({
      tool: 'viewer',
      action: 'Promote WebSocket finding',
      target: `${issue.host}${issue.path}`,
      decision: 'completed',
      detail: `${issue.title}; ${cluster?.detail ?? frame.payload.slice(0, 160)}`,
      requestCount: 1,
      risk: issue.severity,
    });
  }

  function updateAiProvider(id: AiProviderId, patch: Partial<AiProviderConfig>) {
    setAiProviderSettings((current) => current.map((provider) => (provider.id === id ? { ...provider, ...patch } : provider)));
  }

  async function saveAiProviderSettings() {
    setAiRunStatus('Saving AI provider settings');
    const next = await setAiProviders(aiProviderSettings);
    setAiProviderSettings(next);
    setAiRunStatus('AI provider settings saved');
  }

  function enrichAiRunResult(result: AiRunResult, prompt: string, provider?: AiProviderRuntime, contextDigest?: string): AiRunResult {
    const context = buildAiContextBundle(projectName, scopeAllowlist, result.task, selectedExchange, exchanges, issues);
    return {
      ...result,
      providerLabel: provider?.label ?? result.providerId,
      prompt,
      contextDigest,
      usage: result.usage ?? estimateAiRunUsage(prompt, result.output, result.startedAt, result.completedAt, provider),
      promptEvaluation: result.promptEvaluation ?? buildPromptEvaluation(prompt, provider, result.task, context),
      streamEvents: result.streamEvents ?? [
        {
          id: `ai-stream-${result.id}-complete`,
          at: result.completedAt,
          source: result.status === 'unavailable' ? 'fallback' : 'complete',
          text: result.summary,
        },
      ],
    };
  }

  function applyAiPromptTemplate(template: AiPromptTemplate) {
    setAiTask(template.task);
    setAiPrompt(template.prompt);
    setAiRunStatus(`Loaded template: ${template.title}`);
  }

  function saveCurrentAiPromptTemplate() {
    const now = new Date().toISOString();
    setAiPromptTemplates((current) => current.map((template) => (
      template.id === selectedAiPromptTemplate.id
        ? { ...template, task: aiTask, prompt: aiPrompt, updatedAt: now }
        : template
    )));
    setAiRunStatus(`Saved template: ${selectedAiPromptTemplate.title}`);
  }

  function saveCurrentAiEvaluationBaseline() {
    const provider = aiProviderSettings.find((item) => item.id === selectedAiProviderId) ?? aiProviderSettings[0];
    if (!provider) return;
    const context = buildAiContextBundle(projectName, scopeAllowlist, aiTask, selectedExchange, exchanges, issues);
    const digest = aiContextDigest(context);
    const evaluation = aiResult?.promptEvaluation ?? buildPromptEvaluation(aiPrompt, provider, aiTask, context);
    const usage = aiResult?.usage ?? estimateAiRunUsage(aiPrompt, aiResult?.output ?? '', new Date().toISOString(), new Date().toISOString(), provider);
    const existing = aiEvaluationBaselines.find((baseline) => baseline.providerId === provider.id && baseline.task === aiTask && baseline.contextDigest === digest);
    const baseline = buildAiEvaluationBaseline(provider, aiTask, aiPrompt, digest, evaluation, usage, existing);
    setAiEvaluationBaselines((current) => [baseline, ...current.filter((item) => item.id !== baseline.id)].slice(0, 80));
    setSelectedAiBaselineId(baseline.id);
    setAiRunStatus(`Saved evaluation baseline: ${baseline.providerLabel} score ${baseline.score}`);
    appendAuditEvent({
      tool: 'ai',
      action: 'Save evaluation baseline',
      target: `${baseline.providerLabel} ${aiTaskLabels[baseline.task]}`,
      decision: 'completed',
      detail: `${baseline.name} saved with score ${baseline.score}, context ${baseline.contextDigest}, ${baseline.usage?.totalTokens ?? 0} estimated tokens`,
      requestCount: 0,
      risk: 'info',
    });
  }

  function recordAiActionExecution(executionPackage: AiActionExecutionPackage, risk: Severity) {
    const decision = executionPackage.status === 'blocked'
      ? 'blocked'
      : executionPackage.status === 'queued'
        ? 'updated'
        : 'completed';
    setAiActionExecutionPackages((current) => [
      executionPackage,
      ...current.filter((item) => item.id !== executionPackage.id),
    ].slice(0, 80));
    setSelectedAiActionExecutionPackageId(executionPackage.id);
    setAiRunStatus(executionPackage.summary);
    appendAuditEvent({
      tool: 'ai',
      action: 'AI action execution',
      target: executionPackage.target,
      decision,
      detail: executionPackage.summary,
      requestCount: executionPackage.requestCount,
      risk: executionPackage.status === 'blocked' ? 'medium' : risk,
    });
  }

  function compareAiPromptAcrossProviders() {
    const context = buildAiContextBundle(projectName, scopeAllowlist, aiTask, selectedExchange, exchanges, issues);
    const digest = aiContextDigest(context);
    const baseline = selectedAiBaseline
      ?? aiEvaluationBaselines.find((item) => item.task === aiTask && item.contextDigest === digest);
    const comparisons = buildAiPromptComparisons(aiProviderSettings, aiTask, aiPrompt, context, digest, baseline);
    setAiPromptComparisons(comparisons);
    setAiRunStatus(`Compared prompt across ${comparisons.length} provider profile${comparisons.length === 1 ? '' : 's'}`);
    appendAuditEvent({
      tool: 'ai',
      action: 'Compare provider prompts',
      target: `${aiTaskLabels[aiTask]} prompt`,
      decision: 'completed',
      detail: `Compared ${comparisons.length} provider profile${comparisons.length === 1 ? '' : 's'} against ${baseline ? `${baseline.providerLabel} baseline ${baseline.score}` : 'no saved baseline'} for context ${digest}`,
      requestCount: 0,
      risk: 'info',
    });
  }

  function loadAiEvaluationBaseline(baseline: AiEvaluationBaseline) {
    setSelectedAiBaselineId(baseline.id);
    setSelectedAiProviderId(baseline.providerId);
    setAiTask(baseline.task);
    setAiPrompt(baseline.prompt);
    setAiRunStatus(`Loaded baseline: ${baseline.providerLabel} ${aiTaskLabels[baseline.task]} score ${baseline.score}`);
  }

  function loadAiPromptComparison(comparison: AiPromptComparison) {
    setSelectedAiProviderId(comparison.providerId);
    setAiTask(comparison.task);
    if (comparison.baselineId) setSelectedAiBaselineId(comparison.baselineId);
    setAiRunStatus(`${comparison.providerLabel} comparison ${comparison.verdict}; score ${comparison.score}, delta ${formatSignedDelta(comparison.scoreDelta)}`);
  }

  function exportAiBaselineLibrary() {
    const content = JSON.stringify(
      buildAiBaselineLibraryPackage(projectName, scopeAllowlist, aiEvaluationBaselines, aiPromptComparisons, aiBenchmarkRuns),
      null,
      2,
    );
    setAiBaselineLibraryText(content);
    setAiRunStatus(`Exported ${aiEvaluationBaselines.length} AI baseline${aiEvaluationBaselines.length === 1 ? '' : 's'} to portable library JSON`);
    appendAuditEvent({
      tool: 'ai',
      action: 'Export baseline library',
      target: projectName,
      decision: 'completed',
      detail: `Exported ${aiEvaluationBaselines.length} baselines, ${aiPromptComparisons.length} comparisons, and ${aiBenchmarkRuns.length} benchmark runs`,
      requestCount: 0,
      risk: 'info',
    });
  }

  function importAiBaselineLibrary() {
    try {
      const imported = parseAiBaselineLibraryText(aiBaselineLibraryText);
      if (imported.baselines.length === 0 && imported.comparisons.length === 0 && imported.benchmarkRuns.length === 0) {
        setAiRunStatus('No AI baselines, comparisons, or benchmark runs found in the pasted JSON');
        return;
      }
      setAiEvaluationBaselines((current) => mergeById(current, imported.baselines, 80));
      setAiPromptComparisons((current) => mergeById(current, imported.comparisons, 120));
      setAiBenchmarkRuns((current) => mergeById(current, imported.benchmarkRuns, 30));
      if (imported.baselines[0]) setSelectedAiBaselineId(imported.baselines[0].id);
      setAiRunStatus(`Imported ${imported.baselines.length} baseline${imported.baselines.length === 1 ? '' : 's'} from ${imported.projectName ?? 'AI library'}`);
      appendAuditEvent({
        tool: 'ai',
        action: 'Import baseline library',
        target: imported.projectName ?? projectName,
        decision: 'completed',
        detail: `Imported ${imported.baselines.length} baselines, ${imported.comparisons.length} comparisons, and ${imported.benchmarkRuns.length} benchmark runs`,
        requestCount: 0,
        risk: 'info',
      });
    } catch (error) {
      setAiRunStatus(error instanceof Error ? `AI baseline import failed: ${error.message}` : 'AI baseline import failed');
    }
  }

  function stageCurrentProjectForAiBenchmark() {
    const snapshot = buildCurrentProjectSnapshot();
    setAiBenchmarkProjectText(JSON.stringify(snapshot, null, 2));
    setAiRunStatus(`Staged ${snapshot.projectName} for AI benchmark replay`);
  }

  function replayAiBenchmarkSet() {
    try {
      const currentSnapshot = buildCurrentProjectSnapshot();
      const parsedSnapshot = aiBenchmarkProjectText.trim()
        ? JSON.parse(aiBenchmarkProjectText) as Partial<ProjectSnapshot>
        : {};
      const snapshot: ProjectSnapshot = {
        ...currentSnapshot,
        ...parsedSnapshot,
        version: 1,
        savedAt: parsedSnapshot.savedAt ?? currentSnapshot.savedAt,
        projectName: parsedSnapshot.projectName ?? currentSnapshot.projectName,
        scopeAllowlist: Array.isArray(parsedSnapshot.scopeAllowlist) ? parsedSnapshot.scopeAllowlist : currentSnapshot.scopeAllowlist,
        exchanges: Array.isArray(parsedSnapshot.exchanges) ? parsedSnapshot.exchanges : currentSnapshot.exchanges,
        aiEvaluationBaselines: Array.isArray(parsedSnapshot.aiEvaluationBaselines)
          ? parsedSnapshot.aiEvaluationBaselines.filter(isAiEvaluationBaseline)
          : currentSnapshot.aiEvaluationBaselines,
        aiPromptComparisons: Array.isArray(parsedSnapshot.aiPromptComparisons)
          ? parsedSnapshot.aiPromptComparisons.filter(isAiPromptComparison)
          : currentSnapshot.aiPromptComparisons,
        aiBenchmarkRuns: Array.isArray(parsedSnapshot.aiBenchmarkRuns)
          ? parsedSnapshot.aiBenchmarkRuns.filter(isAiBenchmarkRun)
          : currentSnapshot.aiBenchmarkRuns,
      };
      const baselines = snapshot.aiEvaluationBaselines ?? [];
      if (baselines.length === 0) {
        setAiRunStatus('Benchmark replay needs at least one AI evaluation baseline in the staged project');
        return;
      }
      const run = buildAiBenchmarkReplayRun(aiProviderSettings, snapshot);
      setAiBenchmarkRuns((current) => [run, ...current.filter((item) => item.id !== run.id)].slice(0, 30));
      setAiPromptComparisons(run.results.slice(0, 80));
      setAiRunStatus(`Benchmark replay complete: ${run.resultCount} provider result${run.resultCount === 1 ? '' : 's'}, ${run.regressedCount} regression${run.regressedCount === 1 ? '' : 's'}`);
      appendAuditEvent({
        tool: 'ai',
        action: 'Replay benchmark set',
        target: run.projectName,
        decision: 'completed',
        detail: `${run.notes} Average score ${run.averageScore}; ${run.improvedCount} improved, ${run.regressedCount} regressed`,
        requestCount: 0,
        risk: run.regressedCount > 0 ? 'medium' : 'info',
      });
    } catch (error) {
      setAiRunStatus(error instanceof Error ? `AI benchmark replay failed: ${error.message}` : 'AI benchmark replay failed');
    }
  }

  function loadAiRunFromHistory(run: AiRunResult) {
    setAiResult(run);
    setSelectedAiProviderId(run.providerId);
    setAiTask(run.task);
    if (run.prompt) setAiPrompt(run.prompt);
    setAiRunStatus(`Loaded ${run.providerLabel ?? run.providerId} ${aiTaskLabels[run.task]} run`);
  }

  async function runSelectedAiTask() {
    if (!selectedExchange) return;
    const provider = aiProviderSettings.find((item) => item.id === selectedAiProviderId);
    const context = buildAiContextBundle(projectName, scopeAllowlist, aiTask, selectedExchange, exchanges, issues);
    setAiRunStatus(`Running ${provider?.label ?? selectedAiProviderId} ${aiTaskLabels[aiTask]}`);
    const result = await runAiTask({
      providerId: selectedAiProviderId,
      task: aiTask,
      prompt: aiPrompt,
      context,
    });
    const enriched = enrichAiRunResult(result, aiPrompt, provider, aiContextDigest(context));
    setAiResult(enriched);
    setAiRunHistory((current) => [enriched, ...current.filter((item) => item.id !== enriched.id)].slice(0, 100));
    setAiRunStatus(`${enriched.summary} · ${enriched.usage?.totalTokens ?? 0} estimated tokens`);
    appendAuditEvent({
      tool: 'ai',
      action: 'AI task',
      target: `${provider?.label ?? selectedAiProviderId} ${aiTaskLabels[aiTask]}`,
      decision: enriched.status === 'error' ? 'blocked' : 'completed',
      detail: `${enriched.summary}; ${enriched.usage?.totalTokens ?? 0} estimated tokens; ${enriched.contextDigest ?? 'context unavailable'}`,
      requestCount: 0,
      risk: enriched.status === 'error' ? 'medium' : 'info',
    });
  }

  async function sendRepeater() {
    if (!selectedExchange || !repeaterTargetUrl.trim()) return;
    if (blockIfOutOfPolicyScope('repeater', 'Repeater replay', repeaterTargetUrl, 1, setRepeaterStatus)) return;
    setRepeaterStatus('Sending scoped replay');
    const replayed = await replayRequest({
      rawRequest: repeaterRaw,
      targetUrl: repeaterTargetUrl,
      scopeAllowlist: effectiveScopeAllowlist,
      settings: replayTransportSettings,
      oastPayloads: repeaterOastPayloadsForRaw(repeaterRaw),
      repeaterTabId: selectedRepeaterTab?.id,
      repeaterTabName: selectedRepeaterTab?.name,
      repeaterTabGroup: selectedRepeaterTab?.group,
      sourceExchangeId: selectedExchange.id,
      tags: ['manual-replay'],
      notes: selectedRepeaterTab ? `Desktop Repeater send from ${selectedRepeaterTab.name}` : 'Desktop Repeater send',
    });
    setRepeaterResult(replayed);
    setExchanges((current) => mergeExchanges(replayed, current));
    setSelectedExchangeId(replayed.id);
    setRepeaterStatus(replayed.status === 0 ? replayed.notes : `Replay complete: ${replayed.status}`);
    updateActiveRepeaterTab({
      rawRequest: repeaterRaw,
      targetUrl: repeaterTargetUrl,
      name: repeaterNameFromRaw(repeaterRaw, selectedRepeaterTab?.name),
      lastStatus: replayed.status,
      lastReplayId: replayed.id,
      dirty: false,
    });
    appendAuditEvent({
      tool: 'repeater',
      action: 'Repeater replay',
      target: selectedRepeaterTab?.name ?? `${selectedExchange.method} ${selectedExchange.host}${selectedExchange.path}`,
      decision: replayed.status === 0 ? 'blocked' : 'completed',
      detail: replayed.notes,
      requestCount: 1,
      risk: replayed.risk,
    });
  }

  function loadExchangeIntoRepeater(exchange: HttpExchange) {
    setSelectedExchangeId(exchange.id);
    setRepeaterRaw(exchange.requestRaw);
    setRepeaterTargetUrl(exchange.url);
    setRepeaterResult(exchange);
    updateActiveRepeaterTab({
      rawRequest: exchange.requestRaw,
      targetUrl: exchange.url,
      name: `${exchange.method} ${exchange.path}`,
      group: repeaterGroupFromUrl(exchange.url),
      lastStatus: exchange.status,
      lastReplayId: exchange.id,
      dirty: false,
    });
    setRepeaterStatus(`Loaded ${exchange.method} ${exchange.path}`);
  }

  function proxyHistorySelectedOrVisibleIds(limit = 40) {
    const visible = new Set(filteredExchanges.map((exchange) => exchange.id));
    const selected = proxyHistorySelectedIds.filter((id) => visible.has(id));
    return (selected.length ? selected : filteredExchanges.map((exchange) => exchange.id)).slice(0, limit);
  }

  function setProxyHistorySelected(id: string, additive = false) {
    setSelectedExchangeId(id);
    setProxyHistorySelectedIds((current) => {
      if (!additive) return [id];
      return current.includes(id) ? current.filter((item) => item !== id) : [id, ...current].slice(0, 80);
    });
  }

  function reviewProxyInterceptRules() {
    const review = buildProxyInterceptRuleReview({
      exchanges,
      rules: matchReplaceRules,
      filters: proxyHistoryFilters,
      selectedExchangeIds: proxyHistorySelectedOrVisibleIds(),
      viewModel: proxyHistoryViewModel,
    });
    setProxyInterceptRuleReviews((current) => [review, ...current.filter((item) => item.id !== review.id)].slice(0, 40));
    setSelectedProxyInterceptRuleReviewId(review.id);
    setProxyHistoryPackageText(review.content);
    setProxyHistoryWorkflowStatus(review.summary);
    appendAuditEvent({
      tool: 'proxy',
      action: 'Review Proxy intercept rules',
      target: `${review.activeRuleCount} active rule(s)`,
      decision: 'completed',
      detail: review.summary,
      requestCount: review.affectedExchangeCount,
      risk: review.riskyRuleCount ? 'medium' : 'info',
    });
  }

  function createProxyCapturePresetHandoff() {
    const handoff = buildProxyCapturePresetHandoff({
      exchanges,
      rules: matchReplaceRules,
      filters: proxyHistoryFilters,
      selectedExchangeIds: proxyHistorySelectedOrVisibleIds(),
      viewModel: proxyHistoryViewModel,
      ruleReview: selectedProxyInterceptRuleReview,
    });
    setProxyCapturePresetHandoffs((current) => [handoff, ...current.filter((item) => item.id !== handoff.id)].slice(0, 40));
    setSelectedProxyCapturePresetHandoffId(handoff.id);
    setProxyHistoryPackageText(handoff.content);
    const handoffLoggerSources = handoff.includedSources.flatMap((source): LoggerToolSource[] => {
      const loggerSource = source as LoggerToolSource;
      return loggerCaptureSources.includes(loggerSource) ? [loggerSource] : [];
    });
    const enabledTools: LoggerToolSource[] = Array.from(new Set<LoggerToolSource>(['proxy', ...handoffLoggerSources]));
    const loggerPreset: LoggerCapturePreset = {
      id: `logger-preset-${handoff.id}`,
      name: handoff.presetName,
      description: handoff.summary,
      pinned: true,
      controls: capturePresetControls(enabledTools),
      createdAt: handoff.createdAt,
      updatedAt: handoff.createdAt,
    };
    setLoggerCapturePresets((current) => [loggerPreset, ...current.filter((preset) => preset.id !== loggerPreset.id)].slice(0, 24));
    setSelectedLoggerCapturePresetId(loggerPreset.id);
    setLoggerCaptureStatus(`Proxy capture preset handoff staged: ${handoff.summary}`);
    setProxyHistoryWorkflowStatus(handoff.summary);
    appendAuditEvent({
      tool: 'proxy',
      action: 'Create Proxy capture preset',
      target: handoff.fileName,
      decision: 'completed',
      detail: handoff.summary,
      requestCount: handoff.exchangeIds.length,
      risk: 'info',
    });
  }

  function saveProxyTrafficComparisonPackage() {
    const visibleIds = proxyHistorySelectedOrVisibleIds(120);
    const packageArtifact = buildProxyTrafficComparisonPackage({
      exchanges,
      rules: matchReplaceRules,
      filters: proxyHistoryFilters,
      selectedExchangeIds: visibleIds,
      viewModel: proxyHistoryViewModel,
      baseline: {
        name: 'Proxy baseline history',
        exchanges: exchanges.filter((exchange) => exchange.source === 'proxy').slice(0, 120),
      },
      candidate: {
        name: 'Filtered Proxy history',
        exchangeIds: visibleIds,
      },
    });
    setProxyTrafficComparisonPackages((current) => [packageArtifact, ...current.filter((item) => item.id !== packageArtifact.id)].slice(0, 40));
    setSelectedProxyTrafficComparisonPackageId(packageArtifact.id);
    setProxyHistoryPackageText(packageArtifact.content);
    setProxyHistoryWorkflowStatus(packageArtifact.summary);
    appendAuditEvent({
      tool: 'proxy',
      action: 'Save Proxy traffic comparison',
      target: packageArtifact.fileName,
      decision: 'completed',
      detail: packageArtifact.summary,
      requestCount: packageArtifact.deltas.length,
      risk: packageArtifact.statusDrift ? 'medium' : 'info',
    });
  }

  function promoteProxyHistoryToRepeater() {
    const selectedId = proxyHistorySelectedOrVisibleIds(1)[0];
    const exchange = exchanges.find((item) => item.id === selectedId) ?? filteredExchanges[0];
    if (!exchange) {
      setProxyHistoryWorkflowStatus('No Proxy history item is visible for Repeater promotion');
      return;
    }
    loadExchangeIntoRepeater(exchange);
    setActiveTool('repeater');
    setProxyHistoryWorkflowStatus(`Loaded ${exchange.method} ${exchange.path} into Repeater from advanced Proxy history`);
  }

  function promoteProxyHistoryToScanner() {
    const issue = buildProxyScannerPromotionIssue({
      exchanges,
      rules: matchReplaceRules,
      filters: proxyHistoryFilters,
      selectedExchangeIds: proxyHistorySelectedOrVisibleIds(),
      viewModel: proxyHistoryViewModel,
    });
    setImportedBundleIssues((current) => [issue, ...current.filter((item) => item.id !== issue.id)].slice(0, 200));
    setSelectedIssueId(issue.id);
    updateScannerQueueItem('queue-active-scan', {
      status: 'queued',
      detail: `Proxy history promotion queued ${proxyHistoryViewModel.rows.filter((row) => row.scannerReady).length} scanner-ready request(s).`,
      requestCount: Math.max(1, proxyHistoryViewModel.rows.filter((row) => row.scannerReady).length),
      priority: issue.severity,
    });
    setActiveTool('scanner');
    setProxyHistoryWorkflowStatus(`Promoted Proxy history evidence into Scanner: ${issue.title}`);
    appendAuditEvent({
      tool: 'proxy',
      action: 'Promote Proxy history to Scanner',
      target: `${issue.host}${issue.path}`,
      decision: 'completed',
      detail: issue.detail,
      requestCount: proxyHistoryViewModel.rows.filter((row) => row.scannerReady).length,
      risk: issue.severity,
    });
  }

  function attachProxyHistoryEvidenceToReport() {
    const issue = buildProxyScannerPromotionIssue({
      exchanges,
      rules: matchReplaceRules,
      filters: proxyHistoryFilters,
      selectedExchangeIds: proxyHistorySelectedOrVisibleIds(),
      viewModel: proxyHistoryViewModel,
    });
    const ruleReview = selectedProxyInterceptRuleReview ?? buildProxyInterceptRuleReview({
      exchanges,
      rules: matchReplaceRules,
      filters: proxyHistoryFilters,
      selectedExchangeIds: proxyHistorySelectedOrVisibleIds(),
      viewModel: proxyHistoryViewModel,
    });
    const capturePreset = selectedProxyCapturePresetHandoff ?? buildProxyCapturePresetHandoff({
      exchanges,
      rules: matchReplaceRules,
      filters: proxyHistoryFilters,
      selectedExchangeIds: proxyHistorySelectedOrVisibleIds(),
      viewModel: proxyHistoryViewModel,
      ruleReview,
    });
    const comparisonPackage = selectedProxyTrafficComparisonPackage ?? buildProxyTrafficComparisonPackage({
      exchanges,
      rules: matchReplaceRules,
      filters: proxyHistoryFilters,
      selectedExchangeIds: proxyHistorySelectedOrVisibleIds(),
      viewModel: proxyHistoryViewModel,
      baseline: {
        name: 'Proxy baseline history',
        exchanges: exchanges.filter((exchange) => exchange.source === 'proxy').slice(0, 120),
      },
      candidate: {
        name: 'Filtered Proxy history',
        exchangeIds: proxyHistorySelectedOrVisibleIds(120),
      },
    });
    const attachment = buildProxyHistoryEvidenceAttachment({
      exchanges,
      rules: matchReplaceRules,
      filters: proxyHistoryFilters,
      selectedExchangeIds: proxyHistorySelectedOrVisibleIds(120),
      viewModel: proxyHistoryViewModel,
      ruleReview,
      capturePreset,
      comparisonPackage,
      issueId: issue.id,
    });
    setImportedBundleIssues((current) => [issue, ...current.filter((item) => item.id !== issue.id)].slice(0, 200));
    setProxyInterceptRuleReviews((current) => [ruleReview, ...current.filter((item) => item.id !== ruleReview.id)].slice(0, 40));
    setSelectedProxyInterceptRuleReviewId(ruleReview.id);
    setProxyCapturePresetHandoffs((current) => [capturePreset, ...current.filter((item) => item.id !== capturePreset.id)].slice(0, 40));
    setSelectedProxyCapturePresetHandoffId(capturePreset.id);
    setProxyTrafficComparisonPackages((current) => [comparisonPackage, ...current.filter((item) => item.id !== comparisonPackage.id)].slice(0, 40));
    setSelectedProxyTrafficComparisonPackageId(comparisonPackage.id);
    setProxyHistoryEvidenceAttachments((current) => [attachment, ...current.filter((item) => item.id !== attachment.id)].slice(0, 40));
    setSelectedProxyHistoryEvidenceAttachmentId(attachment.id);
    setSelectedIssueId(issue.id);
    setProxyHistoryPackageText(attachment.content);
    setReportArtifact(null);
    setProxyHistoryWorkflowStatus(`Proxy history evidence attached to report: ${attachment.fileName}`);
    appendAuditEvent({
      tool: 'proxy',
      action: 'Attach Proxy history evidence',
      target: attachment.fileName,
      decision: 'completed',
      detail: attachment.summary,
      requestCount: attachment.exchangeIds.length,
      risk: issue.severity,
    });
  }

  function loadSavedRepeaterRequest(request: RepeaterSavedRequest) {
    setSelectedSavedRepeaterRequestId(request.id);
    setRepeaterRaw(request.rawRequest);
    setRepeaterTargetUrl(request.targetUrl);
    updateActiveRepeaterTab({
      rawRequest: request.rawRequest,
      targetUrl: request.targetUrl,
      name: request.name,
      group: request.folder || repeaterGroupFromUrl(request.targetUrl),
      dirty: true,
    });
    setRepeaterStatus(`Loaded saved request ${request.name}`);
  }

  function updateSessionProfile(id: string, patch: Partial<SessionProfile>) {
    setSessionProfiles((current) => current.map((profile) => (
      profile.id === id
        ? refreshSessionProfileCounts({ ...profile, ...patch, updatedAt: new Date().toISOString() })
        : profile
    )));
  }

  function markSessionProfileUsed(profileId: string | undefined) {
    if (!profileId) return;
    const now = new Date().toISOString();
    setSessionProfiles((current) => current.map((profile) => (
      profile.id === profileId ? { ...profile, status: profile.status === 'needs-refresh' ? 'stale' : profile.status, lastUsedAt: now, updatedAt: now } : profile
    )));
  }

  function repeaterOastPayloadsForRaw(rawRequest: string) {
    return callbackPayloads.filter((payload) => (
      rawRequest.includes(payload.id)
      || rawRequest.includes(payload.token)
      || rawRequest.includes(payload.endpoint)
      || rawRequest.includes(encodeURIComponent(payload.endpoint))
    )).slice(0, 20);
  }

  function addSessionProfileFromSelectedExchange() {
    if (!selectedExchange) return;
    const profile = makeSessionProfileFromExchange(selectedExchange, sessionProfiles.length + 1);
    setSessionProfiles((current) => [profile, ...current.filter((item) => item.id !== profile.id)].slice(0, 20));
    setSelectedSessionProfileId(profile.id);
    appendAuditEvent({
      tool: 'settings',
      action: 'Capture session profile',
      target: profile.name,
      decision: 'completed',
      detail: `${profile.headerCount} session header${profile.headerCount === 1 ? '' : 's'} and ${profile.cookieCount} cookie value${profile.cookieCount === 1 ? '' : 's'} captured from selected traffic.`,
      requestCount: 0,
      risk: 'info',
    });
  }

  function addManualSessionProfile() {
    const now = new Date().toISOString();
    const profile = refreshSessionProfileCounts({
      id: `session-manual-${Date.now()}`,
      name: `Manual Session ${sessionProfiles.length + 1}`,
      role: 'operator',
      targetUrl: crawlStartUrl || repeaterTargetUrl,
      source: 'manual',
      status: 'ready',
      headerText: 'Authorization: Bearer replace-me',
      cookieText: 'session=replace-me',
      createdAt: now,
      updatedAt: now,
      headerCount: 0,
      cookieCount: 0,
      notes: 'Manual session profile for authorized crawler, Repeater, and scanner workflows.',
    });
    setSessionProfiles((current) => [profile, ...current].slice(0, 20));
    setSelectedSessionProfileId(profile.id);
  }

  function applySelectedSessionToRepeater() {
    if (!selectedSessionProfile) {
      setRepeaterStatus('No session profile selected');
      setReplayProfileInjectionStatus('No replay session profile selected');
      return;
    }
    const raw = applySessionProfileToRawRequest(repeaterRaw, selectedSessionProfile);
    const injection = makeReplaySessionProfileInjection(selectedSessionProfile);
    setRepeaterRaw(raw);
    updateActiveRepeaterTab({
      rawRequest: raw,
      targetUrl: repeaterTargetUrl,
      name: repeaterNameFromRaw(raw, selectedRepeaterTab?.name),
      dirty: true,
    });
    setReplaySessionProfileInjections((current) => [injection, ...current].slice(0, 30));
    markSessionProfileUsed(selectedSessionProfile.id);
    setRepeaterStatus(`Applied ${selectedSessionProfile.name} to Repeater`);
    setReplayProfileInjectionStatus(`Injected ${selectedSessionProfile.name} into active Replay request`);
    appendAuditEvent({
      tool: 'repeater',
      action: 'Apply session profile',
      target: selectedSessionProfile.name,
      decision: 'updated',
      detail: `${selectedSessionProfile.headerCount} header${selectedSessionProfile.headerCount === 1 ? '' : 's'} staged in the active Repeater request.`,
      requestCount: 0,
      risk: 'info',
    });
  }

  function stageSelectedSessionForCrawler() {
    if (!selectedSessionProfile) return;
    setCrawlStartUrl(selectedSessionProfile.targetUrl || crawlStartUrl);
    markSessionProfileUsed(selectedSessionProfile.id);
    setCrawlStatus(`${selectedSessionProfile.name} selected for authenticated crawler runs`);
  }

  function saveRepeaterRequestToCollection() {
    if (!repeaterTargetUrl.trim()) {
      setRepeaterStatus('Set a target URL before saving the request');
      return;
    }
    const firstLine = repeaterRaw.split(/\r?\n/, 1)[0] ?? 'GET / HTTP/1.1';
    const [method = 'GET', path = '/'] = firstLine.split(/\s+/);
    const host = targetHostFromUrl(repeaterTargetUrl);
    const existing = savedRepeaterRequests.find((request) => request.targetUrl === repeaterTargetUrl && request.rawRequest === repeaterRaw);
    const now = new Date().toISOString();
    const saved: RepeaterSavedRequest = {
      id: existing?.id ?? `saved-repeater-${Date.now()}-${Math.random().toString(16).slice(2)}`,
      name: `${method} ${path}`,
      folder: host || 'Manual',
      targetUrl: repeaterTargetUrl,
      rawRequest: repeaterRaw,
      createdAt: existing?.createdAt ?? now,
      updatedAt: now,
      tags: Array.from(new Set(['manual', method.toLowerCase(), host].filter(Boolean))).slice(0, 8),
    };
    setSavedRepeaterRequests((current) => [saved, ...current.filter((request) => request.id !== saved.id)].slice(0, 100));
    setSelectedSavedRepeaterRequestId(saved.id);
    setRepeaterStatus(`Saved ${saved.name} to collection`);
    appendAuditEvent({
      tool: 'repeater',
      action: 'Save request',
      target: `${saved.folder} ${saved.name}`,
      decision: 'completed',
      detail: `Saved Repeater request ${saved.name} for ${saved.targetUrl}`,
      requestCount: 0,
      risk: 'info',
    });
  }

  function addCurrentRequestToReplayBulkQueue() {
    if (!repeaterTargetUrl.trim() || !repeaterRaw.trim()) {
      setRepeaterStatus('Set a target URL and request before queueing bulk replay');
      return;
    }
    const profile = selectedSessionProfile;
    const item: ReplayBulkRunItem = {
      id: `replay-bulk-item-${Date.now()}-${Math.random().toString(16).slice(2)}`,
      name: repeaterNameFromRaw(repeaterRaw, selectedRepeaterTab?.name),
      targetUrl: repeaterTargetUrl,
      rawRequest: repeaterRaw,
      status: 'queued',
      blocked: false,
      message: profile ? `Queued with ${profile.name}` : 'Queued without a session profile',
      sessionProfileId: profile?.id,
      sessionProfileInjectionId: replaySessionProfileInjections[0]?.sessionProfileId === profile?.id ? replaySessionProfileInjections[0]?.id : undefined,
      sourceExchangeId: selectedExchange?.id,
      sourceRepeaterTabId: selectedRepeaterTab?.id,
    };
    setReplayBulkQueue((current) => [item, ...current].slice(0, safetyMaxRequests()));
    setRepeaterStatus(`Queued ${item.name} for bulk replay`);
  }

  async function runReplayBulkQueue() {
    const queue = replayBulkQueue.length
      ? replayBulkQueue.slice(0, safetyMaxRequests())
      : [{
          id: `replay-bulk-item-${Date.now()}-current`,
          name: repeaterNameFromRaw(repeaterRaw, selectedRepeaterTab?.name),
          targetUrl: repeaterTargetUrl,
          rawRequest: repeaterRaw,
          status: 'queued' as const,
          blocked: false,
          message: 'Queued current request',
          sessionProfileId: selectedSessionProfile?.id,
          sourceExchangeId: selectedExchange?.id,
          sourceRepeaterTabId: selectedRepeaterTab?.id,
        }];
    const startedAt = new Date();
    const results: ReplayBulkRunItem[] = [];
    const replayedExchanges: HttpExchange[] = [];
    setRepeaterStatus(`Running bulk replay for ${queue.length} queued request${queue.length === 1 ? '' : 's'}`);

    for (const item of queue) {
      const host = targetHostFromUrl(item.targetUrl);
      if (effectiveSafetyPolicy.requireScopeMatch && !isHostInScope(host, effectiveScopeAllowlist)) {
        results.push({
          ...item,
          status: 'blocked',
          blocked: true,
          message: `Blocked by project scope: ${host || item.targetUrl}`,
        });
        continue;
      }
      const profile = sessionProfiles.find((candidate) => candidate.id === item.sessionProfileId) ?? selectedSessionProfile;
      const rawRequest = profile ? applySessionProfileToRawRequest(item.rawRequest, profile) : item.rawRequest;
      const replayed = await replayRequest({
        rawRequest,
        targetUrl: item.targetUrl,
        scopeAllowlist: effectiveScopeAllowlist,
        settings: replayTransportSettings,
        repeaterTabId: item.sourceRepeaterTabId,
        repeaterTabName: item.name,
        sourceExchangeId: item.sourceExchangeId,
        tags: ['bulk-replay'],
        notes: `Bulk Replay queue item ${item.name}`,
      });
      const exchange: HttpExchange = {
        ...replayed,
        id: `${replayed.id}-bulk-${item.id}`,
        notes: `Bulk Replay ${item.name}${profile ? ` via ${profile.name}` : ''}: ${replayed.notes}`,
        tags: Array.from(new Set([...replayed.tags, 'bulk-replay', item.sourceRepeaterTabId ? `tab:${item.sourceRepeaterTabId}` : 'manual-bulk'])),
      };
      replayedExchanges.push(exchange);
      if (profile) markSessionProfileUsed(profile.id);
      results.push({
        ...item,
        rawRequest,
        status: exchange.status === 0 ? 'failed' : 'completed',
        blocked: exchange.status === 0,
        message: exchange.notes,
        exchangeId: exchange.id,
        statusCode: exchange.status,
        length: exchange.length,
        timing: exchange.timing,
        risk: exchange.risk,
      });
    }

    const completedAt = new Date();
    const blockedRequests = results.filter((item) => item.blocked || item.status === 'blocked').length;
    const failedRequests = results.filter((item) => item.status === 'failed').length;
    const completedRequests = results.filter((item) => item.status === 'completed').length;
    const profileNames = Array.from(new Set(results
      .map((item) => sessionProfiles.find((profile) => profile.id === item.sessionProfileId)?.name)
      .filter((name): name is string => Boolean(name))));
    const run: ReplayBulkRun = {
      id: `replay-bulk-${startedAt.getTime()}`,
      name: `Bulk Replay ${repeaterNameFromRaw(repeaterRaw)}`,
      startedAt: startedAt.toISOString(),
      completedAt: completedAt.toISOString(),
      status: blockedRequests > 0 || failedRequests > 0 ? 'partial' : 'completed',
      totalRequests: results.length,
      completedRequests,
      blockedRequests,
      failedRequests,
      message: `Bulk replay complete: ${completedRequests}/${results.length} request${results.length === 1 ? '' : 's'} replayed${profileNames.length ? ` with ${profileNames.join(', ')}` : ''}`,
      sessionProfileId: selectedSessionProfile?.id,
      sessionProfileInjectionId: replaySessionProfileInjections[0]?.id,
      throttleMs: effectiveThrottle(replayTransportSettings.timeoutMs),
      items: results,
    };

    if (replayedExchanges.length > 0) {
      setExchanges((current) => replayedExchanges.reduce((next, exchange) => mergeExchanges(exchange, next), current));
      setRepeaterResult(replayedExchanges[0]);
      setSelectedExchangeId(replayedExchanges[0].id);
    }
    setReplayBulkRuns((current) => [run, ...current].slice(0, 30));
    setReplayBulkQueue([]);
    setRepeaterStatus(run.message);
    appendAuditEvent({
      tool: 'repeater',
      action: 'Bulk replay',
      target: run.name,
      decision: run.status === 'completed' ? 'completed' : 'blocked',
      detail: run.message,
      requestCount: run.totalRequests,
      risk: run.status === 'completed' ? 'info' : 'medium',
    });
  }

  function normalizeRepeaterLibraryRequest(input: unknown, index: number): RepeaterSavedRequest | null {
    if (!input || typeof input !== 'object') return null;
    const candidate = input as Partial<RepeaterSavedRequest>;
    if (typeof candidate.rawRequest !== 'string') return null;
    const rawRequest = candidate.rawRequest.trimEnd();
    const explicitUrl = typeof candidate.targetUrl === 'string' ? candidate.targetUrl : '';
    const targetUrl = targetUrlFromRawRequest(rawRequest, explicitUrl);
    if (!targetUrl || !rawRequest) return null;
    const now = new Date().toISOString();
    const name = typeof candidate.name === 'string' && candidate.name.trim()
      ? candidate.name.trim()
      : repeaterNameFromRaw(rawRequest, `Imported request ${index + 1}`);
    const folder = typeof candidate.folder === 'string' && candidate.folder.trim()
      ? candidate.folder.trim()
      : repeaterGroupFromUrl(targetUrl, 'Imported');
    const tags = Array.isArray(candidate.tags)
      ? candidate.tags.filter((tag): tag is string => typeof tag === 'string' && Boolean(tag.trim())).slice(0, 8)
      : ['imported'];
    return {
      id: typeof candidate.id === 'string' && candidate.id.trim() ? `imported-${candidate.id.trim()}` : `imported-repeater-${Date.now()}-${index}-${Math.random().toString(16).slice(2)}`,
      name,
      folder,
      targetUrl,
      rawRequest,
      createdAt: typeof candidate.createdAt === 'string' ? candidate.createdAt : now,
      updatedAt: now,
      tags: Array.from(new Set(['imported', ...tags])).slice(0, 8),
    };
  }

  function repeaterRequestFromLegacyProxyXmlItem(item: Element, index: number): RepeaterSavedRequest | null {
    const requestRaw = decodeLegacyProxyXmlPayload(item.getElementsByTagName('request')[0]).trimEnd();
    if (!requestRaw) return null;
    const url = xmlTextContent(item, 'url');
    const comment = xmlTextContent(item, 'comment') || xmlTextContent(item, 'path');
    return normalizeRepeaterLibraryRequest({
      id: `legacy-proxy-xml-${index + 1}-${sanitizeImportId(repeaterNameFromRaw(requestRaw))}`,
      name: comment ? `${repeaterNameFromRaw(requestRaw)} · ${comment}` : repeaterNameFromRaw(requestRaw, `legacy proxy XML request ${index + 1}`),
      folder: `legacy proxy XML/${targetHostFromUrl(url) || rawHttpHeader(requestRaw, 'Host') || 'Imported'}`,
      targetUrl: url,
      rawRequest: requestRaw,
      tags: ['legacy-proxy-xml', `legacy-proxy-item:${index + 1}`],
    }, index);
  }

  function repeaterRequestsFromLegacyProxyXmlLibrary(text: string) {
    if (typeof DOMParser === 'undefined') return [];
    const doc = new DOMParser().parseFromString(text, 'application/xml');
    if (doc.getElementsByTagName('parsererror').length) return [];
    return Array.from(doc.getElementsByTagName('item'))
      .map((item, index) => repeaterRequestFromLegacyProxyXmlItem(item, index))
      .filter((request): request is RepeaterSavedRequest => Boolean(request));
  }

  function repeaterRequestFromHarEntry(entry: unknown, index: number): RepeaterSavedRequest | null {
    const imported = exchangeEntryFromHarEntry(entry, index);
    if (!imported || typeof imported !== 'object') return null;
    return normalizeRepeaterLibraryRequest({
      id: `har-${index + 1}-${sanitizeImportId(String((imported as { url?: unknown }).url ?? 'request'))}`,
      name: repeaterNameFromRaw(String((imported as { requestRaw?: unknown }).requestRaw ?? ''), `HAR request ${index + 1}`),
      folder: `HAR/${targetHostFromUrl(String((imported as { url?: unknown }).url ?? '')) || 'Imported'}`,
      targetUrl: String((imported as { url?: unknown }).url ?? ''),
      rawRequest: String((imported as { requestRaw?: unknown }).requestRaw ?? ''),
      tags: ['har', `har-entry:${index + 1}`],
    }, index);
  }

  function repeaterRawHttpArchiveChunks(text: string) {
    const normalized = text.replace(/\r\n/g, '\n').trim();
    if (!normalized) return [];
    const entries = plainLoggerArchiveEntries(normalized).map((entry) => entry.requestRaw);
    if (entries.length) return entries;
    return normalized
      .split(/\n(?=[A-Z]+\s+\S+\s+HTTP\/\d(?:\.\d)?)/g)
      .map((chunk) => {
        const responseOffset = chunk.search(/\nHTTP\/\d(?:\.\d)?\s+\d{3}/i);
        return (responseOffset === -1 ? chunk : chunk.slice(0, responseOffset)).trim();
      })
      .filter((chunk) => /^[A-Z]+\s+\S+\s+HTTP\/\d(?:\.\d)?/i.test(chunk));
  }

  function parseRepeaterLibraryRequests(text: string) {
    const trimmed = text.trim();
    if (!trimmed) throw new Error('Paste a ProxyForge library, HAR, legacy proxy XML, or raw HTTP request archive first');

    if (/^<\?xml|^<items|^<item/i.test(trimmed)) {
      const imported = repeaterRequestsFromLegacyProxyXmlLibrary(trimmed);
      if (!imported.length) throw new Error('No request items found in legacy proxy XML');
      return { requests: imported, sourceFormat: 'legacy proxy XML' };
    }

    if (/^[\[{]/.test(trimmed)) {
      const parsed = JSON.parse(trimmed) as {
        kind?: string;
        requests?: unknown[];
        entries?: unknown[];
        exchanges?: unknown[];
        log?: { entries?: unknown[] };
      } | unknown[];
      const rawRequests = Array.isArray(parsed)
        ? parsed
        : Array.isArray(parsed.requests)
          ? parsed.requests
          : Array.isArray(parsed.exchanges)
            ? parsed.exchanges
            : Array.isArray(parsed.entries)
              ? parsed.entries
              : undefined;
      if (Array.isArray((parsed as { log?: { entries?: unknown[] } }).log?.entries)) {
        const imported = (parsed as { log: { entries: unknown[] } }).log.entries
          .map((entry, index) => repeaterRequestFromHarEntry(entry, index))
          .filter((request): request is RepeaterSavedRequest => Boolean(request));
        if (!imported.length) throw new Error('No request items found in HAR');
        return { requests: imported, sourceFormat: 'HAR' };
      }
      if (!Array.isArray(rawRequests)) throw new Error('Library JSON must contain a requests, entries, or exchanges array');
      const imported = rawRequests
        .map((item, index) => normalizeRepeaterLibraryRequest(item, index))
        .filter((request): request is RepeaterSavedRequest => Boolean(request));
      if (!imported.length) throw new Error('No valid Repeater requests found');
      const sourceFormat = !Array.isArray(parsed) && parsed.kind === 'proxyforge-raw-http-archive'
        ? 'raw HTTP archive JSON'
        : !Array.isArray(parsed) && Array.isArray(parsed.exchanges)
          ? 'project exchanges'
          : 'ProxyForge library JSON';
      return { requests: imported, sourceFormat };
    }

    const imported = repeaterRawHttpArchiveChunks(trimmed)
      .map((rawRequest, index) => normalizeRepeaterLibraryRequest({
        id: `raw-http-${index + 1}-${sanitizeImportId(repeaterNameFromRaw(rawRequest))}`,
        name: repeaterNameFromRaw(rawRequest, `Raw HTTP request ${index + 1}`),
        folder: `Raw HTTP/${rawHttpHeader(rawRequest, 'Host') || 'Imported'}`,
        rawRequest,
        tags: ['raw-http', `raw-request:${index + 1}`],
      }, index))
      .filter((request): request is RepeaterSavedRequest => Boolean(request));
    if (!imported.length) throw new Error('No raw HTTP request lines found');
    return { requests: imported, sourceFormat: 'raw HTTP' };
  }

  function exportRepeaterLibrary() {
    const payload = {
      version: 1,
      kind: 'proxyforge-repeater-library',
      projectName,
      exportedAt: new Date().toISOString(),
      requestCount: savedRepeaterRequests.length,
      requests: savedRepeaterRequests,
    };
    setRepeaterLibraryText(JSON.stringify(payload, null, 2));
    setRepeaterLibraryStatus(`Exported ${savedRepeaterRequests.length} saved request${savedRepeaterRequests.length === 1 ? '' : 's'} to library JSON`);
    appendAuditEvent({
      tool: 'repeater',
      action: 'Export request library',
      target: projectName,
      decision: 'completed',
      detail: `Exported ${savedRepeaterRequests.length} saved Repeater request${savedRepeaterRequests.length === 1 ? '' : 's'}`,
      requestCount: 0,
      risk: 'info',
    });
  }

  function importRepeaterLibrary() {
    try {
      const { requests: imported, sourceFormat } = parseRepeaterLibraryRequests(repeaterLibraryText);

      setSavedRepeaterRequests((current) => {
        const next = [...imported];
        for (const existing of current) {
          if (!next.some((request) => request.targetUrl === existing.targetUrl && request.rawRequest === existing.rawRequest)) {
            next.push(existing);
          }
        }
        return next.slice(0, 200);
      });
      setSelectedSavedRepeaterRequestId(imported[0].id);
      setRepeaterLibraryStatus(`Imported ${imported.length} request${imported.length === 1 ? '' : 's'} from ${sourceFormat} into the Repeater library`);
      appendAuditEvent({
        tool: 'repeater',
        action: 'Import request library',
        target: imported[0].folder,
        decision: 'completed',
        detail: `Imported ${imported.length} saved Repeater request${imported.length === 1 ? '' : 's'} from ${sourceFormat}`,
        requestCount: 0,
        risk: 'info',
      });
    } catch (error) {
      const message = error instanceof Error ? error.message : 'Invalid library JSON';
      setRepeaterLibraryStatus(`Library import failed: ${message}`);
      appendAuditEvent({
        tool: 'repeater',
        action: 'Import request library',
        target: 'library JSON',
        decision: 'blocked',
        detail: message,
        requestCount: 0,
        risk: 'low',
      });
    }
  }

  function updateReplayTransportSettings(patch: Partial<ReplayTransportSettings>) {
    setReplayTransportSettings((current) => ({
      ...current,
      ...patch,
      maxRedirects: patch.maxRedirects === undefined ? current.maxRedirects : clampSafetyNumber(patch.maxRedirects, 0, 10, defaultReplayTransportSettings.maxRedirects),
      timeoutMs: patch.timeoutMs === undefined ? current.timeoutMs : clampSafetyNumber(patch.timeoutMs, 1000, 120000, defaultReplayTransportSettings.timeoutMs),
    }));
  }

  function pinRepeaterResponse() {
    setPinnedRepeaterExchangeIds((current) => [repeaterResult.id, ...current.filter((id) => id !== repeaterResult.id)].slice(0, 8));
    setRepeaterStatus(`Pinned response ${repeaterResult.status} ${repeaterResult.path}`);
  }

  function compareLatestReplay() {
    loadReplayResponseIntoComparer();
    setActiveTool('comparer');
  }

  function planDesyncProbe() {
    const targetUrl = repeaterTargetUrl.trim() || selectedRepeaterTab?.targetUrl || selectedExchange?.url || seedExchanges[0].url;
    if (blockIfOutOfPolicyScope('repeater', 'Desync probe planning', targetUrl, 3, setDesyncRaceStatus)) return;
    const raw = repeaterRaw.trim() || selectedRepeaterTab?.rawRequest || selectedExchange?.requestRaw || seedExchanges[0].requestRaw;
    const plan = buildDesyncProbePlan(raw, targetUrl, repeaterTabs);
    setDesyncProbePlans((current) => [plan, ...current.filter((item) => item.id !== plan.id)].slice(0, 40));
    setSelectedDesyncProbePlanId(plan.id);
    setDesyncEvidenceText(plan.content);
    setDesyncRaceStatus(`Planned scoped authorized CL.0 client-side desync and pause-based probe with ${plan.sendMode.replace(/-/g, ' ')} connection evidence.`);
    appendAuditEvent({
      tool: 'repeater',
      action: 'Plan desync probe',
      target: targetUrl,
      decision: 'completed',
      detail: plan.summary,
      requestCount: plan.requestCount,
      risk: 'medium',
    });
  }

  async function captureDesyncConnectionEvidence() {
    const plan = selectedDesyncProbePlan;
    if (!plan) {
      setDesyncRaceStatus('Plan desync probe before capturing connection evidence');
      return;
    }
    setDesyncRaceStatus('Capturing socket-backed single-connection desync evidence...');
    const runtime = await runRepeaterDesyncProbe({
      planId: plan.id,
      targetUrl: plan.targetUrl,
      requests: plan.requests,
      scopeAllowlist,
      timeoutMs: replayTransportSettings.timeoutMs,
      syncTechnique: 'single-connection',
    });
    const evidence = buildDesyncConnectionEvidence(plan, runtime);
    setDesyncConnectionEvidence((current) => [evidence, ...current.filter((item) => item.id !== evidence.id)].slice(0, 40));
    setSelectedDesyncConnectionEvidenceId(evidence.id);
    setDesyncEvidenceText(evidence.evidence);
    setDesyncRaceStatus(runtime.status === 'proof'
      ? `Captured socket-backed timing, jitter, and response order evidence with ${evidence.protocol} ${evidence.syncTechnique}.`
      : `Desync transport ${runtime.status}: ${runtime.summary}`);
    appendAuditEvent({
      tool: 'repeater',
      action: 'Capture connection evidence',
      target: plan.targetUrl,
      decision: runtime.status === 'proof' ? 'completed' : 'blocked',
      detail: evidence.summary,
      requestCount: plan.requestCount,
      risk: 'medium',
    });
  }

  async function runParallelRaceProbe() {
    const plan = selectedDesyncProbePlan;
    if (!plan) {
      setDesyncRaceStatus('Plan desync probe before running a parallel race');
      return;
    }
    const syncTechnique = selectedDesyncConnectionEvidence?.syncTechnique === 'single-packet' ? 'single-packet' : 'last-byte';
    setDesyncRaceStatus(`Running socket-backed ${syncTechnique} parallel race...`);
    const runtime = await runRepeaterParallelRace({
      planId: plan.id,
      targetUrl: plan.targetUrl,
      requests: plan.requests,
      scopeAllowlist,
      timeoutMs: replayTransportSettings.timeoutMs,
      syncTechnique,
      pauseMs: 25,
    });
    const raceRun = buildParallelRaceRun(plan, selectedDesyncConnectionEvidence, runtime);
    setParallelRaceRuns((current) => [raceRun, ...current.filter((item) => item.id !== raceRun.id)].slice(0, 40));
    setSelectedParallelRaceRunId(raceRun.id);
    setDesyncEvidenceText(raceRun.evidence);
    setDesyncRaceStatus(runtime.status === 'proof'
      ? `Parallel race run complete with ${raceRun.syncTechnique}; ${raceRun.raceWindowMs}ms window, ${raceRun.jitterMs}ms jitter, response order captured.`
      : `Parallel race transport ${runtime.status}: ${runtime.summary}`);
    appendAuditEvent({
      tool: 'repeater',
      action: 'Run parallel race',
      target: plan.targetUrl,
      decision: runtime.status === 'proof' ? 'completed' : 'blocked',
      detail: raceRun.summary,
      requestCount: raceRun.requestCount,
      risk: 'medium',
    });
  }

  function exportDesyncProofBundle(issueId?: string) {
    const plan = selectedDesyncProbePlan;
    if (!plan) {
      setDesyncRaceStatus('Plan desync probe before exporting a proof bundle');
      return undefined;
    }
    const bundle = buildDesyncProofBundle(plan, selectedDesyncConnectionEvidence, selectedParallelRaceRun, issueId);
    setDesyncProofBundles((current) => [bundle, ...current.filter((item) => item.id !== bundle.id)].slice(0, 40));
    setSelectedDesyncProofBundleId(bundle.id);
    setDesyncEvidenceText(bundle.content);
    setDesyncRaceStatus(`Exported report-ready proof bundle for request smuggling, desync, and parallel race evidence.`);
    appendAuditEvent({
      tool: 'repeater',
      action: 'Export proof bundle',
      target: plan.targetUrl,
      decision: 'completed',
      detail: bundle.summary,
      requestCount: plan.requestCount,
      risk: 'medium',
    });
    return bundle;
  }

  function promoteDesyncRaceEvidence() {
    const plan = selectedDesyncProbePlan;
    if (!plan) {
      setDesyncRaceStatus('Plan desync probe before promoting race evidence');
      return;
    }
    const issue: Issue = {
      id: `desync-race-${plan.id}`,
      title: 'Browser-powered desync and parallel race evidence',
      severity: 'high',
      host: plan.host,
      path: plan.path,
      confidence: selectedParallelRaceRun ? 'firm' : 'tentative',
      status: 'open',
      detail: [
        'Repeater desync workbench staged CL.0 request smuggling, client-side desync, and pause-based desync probes under authorized scope gates.',
        selectedDesyncConnectionEvidence?.summary ?? 'Connection-level evidence has not been captured yet.',
        selectedParallelRaceRun?.summary ?? 'Parallel race proof has not been run yet.',
        'Report evidence preserves grouped-send mode, single connection sequencing, last-byte or single-packet synchronization, timing jitter, response order, and proof bundle metadata.',
      ].join(' '),
      remediation: 'Normalize HTTP request parsing across front-end and back-end tiers, reject ambiguous Content-Length handling, avoid connection-state assumptions, and add server-side locking or idempotency for race-sensitive operations.',
      triageNote: 'Promoted from Repeater desync/race workbench with report-ready request smuggling and parallel race evidence.',
      lastTriagedAt: new Date().toISOString(),
    };
    const bundle = buildDesyncProofBundle(plan, selectedDesyncConnectionEvidence, selectedParallelRaceRun, issue.id);
    setImportedBundleIssues((current) => [issue, ...current.filter((item) => item.id !== issue.id)].slice(0, 200));
    setDesyncProofBundles((current) => [bundle, ...current.filter((item) => item.id !== bundle.id)].slice(0, 40));
    setSelectedDesyncProofBundleId(bundle.id);
    setDesyncEvidenceText(bundle.content);
    setSelectedIssueId(issue.id);
    setDesyncRaceStatus(`Promoted race evidence into Reports: ${issue.title}`);
    appendAuditEvent({
      tool: 'repeater',
      action: 'Promote race evidence',
      target: `${issue.host}${issue.path}`,
      decision: 'completed',
      detail: bundle.summary,
      requestCount: plan.requestCount,
      risk: issue.severity,
    });
  }

  async function runRepeaterBatch(group?: string) {
    const sourceTabs = group ? repeaterTabs.filter((tab) => tab.group === group) : repeaterTabs;
    const runnableTabs = sourceTabs
      .filter((tab) => tab.targetUrl.trim() && tab.rawRequest.trim())
      .slice(0, safetyMaxRequests());
    if (runnableTabs.length === 0) {
      setRepeaterStatus(group ? `No Repeater tabs in ${group} are ready for batch send` : 'No Repeater tabs are ready for batch send');
      return;
    }
    const allReady = sourceTabs.filter((tab) => tab.targetUrl.trim() && tab.rawRequest.trim()).length;
    const startedAt = new Date();
    const results: RepeaterBatchResult[] = [];
    const replayedExchanges: HttpExchange[] = [];
    setRepeaterStatus(`Batch sending ${runnableTabs.length} Repeater tab${runnableTabs.length === 1 ? '' : 's'}${group ? ` in ${group}` : ''}${allReady > runnableTabs.length ? `; capped by safety max ${safetyMaxRequests()}` : ''}`);

    for (const tab of runnableTabs) {
      const host = targetHostFromUrl(tab.targetUrl);
      if (effectiveSafetyPolicy.requireScopeMatch && !isHostInScope(host, effectiveScopeAllowlist)) {
        results.push({
          tabId: tab.id,
          tabName: tab.name,
          targetUrl: tab.targetUrl,
          status: 0,
          length: 0,
          timing: 0,
          risk: 'medium',
          notes: `Blocked by project scope: ${host || tab.targetUrl}`,
          blocked: true,
        });
        continue;
      }

      const replayed = await replayRequest({
        rawRequest: tab.rawRequest,
        targetUrl: tab.targetUrl,
        scopeAllowlist: effectiveScopeAllowlist,
        settings: replayTransportSettings,
        repeaterTabId: tab.id,
        repeaterTabName: tab.name,
        repeaterTabGroup: tab.group,
        sourceExchangeId: tab.sourceExchangeId,
        tags: ['batch-replay'],
        notes: `Batch replay ${tab.name}`,
      });
      const exchange = {
        ...replayed,
        id: `${replayed.id}-batch-${tab.id}`,
        notes: `Batch replay ${tab.name}: ${replayed.notes}`,
        tags: Array.from(new Set([...replayed.tags, 'repeater-batch', `tab:${tab.id}`])),
      };
      replayedExchanges.push(exchange);
      results.push({
        tabId: tab.id,
        tabName: tab.name,
        targetUrl: tab.targetUrl,
        status: exchange.status,
        length: exchange.length,
        timing: exchange.timing,
        risk: exchange.risk,
        notes: exchange.notes,
        blocked: exchange.status === 0,
        exchangeId: exchange.id,
      });
    }

    const blocked = results.some((result) => result.blocked);
    const completedAt = new Date();
    const run: RepeaterBatchRun = {
      id: `repeater-batch-${startedAt.getTime()}`,
      startedAt: startedAt.toISOString(),
      completedAt: completedAt.toISOString(),
      totalRequests: results.length,
      blocked,
      message: blocked
        ? `Batch send finished with ${results.filter((result) => result.blocked).length} blocked tab${results.filter((result) => result.blocked).length === 1 ? '' : 's'}`
        : `Batch send complete: ${results.length} tab${results.length === 1 ? '' : 's'} replayed${group ? ` in ${group}` : ''}`,
      results,
    };

    if (replayedExchanges.length > 0) {
      setExchanges((current) => replayedExchanges.reduce((next, exchange) => mergeExchanges(exchange, next), current));
      setRepeaterResult(replayedExchanges[0]);
      setSelectedExchangeId(replayedExchanges[0].id);
    }
    setRepeaterTabs((current) => current.map((tab) => {
      const result = results.find((item) => item.tabId === tab.id);
      if (!result) return tab;
      return {
        ...tab,
        lastStatus: result.status,
        lastReplayId: result.exchangeId ?? tab.lastReplayId,
        dirty: result.blocked ? tab.dirty : false,
        updatedAt: completedAt.toISOString(),
      };
    }));
    setRepeaterBatchRuns((current) => [run, ...current].slice(0, 30));
    setRepeaterStatus(run.message);
    appendAuditEvent({
      tool: 'repeater',
      action: group ? 'Group batch replay' : 'Batch replay',
      target: group ? `${group} Repeater group` : `${results.length} Repeater tabs`,
      decision: blocked ? 'blocked' : 'completed',
      detail: run.message,
      requestCount: run.totalRequests,
      risk: blocked ? 'medium' : highestFindingSeverity(results.map((result) => ({ severity: result.risk })), 'info'),
    });
  }

  async function runReplayMatrix() {
    if (!selectedExchange) return;
    if (blockIfOutOfPolicyScope('repeater', 'Replay matrix', repeaterTargetUrl, safetyMaxRequests(), setReplayMatrixStatus)) {
      updateScannerQueueItem('queue-authz-replay', {
        status: 'blocked',
        target: `${selectedExchange.host}${selectedExchange.path}`,
        detail: 'Replay matrix blocked by project scope policy.',
        priority: 'medium',
        requestCount: safetyMaxRequests(),
      }, true);
      return;
    }
    const allIdentities = parseLineList(replayMatrixRoles, 24);
    const identities = allIdentities.slice(0, safetyMaxRequests());
    if (identities.length === 0) {
      setReplayMatrixStatus('Add at least one identity to run a replay matrix');
      updateScannerQueueItem('queue-authz-replay', {
        status: 'blocked',
        target: `${selectedExchange.host}${selectedExchange.path}`,
        detail: 'Replay matrix needs at least one identity before authorization evidence can be queued.',
        priority: 'low',
        requestCount: 0,
      }, true);
      return;
    }

    const startedAt = new Date();
    const baseline = repeaterResult;
    const headerName = replayMatrixHeader.trim() || 'X-ProxyForge-Role';
    const matrixProfiles = [
      replayMatrixBaselineProfileId,
      ...replayMatrixComparisonProfileIds,
    ]
      .map((id) => sessionProfiles.find((profile) => profile.id === id))
      .filter((profile): profile is SessionProfile => Boolean(profile));
    const matrixProfileNames = Array.from(new Set(matrixProfiles.map((profile) => profile.name)));
    const results: ReplayMatrixResult[] = [];
    setReplayMatrixStatus(`Running ${identities.length} replay matrix request${identities.length === 1 ? '' : 's'}${allIdentities.length > identities.length ? `; capped by safety max ${safetyMaxRequests()}` : ''}`);
    updateScannerQueueItem('queue-authz-replay', {
      status: 'running',
      target: `${selectedExchange.host}${selectedExchange.path}`,
      detail: `Running ${identities.length} identity replay request${identities.length === 1 ? '' : 's'} with ${headerName}.`,
      priority: 'high',
      requestCount: identities.length,
    });
    if (allIdentities.length > identities.length) {
      appendAuditEvent({
        tool: 'repeater',
        action: 'Replay matrix capped',
        target: selectedExchange.host,
        decision: 'allowed',
        detail: `Replay matrix capped from ${allIdentities.length} to ${identities.length} requests by project safety policy`,
        requestCount: identities.length,
        risk: 'low',
      });
    }

    for (const [index, identity] of identities.entries()) {
      const matrixProfile = profileForReplayIdentity(identity, matrixProfiles);
      const rawRequest = matrixProfile
        ? applySessionProfileToRawRequest(upsertRawHeader(repeaterRaw, headerName, identity), matrixProfile)
        : upsertRawHeader(repeaterRaw, headerName, identity);
      const replayed = await replayRequest({
        rawRequest,
        targetUrl: repeaterTargetUrl,
        scopeAllowlist: effectiveScopeAllowlist,
        settings: replayTransportSettings,
        repeaterTabId: selectedRepeaterTab?.id,
        repeaterTabName: selectedRepeaterTab?.name,
        repeaterTabGroup: selectedRepeaterTab?.group,
        sourceExchangeId: selectedExchange.id,
        tags: ['replay-matrix'],
        notes: `Replay matrix identity ${identity}`,
      });
      const identitySlug = identity.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '') || `identity-${index + 1}`;
      const taggedReplay: HttpExchange = {
        ...replayed,
        id: `${replayed.id}-matrix-${index}-${identitySlug}`,
        notes: `Replay matrix ${identity}${matrixProfile ? ` via ${matrixProfile.name}` : ''}: ${replayed.notes}`,
        tags: Array.from(new Set([...replayed.tags, 'replay-matrix', `identity:${identity}`, matrixProfile ? `profile:${matrixProfile.id}` : 'profile:none'])),
      };
      if (matrixProfile) markSessionProfileUsed(matrixProfile.id);
      results.push(buildReplayMatrixResult(identity, headerName, baseline, taggedReplay));
    }

    const matrixBaseline = results[0]?.exchange ?? baseline;
    results.splice(
      0,
      results.length,
      ...results.map((result) => buildReplayMatrixResult(result.identity, result.headerName, matrixBaseline, result.exchange)),
    );
    const blocked = results.some((result) => result.status === 0);
    const completedAt = new Date();
    const run: ReplayMatrixRun = {
      id: `replay-matrix-${startedAt.getTime()}`,
      targetUrl: repeaterTargetUrl,
      headerName,
      startedAt: startedAt.toISOString(),
      completedAt: completedAt.toISOString(),
      baselineStatus: matrixBaseline.status,
      baselineLength: matrixBaseline.length,
      totalRequests: results.length,
      blocked,
      message: blocked
        ? `Replay matrix completed with ${results.filter((result) => result.status === 0).length} blocked request${results.filter((result) => result.status === 0).length === 1 ? '' : 's'}`
        : `Replay matrix complete: ${results.length} ${results.length === 1 ? 'identity' : 'identities'} replayed${matrixProfileNames.length ? ` with ${matrixProfileNames.join(', ')}` : ''}`,
      results,
    };
    setReplayMatrixRuns((current) => [run, ...current].slice(0, 50));
    setExchanges((current) => results.reduce((next, result) => mergeExchanges(result.exchange, next), current));
    setRepeaterResult(results[0].exchange);
    setRepeaterRaw(results[0].exchange.requestRaw);
    setSelectedExchangeId(results[0].exchange.id);
    updateActiveRepeaterTab({
      rawRequest: results[0].exchange.requestRaw,
      targetUrl: results[0].exchange.url,
      name: repeaterNameFromRaw(results[0].exchange.requestRaw, selectedRepeaterTab?.name),
      lastStatus: results[0].exchange.status,
      lastReplayId: results[0].exchange.id,
      dirty: false,
    });
    setReplayMatrixStatus(run.message);
    setRepeaterStatus(`Matrix replay complete against ${selectedExchange.host}`);
    updateScannerQueueItem('queue-authz-replay', {
      status: blocked ? 'blocked' : 'complete',
      target: `${selectedExchange.host}${selectedExchange.path}`,
      detail: run.message,
      priority: blocked ? 'medium' : highestFindingSeverity(results.map((result) => ({ severity: result.risk })), 'info'),
      requestCount: run.totalRequests,
    }, true);
    appendAuditEvent({
      tool: 'repeater',
      action: 'Replay matrix',
      target: `${selectedExchange.method} ${selectedExchange.host}${selectedExchange.path}`,
      decision: blocked ? 'blocked' : 'completed',
      detail: run.message,
      requestCount: run.totalRequests,
      risk: blocked ? 'medium' : 'info',
    });
  }

  function saveReplayAuthorizationMatrix() {
    const run = latestReplayMatrixRun;
    if (!run || !run.results.length) {
      setReplayMatrixStatus('Run a replay matrix before saving authorization evidence');
      return;
    }
    const now = new Date().toISOString();
    const methodPath = repeaterNameFromRaw(run.results[0]?.exchange.requestRaw ?? repeaterRaw, repeaterNameFromRaw(repeaterRaw));
    const routeId = `replay-route-${Date.now()}`;
    const matrixProfiles = [
      replayMatrixBaselineProfileId,
      ...replayMatrixComparisonProfileIds,
    ]
      .map((id) => sessionProfiles.find((profile) => profile.id === id))
      .filter((profile): profile is SessionProfile => Boolean(profile));
    const identities = run.results.map((result, index) => {
      const profile = profileForReplayIdentity(result.identity, matrixProfiles);
      return {
        id: `replay-identity-${index}-${result.identity.toLowerCase().replace(/[^a-z0-9]+/g, '-')}`,
        name: profile?.name ?? result.identity,
        role: result.identity,
        sessionProfileId: profile?.id,
        sessionProfileInjectionId: replaySessionProfileInjections.find((injection) => injection.sessionProfileId === profile?.id)?.id,
        notes: profile ? `${profile.name} profile compared as ${result.identity}` : `Header identity ${result.identity}`,
      };
    });
    const route = {
      id: routeId,
      name: methodPath,
      method: methodPath.split(/\s+/)[0] ?? 'GET',
      targetUrl: run.targetUrl,
      rawRequest: repeaterRaw,
      baselineExchangeId: repeaterResult.id,
      notes: `Saved from replay matrix ${run.id}`,
    };
    const cells = run.results.map((result, index) => {
      const outcome = result.status === 0
        ? 'blocked'
        : result.status >= 400
          ? 'denied'
          : result.delta === 'same status/length/risk'
            ? 'same'
            : 'allowed';
      return {
        id: `replay-cell-${Date.now()}-${index}`,
        identityId: identities[index].id,
        routeId,
        expectation: index === 0 ? 'same-as-baseline' : 'changed-from-baseline',
        outcome,
        lastRunAt: run.completedAt,
        exchangeId: result.exchange.id,
        statusCode: result.status,
        length: result.length,
        timing: result.timing,
        risk: result.risk,
        notes: result.delta,
      } satisfies ReplayAuthorizationMatrix['cells'][number];
    });
    const matrix: ReplayAuthorizationMatrix = {
      id: `replay-authz-matrix-${Date.now()}`,
      name: `${methodPath} authorization matrix`,
      description: `${run.totalRequests} identity replay comparison saved from Repeater.`,
      createdAt: now,
      updatedAt: now,
      targetUrl: run.targetUrl,
      identities,
      routes: [route],
      cells,
      lastBulkRunId: replayBulkRuns[0]?.id,
      notes: run.message,
    };
    setReplayAuthorizationMatrices((current) => [matrix, ...current].slice(0, 30));
    setSelectedReplayAuthorizationMatrixId(matrix.id);
    setReplayMatrixStatus(`Saved authorization matrix for ${methodPath}`);
  }

  function exportReplayAuthorizationMatrix() {
    const matrix = selectedReplayAuthorizationMatrix ?? replayAuthorizationMatrices[0];
    if (!matrix) {
      setReplayMatrixStatus('Save an authorization matrix before export');
      return;
    }
    setReplayAuthorizationMatrixText(JSON.stringify({
      kind: 'proxyforge-replay-authorization-matrix',
      version: 1,
      projectName,
      exportedAt: new Date().toISOString(),
      matrix,
    }, null, 2));
    setReplayMatrixStatus(`Exported authorization matrix ${matrix.name}`);
  }

  function loadSelectedIntoIntruder() {
    if (!selectedExchange) return;
    setIntruderRaw(makeIntruderTemplate(selectedExchange));
    setIntruderTargetUrl(selectedExchange.url);
    setIntruderStatus(`Loaded ${selectedExchange.method} ${selectedExchange.path}`);
  }

  function saveIntruderAttackConfig() {
    const now = new Date().toISOString();
    const name = `${intruderAttackModeLabels[intruderAttackMode]} ${repeaterNameFromRaw(intruderRaw)}`;
    const existing = savedIntruderAttacks.find((attack) => attack.targetUrl === intruderTargetUrl && attack.rawRequest === intruderRaw && attack.attackMode === intruderAttackMode);
    const saved: IntruderSavedAttack = {
      id: existing?.id ?? `intruder-attack-${Date.now()}-${Math.random().toString(16).slice(2)}`,
      name,
      targetUrl: intruderTargetUrl,
      rawRequest: intruderRaw,
      attackMode: intruderAttackMode,
      payloads: intruderPayloads,
      payloadSetTwo: intruderPayloadSetTwo,
      payloadProcessors: intruderProcessors,
      payloadRules: intruderPayloadRules,
      grepTerms: intruderGrepTerms,
      extractRegexes: intruderExtractRegexes,
      throttleMs: intruderThrottleMs,
      createdAt: existing?.createdAt ?? now,
      updatedAt: now,
    };
    setSavedIntruderAttacks((current) => [saved, ...current.filter((attack) => attack.id !== saved.id)].slice(0, 50));
    setSelectedSavedIntruderAttackId(saved.id);
    setIntruderStatus(`Saved attack ${saved.name}`);
    appendAuditEvent({
      tool: 'intruder',
      action: 'Save attack',
      target: saved.targetUrl,
      decision: 'completed',
      detail: `Saved Intruder attack ${saved.name}`,
      requestCount: 0,
      risk: 'info',
    });
  }

  function loadIntruderAttackConfig(attack: IntruderSavedAttack) {
    setSelectedSavedIntruderAttackId(attack.id);
    setIntruderTargetUrl(attack.targetUrl);
    setIntruderRaw(attack.rawRequest);
    setIntruderAttackMode(attack.attackMode);
    setIntruderPayloads(attack.payloads);
    setIntruderPayloadSetTwo(attack.payloadSetTwo);
    setIntruderProcessors(attack.payloadProcessors);
    setIntruderPayloadRules(attack.payloadRules ?? []);
    setIntruderGrepTerms(attack.grepTerms);
    setIntruderExtractRegexes(attack.extractRegexes);
    setIntruderThrottleMs(attack.throttleMs);
    setIntruderStatus(`Loaded attack ${attack.name}`);
  }

  function normalizeIntruderSavedAttack(input: unknown, index: number): IntruderSavedAttack | null {
    if (!input || typeof input !== 'object') return null;
    const candidate = input as Partial<IntruderSavedAttack>;
    if (typeof candidate.rawRequest !== 'string' || !candidate.rawRequest.trim()) return null;
    const rawRequest = candidate.rawRequest.trimEnd();
    const explicitUrl = typeof candidate.targetUrl === 'string' ? candidate.targetUrl : '';
    const targetUrl = targetUrlFromRawRequest(rawRequest.replace(/§/g, ''), explicitUrl);
    if (!targetUrl) return null;
    const now = new Date().toISOString();
    const attackMode = (Object.keys(intruderAttackModeLabels) as IntruderAttackMode[]).includes(candidate.attackMode as IntruderAttackMode)
      ? candidate.attackMode as IntruderAttackMode
      : 'sniper';
    const payloadProcessors = Array.isArray(candidate.payloadProcessors)
      ? candidate.payloadProcessors.filter((processor): processor is IntruderPayloadProcessor => (
        (Object.keys(intruderProcessorLabels) as IntruderPayloadProcessor[]).includes(processor as IntruderPayloadProcessor)
      ))
      : [];
    const payloadRules = Array.isArray(candidate.payloadRules)
      ? candidate.payloadRules.filter((rule): rule is IntruderPayloadRuleId => (
        (Object.keys(intruderPayloadRuleLabels) as IntruderPayloadRuleId[]).includes(rule as IntruderPayloadRuleId)
      ))
      : [];
    return {
      id: typeof candidate.id === 'string' && candidate.id.trim() ? `imported-${sanitizeImportId(candidate.id)}` : `imported-intruder-${Date.now()}-${index}-${Math.random().toString(16).slice(2)}`,
      name: typeof candidate.name === 'string' && candidate.name.trim()
        ? candidate.name.trim().slice(0, 100)
        : `${intruderAttackModeLabels[attackMode]} ${repeaterNameFromRaw(rawRequest.replace(/§/g, ''), `Imported attack ${index + 1}`)}`,
      targetUrl,
      rawRequest,
      attackMode,
      payloads: typeof candidate.payloads === 'string' && candidate.payloads.trim() ? candidate.payloads.trim() : intruderPayloads,
      payloadSetTwo: typeof candidate.payloadSetTwo === 'string' ? candidate.payloadSetTwo.trim() : '',
      payloadProcessors,
      payloadRules,
      grepTerms: typeof candidate.grepTerms === 'string' ? candidate.grepTerms.trim() : intruderGrepTerms,
      extractRegexes: typeof candidate.extractRegexes === 'string' ? candidate.extractRegexes.trim() : intruderExtractRegexes,
      throttleMs: clampSafetyNumber(Number(candidate.throttleMs ?? intruderThrottleMs), 0, 5000, intruderThrottleMs),
      createdAt: typeof candidate.createdAt === 'string' ? candidate.createdAt : now,
      updatedAt: now,
    };
  }

  function normalizeIntruderPayloadGenerator(input: unknown, index: number): IntruderPayloadGenerator | null {
    if (!input || typeof input !== 'object') return null;
    const candidate = input as Partial<IntruderPayloadGenerator>;
    const payloads = Array.isArray(candidate.payloads)
      ? candidate.payloads.filter((payload): payload is string => typeof payload === 'string' && Boolean(payload.trim())).slice(0, intruderPayloadInputLimit)
      : [];
    if (!payloads.length) return null;
    const kind = candidate.kind === 'wordlist'
      || candidate.kind === 'number-range'
      || candidate.kind === 'role-matrix'
      || candidate.kind === 'case-mutation'
      || candidate.kind === 'date-range'
      || candidate.kind === 'bruteforce'
      || candidate.kind === 'injection-probes'
      ? candidate.kind
      : 'wordlist';
    return {
      id: typeof candidate.id === 'string' && candidate.id.trim() ? `imported-${sanitizeImportId(candidate.id)}` : `imported-generator-${Date.now()}-${index}-${Math.random().toString(16).slice(2)}`,
      name: typeof candidate.name === 'string' && candidate.name.trim() ? candidate.name.trim().slice(0, 80) : `Imported generator ${index + 1}`,
      kind,
      description: typeof candidate.description === 'string' && candidate.description.trim()
        ? candidate.description.trim().slice(0, 240)
        : 'Imported Intruder payload generator.',
      payloads,
      updatedAt: new Date().toISOString(),
    };
  }

  function exportIntruderAttackLibrary() {
    const payload = {
      version: 1,
      kind: 'proxyforge-intruder-attack-library',
      projectName,
      exportedAt: new Date().toISOString(),
      attackCount: savedIntruderAttacks.length,
      generatorCount: intruderPayloadGenerators.length,
      attacks: savedIntruderAttacks,
      payloadGenerators: intruderPayloadGenerators,
      secretHandling: 'execution-full-fidelity-secrets-preserved',
      reportRedactionBoundary: 'redact-only-during-report-export',
    };
    setIntruderAttackLibraryText(JSON.stringify(payload, null, 2));
    const message = `Exported ${payload.attackCount} saved attack${payload.attackCount === 1 ? '' : 's'} and ${payload.generatorCount} payload generator${payload.generatorCount === 1 ? '' : 's'}`;
    setIntruderAttackLibraryStatus(message);
    setIntruderStatus(message);
    appendAuditEvent({
      tool: 'intruder',
      action: 'Export attack library',
      target: projectName,
      decision: 'completed',
      detail: `${message}; executor request material preserved full fidelity`,
      requestCount: 0,
      risk: 'info',
    });
  }

  function importIntruderAttackLibrary() {
    try {
      const parsed = JSON.parse(intruderAttackLibraryText) as {
        kind?: unknown;
        attacks?: unknown[];
        savedIntruderAttacks?: unknown[];
        payloadGenerators?: unknown[];
        intruderPayloadGenerators?: unknown[];
      } | unknown[];
      const rawAttacks = Array.isArray(parsed)
        ? parsed
        : Array.isArray(parsed.attacks)
          ? parsed.attacks
          : Array.isArray(parsed.savedIntruderAttacks)
            ? parsed.savedIntruderAttacks
            : [];
      const rawGenerators = Array.isArray(parsed) ? [] : (
        Array.isArray(parsed.payloadGenerators)
          ? parsed.payloadGenerators
          : Array.isArray(parsed.intruderPayloadGenerators)
            ? parsed.intruderPayloadGenerators
            : []
      );
      const importedAttacks = rawAttacks
        .map((item, index) => normalizeIntruderSavedAttack(item, index))
        .filter((attack): attack is IntruderSavedAttack => Boolean(attack));
      const importedGenerators = rawGenerators
        .map((item, index) => normalizeIntruderPayloadGenerator(item, index))
        .filter((generator): generator is IntruderPayloadGenerator => Boolean(generator));
      if (!importedAttacks.length && !importedGenerators.length) throw new Error('No valid Intruder attacks or payload generators found');

      if (importedAttacks.length) {
        setSavedIntruderAttacks((current) => {
          const next = [...importedAttacks];
          for (const existing of current) {
            if (!next.some((attack) => attack.targetUrl === existing.targetUrl && attack.rawRequest === existing.rawRequest && attack.attackMode === existing.attackMode)) {
              next.push(existing);
            }
          }
          return next.slice(0, 100);
        });
        setSelectedSavedIntruderAttackId(importedAttacks[0].id);
      }
      if (importedGenerators.length) {
        setIntruderPayloadGenerators((current) => {
          const next = [...importedGenerators];
          for (const existing of current) {
            if (!next.some((generator) => generator.name === existing.name && generator.payloads.join('\n') === existing.payloads.join('\n'))) {
              next.push(existing);
            }
          }
          return next.slice(0, 60);
        });
        setSelectedIntruderGeneratorId(importedGenerators[0].id);
      }
      const sourceFormat = Array.isArray(parsed)
        ? 'attack array'
        : parsed.kind === 'proxyforge-intruder-attack-library'
          ? 'ProxyForge Intruder library'
          : 'project snapshot';
      const message = `Imported ${importedAttacks.length} attack${importedAttacks.length === 1 ? '' : 's'} and ${importedGenerators.length} generator${importedGenerators.length === 1 ? '' : 's'} from ${sourceFormat}`;
      setIntruderAttackLibraryStatus(message);
      setIntruderStatus(message);
      appendAuditEvent({
        tool: 'intruder',
        action: 'Import attack library',
        target: sourceFormat,
        decision: 'completed',
        detail: `${message}; raw requests and payload lists preserved full fidelity`,
        requestCount: 0,
        risk: 'info',
      });
    } catch (error) {
      const message = error instanceof Error ? error.message : 'Invalid Intruder attack library JSON';
      setIntruderAttackLibraryStatus(`Import failed: ${message}`);
      setIntruderStatus(`Attack library import failed: ${message}`);
      appendAuditEvent({
        tool: 'intruder',
        action: 'Import attack library',
        target: 'library JSON',
        decision: 'blocked',
        detail: message,
        requestCount: 0,
        risk: 'low',
      });
    }
  }

  function applyIntruderGenerator(targetSet: 'primary' | 'secondary') {
    if (!selectedIntruderGenerator) return;
    const payloadText = selectedIntruderGenerator.payloads.join('\n');
    if (targetSet === 'primary') setIntruderPayloads(payloadText);
    else setIntruderPayloadSetTwo(payloadText);
    setIntruderStatus(`Applied ${selectedIntruderGenerator.name} to ${targetSet === 'primary' ? 'set 1' : 'set 2'}`);
  }

  function savePayloadGeneratorFromSet() {
    const payloads = parseLineList(intruderPayloads, intruderPayloadInputLimit);
    if (payloads.length === 0) {
      setIntruderStatus('Add payloads to set 1 before saving a generator');
      return;
    }
    const generator: IntruderPayloadGenerator = {
      id: `gen-custom-${Date.now()}-${Math.random().toString(16).slice(2)}`,
      name: `Custom set ${intruderPayloadGenerators.length + 1}`,
      kind: 'wordlist',
      description: `${payloads.length} payloads saved from Intruder set 1.`,
      payloads,
      updatedAt: new Date().toISOString(),
    };
    setIntruderPayloadGenerators((current) => [generator, ...current].slice(0, 30));
    setSelectedIntruderGeneratorId(generator.id);
    setIntruderStatus(`Saved payload generator ${generator.name}`);
  }

  function updateIntruderQueueItem(id: string, patch: Partial<Omit<IntruderAttackQueueItem, 'id' | 'createdAt'>>) {
    setIntruderAttackQueue((current) => current.map((item) => (
      item.id === id ? { ...item, ...patch, updatedAt: new Date().toISOString() } : item
    )));
  }

  function applyIntruderGrepExtractPreset(presetId: string) {
    const preset = intruderGrepExtractPresets.find((item) => item.id === presetId);
    if (!preset) return;
    const nextGrepTerms = Array.from(new Set([...parseLineList(intruderGrepTerms, 50), ...preset.grepTerms])).slice(0, 50);
    const nextExtractRegexes = Array.from(new Set([...parseLineList(intruderExtractRegexes, 12), ...preset.extractRegexes])).slice(0, 12);
    setIntruderGrepTerms(nextGrepTerms.join('\n'));
    setIntruderExtractRegexes(nextExtractRegexes.join('\n'));
    setIntruderStatus(`Applied ${preset.label} grep/extract library`);
  }

  function toggleIntruderPayloadRule(rule: IntruderPayloadRuleId) {
    setIntruderPayloadRules((current) => (
      current.includes(rule)
        ? current.filter((item) => item !== rule)
        : [...current, rule]
    ));
  }

  function pauseLatestIntruderCheckpoint() {
    const latest = intruderAttackQueue[0];
    if (!latest) {
      setIntruderStatus('No Intruder queue item is available to pause');
      return;
    }
    const checkpointOffset = Math.max(latest.checkpointOffset ?? latest.completedRequests, 0);
    updateIntruderQueueItem(latest.id, {
      status: 'paused',
      checkpointOffset,
      message: `Paused at checkpoint offset ${checkpointOffset}`,
    });
    setIntruderCheckpointOffset(checkpointOffset);
    setIntruderStatus(`Paused ${latest.attackName} at checkpoint offset ${checkpointOffset}`);
  }

  async function resumeIntruderCheckpoint() {
    await runIntruder({ checkpoint: true, startOffset: intruderCheckpointOffset });
  }

  async function runIntruderCheckpoint() {
    setIntruderCheckpointOffset(0);
    await runIntruder({ checkpoint: true, startOffset: 0 });
  }

  async function runIntruder(options: { checkpoint?: boolean; startOffset?: number } = {}) {
    if (!selectedExchange) return;
    const payloads = parseLineList(intruderPayloads, intruderPayloadInputLimit);
    const payloadSetTwo = parseLineList(intruderPayloadSetTwo, intruderPayloadInputLimit);
    const expandedPayloads = expandIntruderPayloadsForRules(payloads, intruderPayloadRules);
    const expandedPayloadSetTwo = expandIntruderPayloadsForRules(payloadSetTwo, intruderPayloadRules);
    const payloadSets = payloadSetTwo.length > 0 ? [payloads, payloadSetTwo] : [payloads];
    const expandedPayloadSets = expandedPayloadSetTwo.length > 0 ? [expandedPayloads, expandedPayloadSetTwo] : [expandedPayloads];
    const grepTerms = parseLineList(intruderGrepTerms, 50);
    const extractRegexes = parseLineList(intruderExtractRegexes, 12);
    const estimatedRequests = estimateIntruderRequestCount(intruderRaw, intruderAttackMode, expandedPayloadSets);
    const maxRequests = safetyMaxRequests();
    const startOffset = Math.max(options.startOffset ?? 0, 0);
    const checkpointLimit = options.checkpoint ? Math.min(Math.max(intruderCheckpointSize, 1), maxRequests) : undefined;
    const requestsThisRun = checkpointLimit ?? estimatedRequests;
    const queueId = `intruder-queue-${Date.now()}-${Math.random().toString(16).slice(2)}`;
    const attackName = `${intruderAttackModeLabels[intruderAttackMode]} ${repeaterNameFromRaw(intruderRaw)}`;
    const queuedAt = new Date().toISOString();
    const queueItem: IntruderAttackQueueItem = {
      id: queueId,
      attackName,
      targetUrl: intruderTargetUrl,
      attackMode: intruderAttackMode,
      status: 'queued',
      totalRequests: estimatedRequests,
      completedRequests: startOffset,
      message: options.checkpoint
        ? `Queued checkpoint slice from offset ${startOffset} (${requestsThisRun} request${requestsThisRun === 1 ? '' : 's'})`
        : `Queued ${estimatedRequests} request${estimatedRequests === 1 ? '' : 's'}`,
      createdAt: queuedAt,
      updatedAt: queuedAt,
      checkpointOffset: startOffset,
      resourcePoolName: `Pool ${intruderResourcePoolSize}`,
      payloadRules: intruderPayloadRules,
    };

    if (blockIfOutOfPolicyScope('intruder', 'Intruder attack', intruderTargetUrl, requestsThisRun, setIntruderStatus)) {
      setIntruderAttackQueue((current) => [{ ...queueItem, status: 'blocked' as IntruderAttackQueueItem['status'], message: 'Blocked by project scope policy', updatedAt: new Date().toISOString() }, ...current].slice(0, 30));
      return;
    }
    if (!options.checkpoint && estimatedRequests > maxRequests) {
      const message = `Safety policy blocked Intruder: estimated ${estimatedRequests} requests exceeds max ${maxRequests}`;
      setIntruderStatus(message);
      setIntruderAttackQueue((current) => [{ ...queueItem, status: 'blocked' as IntruderAttackQueueItem['status'], message, updatedAt: new Date().toISOString() }, ...current].slice(0, 30));
      appendAuditEvent({
        tool: 'intruder',
        action: 'Intruder attack',
        target: intruderTargetUrl,
        decision: 'blocked',
        detail: message,
        requestCount: estimatedRequests,
        risk: 'medium',
      });
      return;
    }

    const throttleMs = effectiveThrottle(intruderThrottleMs);
    setIntruderStatus(options.checkpoint
      ? `Running checkpoint slice from offset ${startOffset} with ${requestsThisRun} request${requestsThisRun === 1 ? '' : 's'}`
      : `Running ${intruderAttackModeLabels[intruderAttackMode]} with ${estimatedRequests} scoped request${estimatedRequests === 1 ? '' : 's'}`);
    setIntruderAttackQueue((current) => [{ ...queueItem, status: 'running' as IntruderAttackQueueItem['status'], message: `Running with ${throttleMs}ms throttle through Pool ${intruderResourcePoolSize}`, updatedAt: new Date().toISOString() }, ...current].slice(0, 30));
    const summary = await runIntruderAttack({
      rawRequest: intruderRaw,
      targetUrl: intruderTargetUrl,
      payloads,
      payloadSets,
      attackMode: intruderAttackMode,
      payloadProcessors: intruderProcessors,
      payloadRules: intruderPayloadRules,
      scopeAllowlist: effectiveScopeAllowlist,
      throttleMs,
      grepTerms,
      extractRegexes,
      startOffset,
      maxPayloadRequests: checkpointLimit,
      resourcePoolName: `Pool ${intruderResourcePoolSize}`,
      resourcePoolMaxConcurrent: intruderResourcePoolSize,
      streamChunkSize: Math.min(checkpointLimit ?? intruderDefaultStreamChunkSize, Math.max(requestsThisRun, 1)),
      resultWindowSize: Math.min(Math.max(requestsThisRun, 1), intruderDefaultResultWindowSize),
      memoryBudgetBytes: intruderDefaultMemoryBudgetBytes,
    });
    setIntruderSummary(summary);
    const nextComparisons = buildIntruderResultComparisons(summary);
    const nextPositionDiffs = buildIntruderPayloadPositionDiffs(summary);
    const nextClusterAnalysis = buildIntruderClusterAnalysis(summary, savedIntruderAttacks);
    setIntruderComparisons(nextComparisons);
    setIntruderPositionDiffs(nextPositionDiffs);
    setIntruderResultClusters(nextClusterAnalysis.clusters);
    setIntruderStatRankings(nextClusterAnalysis.rankings);
    setIntruderStatus(summary.message);
    setIntruderCheckpointOffset(summary.hasMore ? summary.nextOffset ?? 0 : 0);
    updateIntruderQueueItem(queueId, {
      status: summary.blocked ? 'blocked' : summary.hasMore ? 'paused' : 'complete',
      completedRequests: summary.nextOffset ?? summary.results.length,
      totalRequests: summary.payloadPlanCount ?? estimatedRequests,
      message: summary.message,
      latestSummaryId: summary.id,
      checkpointOffset: summary.nextOffset,
      resourcePoolName: summary.resourcePoolName,
      payloadRules: intruderPayloadRules,
    });

    if (!summary.blocked && summary.results.length > 0) {
      const intruderExchanges = summary.results.map((result) => exchangeFromIntruderResult(result, summary.targetUrl));
      setExchanges((current) => intruderExchanges.reduce((next, exchange) => mergeExchanges(exchange, next), current));
      setSelectedExchangeId(intruderExchanges[0].id);
    }
    appendAuditEvent({
      tool: 'intruder',
      action: 'Intruder attack',
      target: intruderTargetUrl,
      decision: summary.blocked ? 'blocked' : 'completed',
      detail: `${summary.message}; throttle ${throttleMs}ms`,
      requestCount: summary.totalRequests || requestsThisRun,
      risk: summary.blocked ? 'medium' : 'info',
    });
  }

  function compareIntruderResult(comparison = intruderComparisons[0]) {
    if (!intruderSummary || !comparison) {
      setIntruderStatus('Run Intruder before comparing result anomalies');
      return;
    }
    const baseline = intruderSummary.results.find((result) => result.id === comparison.baselineResultId);
    const candidate = intruderSummary.results.find((result) => result.id === comparison.candidateResultId);
    if (!baseline || !candidate) {
      setIntruderStatus('Comparison result is no longer available in the latest Intruder run');
      return;
    }
    setComparerLeft(formatIntruderCompareSide(`Baseline ${comparison.baselinePayload}`, baseline));
    setComparerRight(formatIntruderCompareSide(`Candidate ${comparison.candidatePayload}`, candidate));
    setComparerStatus(`Loaded Intruder comparison ${comparison.candidatePayload} against ${comparison.baselinePayload}`);
    setActiveTool('comparer');
  }

  function promoteIntruderComparison(comparison = intruderComparisons[0]) {
    if (!intruderSummary || !comparison) {
      setIntruderStatus('Run Intruder before promoting a result');
      return;
    }
    const candidate = intruderSummary.results.find((result) => result.id === comparison.candidateResultId);
    if (!candidate) {
      setIntruderStatus('Promotion target is no longer available in the latest Intruder run');
      return;
    }
    promoteIntruderResult(candidate, comparison);
  }

  function promoteIntruderResult(result: IntruderAttackResult, comparison?: IntruderResultComparison) {
    if (!intruderSummary) return;
    const issue = buildPromotedIntruderIssue(intruderSummary, result, comparison);
    setIntruderPromotedIssues((current) => [issue, ...current.filter((item) => item.id !== issue.id)].slice(0, 100));
    setSelectedIssueId(issue.id);
    setActiveTool('scanner');
    setIntruderStatus(`Promoted ${result.payload} into Scanner findings`);
    appendAuditEvent({
      tool: 'intruder',
      action: 'Promote finding',
      target: `${issue.host}${issue.path}`,
      decision: 'completed',
      detail: `${issue.title}; ${comparison?.notes ?? result.notes}`,
      requestCount: 1,
      risk: issue.severity,
    });
  }

  function analyzeIntruderClusters() {
    if (!intruderSummary) {
      setIntruderStatus('Run Intruder before clustering result sets');
      return;
    }
    const analysis = buildIntruderClusterAnalysis(intruderSummary, savedIntruderAttacks);
    setIntruderResultClusters(analysis.clusters);
    setIntruderStatRankings(analysis.rankings);
    setIntruderStatus(`Clustered ${intruderSummary.results.length} Intruder result${intruderSummary.results.length === 1 ? '' : 's'} into ${analysis.clusters.length} group${analysis.clusters.length === 1 ? '' : 's'}; top outlier score ${analysis.rankings[0]?.score.toFixed(2) ?? '0.00'}`);
    appendAuditEvent({
      tool: 'intruder',
      action: 'Analyze result clusters',
      target: intruderSummary.targetUrl,
      decision: 'completed',
      detail: `${analysis.clusters.length} cluster(s), ${analysis.rankings.length} ranked result(s), top payload ${analysis.rankings[0]?.payload ?? 'none'}`,
      requestCount: intruderSummary.results.length,
      risk: analysis.rankings[0]?.verdict === 'regression' ? 'medium' : 'info',
    });
  }

  function toggleIntruderProcessor(processor: IntruderPayloadProcessor) {
    setIntruderProcessors((current) => (
      current.includes(processor)
        ? current.filter((item) => item !== processor)
        : [...current, processor]
    ));
  }

  async function runTargetCrawler() {
    if (blockIfOutOfPolicyScope('target', 'Target crawl', crawlStartUrl, Math.min(crawlMaxPages, safetyMaxRequests()), setCrawlStatus)) return;
    const maxPages = Math.min(crawlMaxPages, safetyMaxRequests());
    const throttleMs = effectiveThrottle(crawlThrottleMs);
    const sessionHeaders = sessionHeadersFromProfile(selectedSessionProfile);
    const sessionLabel = selectedSessionProfile ? ` with ${selectedSessionProfile.name}` : '';
    setCrawlStatus(`Crawling ${crawlStartUrl}${sessionLabel}`);
    markSessionProfileUsed(selectedSessionProfile?.id);
    const summary = await runCrawl({
      startUrl: crawlStartUrl,
      scopeAllowlist: effectiveScopeAllowlist,
      maxDepth: crawlMaxDepth,
      maxPages,
      throttleMs,
      userAgent: 'ProxyForge Crawler',
      includeForms: crawlIncludeForms,
      headers: sessionHeaders,
    });
    setCrawlSummary(summary);
    setCrawlStatus(selectedSessionProfile ? `${summary.message} · ${selectedSessionProfile.name}` : summary.message);
    setSelectedCrawlRouteId(summary.routes[0]?.id ?? null);

    if (!summary.blocked && summary.exchanges.length > 0) {
      setExchanges((current) => summary.exchanges.reduce((next, exchange) => mergeExchanges(exchange, next), current));
      setSelectedExchangeId(summary.exchanges[0].id);
    }
    appendAuditEvent({
      tool: 'target',
      action: 'Target crawl',
      target: crawlStartUrl,
      decision: summary.blocked ? 'blocked' : 'completed',
      detail: `${summary.message}; max pages ${maxPages}; throttle ${throttleMs}ms${selectedSessionProfile ? `; session ${selectedSessionProfile.name}` : ''}`,
      requestCount: summary.totalRequests,
      risk: summary.blocked ? 'medium' : 'info',
    });
  }

  function importTargetSiteMapArchive() {
    try {
      const imported = parseLoggerRawHttpArchive(targetSiteMapImportText);
      const summary = buildTargetImportSummary(imported);
      if (!summary.routes.length) throw new Error('No target routes found in archive');
      setCrawlSummary(summary);
      setCrawlStartUrl(summary.startUrl);
      setSelectedCrawlRouteId(summary.routes[0]?.id ?? null);
      setExchanges((current) => summary.exchanges.reduce((next, exchange) => mergeExchanges(exchange, next), current));
      setSelectedExchangeId(summary.exchanges[0]?.id ?? selectedExchangeId);
      setTargetSiteMapSourceFilter('import');
      setTargetSiteMapView('url');
      setTargetSiteMapImportStatus(summary.message);
      setTargetSiteMapWorkflowStatus(summary.message);
      appendAuditEvent({
        tool: 'target',
        action: 'Import Target site map archive',
        target: summary.startUrl,
        decision: 'completed',
        detail: `${summary.message}; raw requests, headers, cookies, API keys, and response bodies preserved full fidelity`,
        requestCount: summary.totalRequests,
        risk: summary.insertionPoints.some((point) => point.type === 'header' || point.type === 'cookie' || point.type === 'body') ? 'medium' : 'info',
      });
    } catch (error) {
      const message = error instanceof Error ? error.message : 'Target site-map import failed';
      setTargetSiteMapImportStatus(`Import failed: ${message}`);
      setTargetSiteMapWorkflowStatus(`Target import failed: ${message}`);
      appendAuditEvent({
        tool: 'target',
        action: 'Import Target site map archive',
        target: 'archive',
        decision: 'blocked',
        detail: message,
        requestCount: 0,
        risk: 'low',
      });
    }
  }

  function buildTargetSiteMapRequest(routeSet = targetRoutes) {
    return {
      crawl: crawlSummary,
      routes: routeSet,
      insertionPoints: targetInsertionPoints,
      issues,
      scopeAllowlist: effectiveScopeAllowlist,
      filters: {
        url: targetSiteMapUrlFilter,
        source: targetSiteMapSourceFilter,
        status: targetSiteMapStatusFilter,
      },
      accessControlProfiles: sessionProfiles.map((profile) => profile.role || profile.name),
      throttleMs: effectiveThrottle(crawlThrottleMs),
    };
  }

  function applyTargetSiteMapFilters() {
    const viewModel = buildTargetSiteMapViewModel(buildTargetSiteMapRequest());
    setTargetSiteMapWorkflowStatus(`Applied Target filters: ${viewModel.filteredRouteCount}/${viewModel.routeCount} route(s) visible in ${targetSiteMapView === 'url' ? 'URL view' : 'Crawl-path view'}`);
    appendAuditEvent({
      tool: 'target',
      action: 'Apply Target filters',
      target: targetSiteMapUrlFilter || targetSiteMapSourceFilter || 'Target site map',
      decision: 'completed',
      detail: `${viewModel.filteredRouteCount}/${viewModel.routeCount} route(s) matched; source ${targetSiteMapSourceFilter}; status ${targetSiteMapStatusFilter}`,
      requestCount: 0,
      risk: 'info',
    });
  }

  function handOffTargetContentDiscovery() {
    const handoff = buildTargetContentDiscoveryHandoff(buildTargetSiteMapRequest());
    setTargetContentDiscoveryHandoffs((current) => [handoff, ...current.filter((item) => item.id !== handoff.id)].slice(0, 40));
    setTargetSiteMapWorkflowStatus(handoff.summary);
    appendAuditEvent({
      tool: 'target',
      action: 'Content discovery handoff',
      target: handoff.scopeSummary,
      decision: 'completed',
      detail: handoff.summary,
      requestCount: handoff.candidateCount,
      risk: handoff.candidates.some((candidate) => severityRank[candidate.priority] >= severityRank.high) ? 'high' : 'info',
    });
  }

  function runTargetAnalyzer() {
    const analysisPackage = buildTargetAnalyzerInventory(buildTargetSiteMapRequest());
    setTargetSiteMapAnalysisPackages((current) => [analysisPackage, ...current.filter((item) => item.id !== analysisPackage.id)].slice(0, 40));
    setSelectedTargetSiteMapAnalysisPackageId(analysisPackage.id);
    setTargetContentDiscoveryHandoffs((current) => [analysisPackage.contentDiscoveryHandoff, ...current.filter((item) => item.id !== analysisPackage.contentDiscoveryHandoff.id)].slice(0, 40));
    setTargetAccessControlReviewLanes(analysisPackage.accessControlReview);
    setTargetSiteMapPackageText(analysisPackage.content);
    setTargetSiteMapWorkflowStatus(analysisPackage.summary);
    appendAuditEvent({
      tool: 'target',
      action: 'Run target analyzer',
      target: `${analysisPackage.hostCount} host(s)`,
      decision: 'completed',
      detail: analysisPackage.summary,
      requestCount: analysisPackage.routeCount,
      risk: analysisPackage.accessControlReview.some((lane) => severityRank[lane.severity] >= severityRank.high) ? 'high' : 'info',
    });
  }

  function buildTargetAccessControlMatrix() {
    const lanes = buildTargetAccessControlReview(buildTargetSiteMapRequest());
    setTargetAccessControlReviewLanes(lanes);
    setTargetSiteMapWorkflowStatus(`Access-control matrix review ready for ${lanes.map((lane) => lane.role).join(', ')}`);
    appendAuditEvent({
      tool: 'target',
      action: 'Build access-control review',
      target: lanes.map((lane) => lane.role).join(', '),
      decision: 'completed',
      detail: `${lanes.length} access-control lane(s) prepared for authorization matrix review`,
      requestCount: lanes.reduce((total, lane) => total + lane.riskyRoutes.length, 0),
      risk: lanes.some((lane) => severityRank[lane.severity] >= severityRank.high) ? 'high' : 'info',
    });
  }

  function saveTargetSiteMapComparison() {
    const baselineRoutes = targetRoutes.filter((route) => route.source === 'seed' || route.depth === 0);
    const comparisonPackage = buildTargetSiteMapComparisonPackage({
      ...buildTargetSiteMapRequest(),
      baseline: {
        name: 'Target baseline',
        routes: baselineRoutes.length ? baselineRoutes : targetRoutes.slice(0, 2),
      },
      candidate: {
        name: 'Target candidate',
        routes: targetRoutes,
      },
    });
    setTargetSiteMapComparisonPackages((current) => [comparisonPackage, ...current.filter((item) => item.id !== comparisonPackage.id)].slice(0, 40));
    setSelectedTargetSiteMapComparisonPackageId(comparisonPackage.id);
    setTargetSiteMapPackageText(comparisonPackage.content);
    setTargetSiteMapWorkflowStatus(comparisonPackage.summary);
    appendAuditEvent({
      tool: 'target',
      action: 'Save site-map comparison',
      target: comparisonPackage.digestPreview,
      decision: 'completed',
      detail: comparisonPackage.summary,
      requestCount: comparisonPackage.deltas.length,
      risk: comparisonPackage.deltas.some((delta) => severityRank[delta.severity] >= severityRank.high) ? 'high' : 'info',
    });
  }

  function attachTargetSiteMapEvidenceToReport() {
    const analysisPackage = selectedTargetSiteMapAnalysisPackage ?? buildTargetAnalyzerInventory(buildTargetSiteMapRequest());
    const comparisonPackage = selectedTargetSiteMapComparisonPackage ?? buildTargetSiteMapComparisonPackage({
      ...buildTargetSiteMapRequest(),
      baseline: {
        name: 'Target baseline',
        routes: targetRoutes.filter((route) => route.source === 'seed' || route.depth === 0),
      },
      candidate: {
        name: 'Target candidate',
        routes: targetRoutes,
      },
    });
    const representativeRoute = targetRoutes.find((route) => route.path.includes('/api/refunds')) ?? targetRoutes[0] ?? targetFallbackRoutes[0];
    const issue: Issue = {
      id: `target-site-map-evidence-${Date.now()}`,
      title: 'Target site-map discovery coverage requires review',
      severity: 'info',
      host: representativeRoute?.host ?? 'example.test',
      path: representativeRoute?.path ?? '/target-site-map',
      confidence: 'firm',
      status: 'triaged',
      detail: 'Target site-map evidence was attached for URL tree, crawl-path, content discovery, technology inventory, parameter inventory, access-control review, and saved comparison-package coverage.',
      remediation: 'Review the Target site-map evidence package, replay role-sensitive routes, and keep comparison deltas attached to the report appendix.',
      triageNote: 'Target Site Map Evidence attached from advanced Target workflow.',
      lastTriagedAt: new Date().toISOString(),
    };
    const attachment = buildTargetSiteMapReportAttachment({
      ...buildTargetSiteMapRequest(),
      analysisPackage,
      comparisonPackage,
      issueId: issue.id,
    });

    setTargetSiteMapAnalysisPackages((current) => [analysisPackage, ...current.filter((item) => item.id !== analysisPackage.id)].slice(0, 40));
    setSelectedTargetSiteMapAnalysisPackageId(analysisPackage.id);
    setTargetSiteMapComparisonPackages((current) => [comparisonPackage, ...current.filter((item) => item.id !== comparisonPackage.id)].slice(0, 40));
    setSelectedTargetSiteMapComparisonPackageId(comparisonPackage.id);
    setTargetSiteMapEvidenceAttachments((current) => [attachment, ...current.filter((item) => item.id !== attachment.id)].slice(0, 40));
    setSelectedTargetSiteMapEvidenceAttachmentId(attachment.id);
    setImportedBundleIssues((current) => [issue, ...current.filter((item) => item.id !== issue.id)].slice(0, 100));
    setSelectedIssueId(issue.id);
    setTargetSiteMapPackageText(attachment.content);
    setReportArtifact(null);
    setTargetSiteMapWorkflowStatus(`Target site-map evidence attached to report: ${attachment.fileName}`);
    appendAuditEvent({
      tool: 'target',
      action: 'Attach Target site-map evidence',
      target: attachment.fileName,
      decision: 'completed',
      detail: attachment.summary,
      requestCount: analysisPackage.routeCount,
      risk: 'info',
    });
  }

  function resolveBrowserClientRoute(): CrawlRoute {
    const route = targetRoutes.find((item) => item.id === selectedCrawlRouteId) ?? targetRoutes[0] ?? crawlSummary?.routes[0];
    if (route) return route;
    const exchange = selectedExchange ?? seedExchanges[0];
    return {
      id: `client-route-${exchange.id}`,
      method: exchange.method,
      url: crawlStartUrl || exchange.url,
      host: safeUrlParts(crawlStartUrl || exchange.url).host,
      path: safeUrlParts(crawlStartUrl || exchange.url).path,
      status: exchange.status,
      mime: exchange.mime,
      depth: 0,
      source: 'seed',
      title: exchange.path,
      discoveredAt: '',
      insertionPoints: [],
    };
  }

  function runBrowserClientAnalysis() {
    const route = resolveBrowserClientRoute();
    if (blockIfOutOfPolicyScope('target', 'Browser client analysis', route.url, 4, setBrowserClientAnalysisStatus)) return;
    const exchange = exchanges.find((item) => item.url === route.url) ?? selectedExchange ?? seedExchanges[0];
    const analysis = buildBrowserClientAnalysis(route, exchange);
    setBrowserClientAnalyses((current) => [analysis, ...current.filter((item) => item.id !== analysis.id)].slice(0, 40));
    setSelectedBrowserClientAnalysisId(analysis.id);
    setBrowserClientAnalysisText(analysis.content);
    setBrowserClientAnalysisStatus(`Browser client analysis complete: ${analysis.summary}`);
    appendAuditEvent({
      tool: 'target',
      action: 'Browser client analysis',
      target: route.url,
      decision: 'completed',
      detail: analysis.summary,
      requestCount: analysis.instrumentation.length,
      risk: analysis.findings[0]?.severity ?? 'info',
    });
  }

  function replayBrowserWebMessage() {
    if (!selectedBrowserClientAnalysis) {
      setBrowserClientAnalysisStatus('Run client analysis before replaying web messages');
      return;
    }
    const replay = buildBrowserWebMessageReplay(selectedBrowserClientAnalysis);
    setBrowserWebMessageReplays((current) => [replay, ...current.filter((item) => item.id !== replay.id)].slice(0, 40));
    setSelectedBrowserWebMessageReplayId(replay.id);
    setBrowserClientAnalysisStatus(`Web message replay complete: ${replay.summary}`);
    appendAuditEvent({
      tool: 'target',
      action: 'Replay web message',
      target: selectedBrowserClientAnalysis.url,
      decision: 'completed',
      detail: replay.summary,
      requestCount: 1,
      risk: 'medium',
    });
  }

  function scanPrototypeGadgets() {
    if (!selectedBrowserClientAnalysis) {
      setBrowserClientAnalysisStatus('Run client analysis before scanning prototype gadgets');
      return;
    }
    const scan = buildBrowserPrototypeGadgetScan(selectedBrowserClientAnalysis);
    setBrowserPrototypeScans((current) => [scan, ...current.filter((item) => item.id !== scan.id)].slice(0, 40));
    setSelectedBrowserPrototypeScanId(scan.id);
    setBrowserClientAnalysisStatus(`Prototype pollution gadget scan complete: ${scan.summary}`);
    appendAuditEvent({
      tool: 'target',
      action: 'Scan prototype gadgets',
      target: selectedBrowserClientAnalysis.url,
      decision: 'completed',
      detail: scan.summary,
      requestCount: 1,
      risk: 'medium',
    });
  }

  function promoteBrowserClientEvidence() {
    if (!selectedBrowserClientAnalysis) {
      setBrowserClientAnalysisStatus('Run client analysis before promoting DOM evidence');
      return;
    }
    const finding = selectedBrowserClientAnalysis.findings[0];
    const issue: Issue = {
      id: `client-dom-${selectedBrowserClientAnalysis.id}`,
      title: finding?.title ?? 'Client-side browser DOM evidence needs review',
      severity: finding?.severity ?? 'medium',
      host: selectedBrowserClientAnalysis.host,
      path: selectedBrowserClientAnalysis.path,
      confidence: finding?.confidence ?? 'firm',
      status: 'open',
      detail: [
        `${finding?.summary ?? selectedBrowserClientAnalysis.summary}`,
        `Browser instrumentation covered fetch, XHR, WebSocket, and storage events for ${selectedBrowserClientAnalysis.url}.`,
        `Web message replay: ${selectedBrowserWebMessageReplay?.summary ?? 'not replayed yet'}.`,
        `Prototype pollution: ${selectedBrowserPrototypeScan?.summary ?? 'prototype gadget scan not run yet'}.`,
      ].join(' '),
      remediation: 'Validate client-side source/sink flows in the browser, avoid unsafe DOM sinks, validate postMessage origins, sanitize gadget-controlled properties, and prefer safe rendering APIs.',
      triageNote: 'Promoted from browser-powered client-side analysis with report-ready DOM evidence.',
      lastTriagedAt: new Date().toISOString(),
    };
    const evidencePackage = buildBrowserClientEvidencePackage(
      selectedBrowserClientAnalysis,
      selectedBrowserWebMessageReplay,
      selectedBrowserPrototypeScan,
      issue.id,
    );
    setImportedBundleIssues((current) => [issue, ...current.filter((item) => item.id !== issue.id)].slice(0, 200));
    setBrowserClientEvidencePackages((current) => [evidencePackage, ...current.filter((item) => item.id !== evidencePackage.id)].slice(0, 40));
    setSelectedBrowserClientEvidencePackageId(evidencePackage.id);
    setBrowserClientAnalyses((current) => current.map((item) => (
      item.id === selectedBrowserClientAnalysis.id ? { ...item, status: 'promoted' } : item
    )));
    setSelectedIssueId(issue.id);
    setBrowserClientAnalysisStatus(`Promoted DOM browser evidence into report-ready finding ${issue.title}`);
    appendAuditEvent({
      tool: 'target',
      action: 'Promote DOM evidence',
      target: `${issue.host}${issue.path}`,
      decision: 'completed',
      detail: evidencePackage.summary,
      requestCount: selectedBrowserClientAnalysis.instrumentation.length,
      risk: issue.severity,
    });
  }

  function toggleActiveScanCheck(check: ActiveScanCheckId) {
    setActiveScanChecks((current) => (
      current.includes(check)
        ? current.filter((item) => item !== check)
        : [...current, check]
    ));
  }

  function applyScannerCheckPack(packId: ScannerCheckPackId) {
    const pack = scannerCheckPacks.find((item) => item.id === packId) ?? scannerCheckPacks[0];
    setSelectedScannerCheckPackId(pack.id);
    setActiveScanChecks([...pack.checks]);
    setActiveScanMaxRequests((current) => Math.max(current, pack.checks.length));
    setActiveScanSummary(null);
    setActiveScanStatus(`${pack.label} loaded: ${pack.checks.length} checks selected`);
    updateScannerQueueItem('queue-active-scan', {
      status: 'queued',
      detail: `${pack.label} staged. ${pack.detail}`,
      requestCount: pack.checks.length,
      priority: pack.id === 'auth-state' || pack.id === 'full-active' ? 'high' : 'medium',
    });
  }

  async function runActiveScanner() {
    if (!selectedExchange) return;
    if (blockIfOutOfPolicyScope('scanner', 'Active scan', selectedExchange.url, Math.min(activeScanChecks.length, safetyMaxRequests()), setActiveScanStatus)) {
      updateScannerQueueItem('queue-active-scan', {
        status: 'blocked',
        target: `${selectedExchange.host}${selectedExchange.path}`,
        detail: 'Active scan blocked by project scope policy.',
        priority: 'medium',
        requestCount: Math.min(activeScanChecks.length, safetyMaxRequests()),
      }, true);
      return;
    }
    const maxRequests = Math.min(activeScanMaxRequests, safetyMaxRequests());
    const throttleMs = effectiveThrottle(activeScanThrottleMs);
    const rawRequest = applySessionProfileToRawRequest(selectedExchange.requestRaw, selectedSessionProfile);
    const sessionDetail = selectedSessionProfile ? ` using ${selectedSessionProfile.name}` : '';
    const oastPayload = activeScanChecks.includes('oast-ssrf') ? selectedCallbackPayload : undefined;
    const oastDetail = oastPayload ? ` with OAST payload ${oastPayload.token}` : '';
    setActiveScanStatus(`Running ${activeScanChecks.length} active scanner check${activeScanChecks.length === 1 ? '' : 's'}${sessionDetail}${oastDetail}`);
    markSessionProfileUsed(selectedSessionProfile?.id);
    updateScannerQueueItem('queue-active-scan', {
      status: 'running',
      target: `${selectedExchange.host}${selectedExchange.path}`,
      detail: `Running ${activeScanChecks.length} selected scanner check${activeScanChecks.length === 1 ? '' : 's'} with ${throttleMs}ms throttle${sessionDetail}${oastDetail}.`,
      priority: 'medium',
      requestCount: maxRequests,
    });
    const summary = await runActiveScan({
      rawRequest,
      targetUrl: selectedExchange.url,
      scopeAllowlist: effectiveScopeAllowlist,
      checks: activeScanChecks,
      throttleMs,
      maxRequests,
      oastPayloadUrl: oastPayload?.endpoint,
      oastPayloadToken: oastPayload?.token,
      oastPayloadId: oastPayload?.id,
    });
    setActiveScanSummary(summary);
    setActiveScanStatus(selectedSessionProfile ? `${summary.message} · using ${selectedSessionProfile.name}` : summary.message);
    updateScannerQueueItem('queue-active-scan', {
      status: summary.blocked ? 'blocked' : 'complete',
      target: `${selectedExchange.host}${selectedExchange.path}`,
      detail: summary.message,
      priority: highestFindingSeverity(summary.findings, summary.blocked ? 'medium' : 'info'),
      requestCount: summary.totalRequests,
    }, true);

    if (!summary.blocked && summary.exchanges.length > 0) {
      setExchanges((current) => summary.exchanges.reduce((next, exchange) => mergeExchanges(exchange, next), current));
      setSelectedExchangeId(summary.exchanges[0].id);
    }
    appendAuditEvent({
      tool: 'scanner',
      action: 'Active scan',
      target: `${selectedExchange.method} ${selectedExchange.host}${selectedExchange.path}`,
      decision: summary.blocked ? 'blocked' : 'completed',
      detail: `${summary.message}; max requests ${maxRequests}; throttle ${throttleMs}ms${selectedSessionProfile ? `; session ${selectedSessionProfile.name}` : ''}`,
      requestCount: summary.totalRequests,
      risk: summary.blocked ? 'medium' : 'info',
    });
  }

  async function runCrawlerAudit() {
    if (!crawlSummary?.insertionPoints.length) {
      setActiveScanStatus('Run the Target crawler before auditing insertion points');
      updateScannerQueueItem('queue-crawl-audit', {
        status: 'blocked',
        target: 'Target map insertion points',
        detail: 'Run the Target crawler before auditing insertion points.',
        priority: 'low',
        requestCount: 0,
      }, true);
      return;
    }

    const maxInsertionPoints = Math.min(activeScanMaxRequests, safetyMaxRequests());
    const throttleMs = effectiveThrottle(activeScanThrottleMs);
    const sessionHeaders = sessionHeadersFromProfile(selectedSessionProfile);
    const sessionDetail = selectedSessionProfile ? ` using ${selectedSessionProfile.name}` : '';
    setActiveScanStatus(`Auditing ${Math.min(crawlSummary.insertionPoints.length, maxInsertionPoints)} crawler insertion point${crawlSummary.insertionPoints.length === 1 ? '' : 's'}${sessionDetail}`);
    markSessionProfileUsed(selectedSessionProfile?.id);
    updateScannerQueueItem('queue-crawl-audit', {
      status: 'running',
      target: crawlSummary.startUrl,
      detail: `Auditing ${Math.min(crawlSummary.insertionPoints.length, maxInsertionPoints)} crawler insertion point${crawlSummary.insertionPoints.length === 1 ? '' : 's'}${sessionDetail}.`,
      priority: 'medium',
      requestCount: maxInsertionPoints,
    });
    const summary = await runCrawlAudit({
      scopeAllowlist: effectiveScopeAllowlist,
      checks: activeScanChecks,
      insertionPoints: crawlSummary.insertionPoints,
      sessionHeaders,
      throttleMs,
      maxInsertionPoints,
    });
    setActiveScanSummary(summary);
    setActiveScanStatus(selectedSessionProfile ? `${summary.message} · using ${selectedSessionProfile.name}` : summary.message);
    updateScannerQueueItem('queue-crawl-audit', {
      status: summary.blocked ? 'blocked' : 'complete',
      target: crawlSummary.startUrl,
      detail: summary.message,
      priority: highestFindingSeverity(summary.findings, summary.blocked ? 'medium' : 'info'),
      requestCount: summary.totalRequests,
    }, true);

    if (!summary.blocked && summary.exchanges.length > 0) {
      setExchanges((current) => summary.exchanges.reduce((next, exchange) => mergeExchanges(exchange, next), current));
      setSelectedExchangeId(summary.exchanges[0].id);
    }
    appendAuditEvent({
      tool: 'scanner',
      action: 'Crawl insertion audit',
      target: crawlSummary.startUrl,
      decision: summary.blocked ? 'blocked' : 'completed',
      detail: `${summary.message}; max insertion points ${maxInsertionPoints}; throttle ${throttleMs}ms${selectedSessionProfile ? `; session ${selectedSessionProfile.name}` : ''}`,
      requestCount: summary.totalRequests,
      risk: summary.blocked ? 'medium' : 'info',
    });
  }

  async function generateRootCertificate() {
    setCertActionStatus('Generating root CA');
    const status = await ensureRootCertificate();
    setCertStatus(status);
    setCertActionStatus(status.message);
    appendAuditEvent({
      tool: 'settings',
      action: 'Generate root CA',
      target: status.rootCertificatePath,
      decision: status.ready ? 'completed' : 'blocked',
      detail: status.message,
      requestCount: 0,
      risk: status.ready ? 'info' : 'low',
    });
  }

  async function copyRootCertificate() {
    setCertActionStatus('Preparing root CA export');
    const exported = await exportRootCertificate();
    if (exported.pem && navigator.clipboard) {
      await navigator.clipboard.writeText(exported.pem);
      setCertActionStatus(`Copied root CA PEM. Stored at ${exported.path}`);
      appendAuditEvent({
        tool: 'settings',
        action: 'Copy root CA PEM',
        target: exported.path,
        decision: 'completed',
        detail: `Copied root CA PEM from ${exported.path}`,
        requestCount: 0,
        risk: 'info',
      });
      return;
    }
    setCertActionStatus(exported.path ? `Root CA stored at ${exported.path}` : 'Root CA export unavailable in browser preview');
    appendAuditEvent({
      tool: 'settings',
      action: 'Copy root CA PEM',
      target: exported.path || 'browser preview',
      decision: exported.path ? 'completed' : 'blocked',
      detail: exported.path ? `Root CA stored at ${exported.path}` : 'Root CA export unavailable in browser preview',
      requestCount: 0,
      risk: 'low',
    });
  }

  async function rotateRootCertificateForProject() {
    setCertActionStatus('Rotating project root CA');
    const status = await rotateRootCertificate();
    setCertStatus(status);
    setCertActionStatus(status.message);
    appendAuditEvent({
      tool: 'settings',
      action: 'Rotate root CA',
      target: status.projectCertificateDir,
      decision: status.ready ? 'completed' : 'blocked',
      detail: status.message,
      requestCount: 0,
      risk: 'medium',
    });
  }

  async function revokeRootCertificateForProject() {
    setCertActionStatus('Revoking project root CA locally');
    const status = await revokeRootCertificate();
    setCertStatus(status);
    setCertActionStatus(status.message);
    appendAuditEvent({
      tool: 'settings',
      action: 'Revoke root CA',
      target: status.projectCertificateDir,
      decision: status.revokedAt ? 'completed' : 'blocked',
      detail: status.message,
      requestCount: 0,
      risk: 'medium',
    });
  }

  async function toggleHttpsInspection() {
    const next = await setHttpsInspection(!httpsStatus.enabled);
    setHttpsStatus(next);
    appendAuditEvent({
      tool: 'settings',
      action: 'HTTPS inspection',
      target: 'CONNECT MITM',
      decision: 'updated',
      detail: next.message,
      requestCount: 0,
      risk: next.enabled ? 'low' : 'info',
    });
  }

  async function updateUpstreamTlsMode(mode: HttpsInspectionStatus['upstreamTlsMode']) {
    const next = await setUpstreamTlsValidation(mode);
    setHttpsStatus(next);
    appendAuditEvent({
      tool: 'settings',
      action: 'Upstream TLS validation',
      target: 'HTTPS upstreams',
      decision: 'updated',
      detail: next.message,
      requestCount: 0,
      risk: mode === 'strict' ? 'info' : 'medium',
    });
  }

  function toggleReportSection(section: ReportSection) {
    setReportArtifact(null);
    setReportSections((current) => (
      current.includes(section)
        ? current.filter((item) => item !== section)
        : [...current, section]
    ));
  }

  async function exportCurrentReport(formatOverride?: ReportFormat) {
    const effectiveFormat = formatOverride ?? reportFormat;
    setReportStatus(`Exporting ${reportFormatLabels[effectiveFormat]} report`);
    try {
      const artifact = await exportReport({
        projectName,
        scopeAllowlist,
        issues: reportCuration.issues,
        exchanges: reportCuration.exchanges,
        format: effectiveFormat,
        sections: reportSections,
        templateId: reportTemplateId,
        brandName: reportBrandName,
        preparedFor: reportPreparedFor,
        engagementId: reportEngagementId,
        customTemplateName: reportCustomTemplateName,
        customTemplateBody: reportCustomTemplateBody,
        signEvidenceBundle: reportSignEvidenceBundle,
        signerName: reportSignerName,
        signingKeyId: reportSigningKeyId,
        signingSecret: reportSigningSecret,
        loggerImportJobs: reportLoggerImportJobs,
        comparerDiffPackages,
        comparerEvidenceAttachments,
        targetSiteMapEvidenceAttachments,
        proxyHistoryEvidenceAttachments,
        scannerActiveScanEvidencePackages,
        governanceAttestation: reportGovernanceAttestation,
      });
      setReportArtifact(artifact);
      setReportStatus(`Exported ${artifact.fileName}`);
      if (artifact.format === 'bundle') {
        setReportVerificationText(artifact.content);
        setReportVerificationResult({
          status: 'idle',
          message: 'Bundle exported. Verify it with the shared signing secret.',
        });
      }
    } catch (error) {
      setReportStatus(error instanceof Error ? `Report export failed: ${error.message}` : 'Report export failed');
    }
  }

  function buildCurrentFullReportPackage(signatureStatus: ReportFullPackage['signature']['status'] = 'signed'): ReportFullPackage {
    const generatedAt = new Date().toISOString();
    const title = `${projectName} full report package`;
    const unsignedContent = buildFullReportPackageContent(
      projectName,
      reportBrandName,
      reportPreparedFor,
      reportEngagementId,
      reportCuration.issues,
      reportCuration.exchanges,
      reportAffectedAssets,
      reportEvidenceManifest,
      reportReadinessChecks,
      reportGovernanceAttestation,
      scannerEvidenceDeltas,
      scannerActiveScanEvidencePackages,
      callbackSignedPollBatches,
      callbackCorrelationReplays,
      callbackReplayExecutionBatches,
      callbackLifecycleReviews,
      callbackCiHandoffPackages,
      callbackPublicRelaySoakPackages,
      reportPreview,
      reportSignerName.trim() || reportBrandName,
      reportSigningKeyId.trim() || 'report-local',
      'ready-on-export',
      'pending',
    );
    const digestPreview = getSimpleDigestPreview(unsignedContent);
    const content = buildFullReportPackageContent(
      projectName,
      reportBrandName,
      reportPreparedFor,
      reportEngagementId,
      reportCuration.issues,
      reportCuration.exchanges,
      reportAffectedAssets,
      reportEvidenceManifest,
      reportReadinessChecks,
      reportGovernanceAttestation,
      scannerEvidenceDeltas,
      scannerActiveScanEvidencePackages,
      callbackSignedPollBatches,
      callbackCorrelationReplays,
      callbackReplayExecutionBatches,
      callbackLifecycleReviews,
      callbackCiHandoffPackages,
      callbackPublicRelaySoakPackages,
      reportPreview,
      reportSignerName.trim() || reportBrandName,
      reportSigningKeyId.trim() || 'report-local',
      signatureStatus,
      digestPreview,
    );
    const stamp = Date.now();
    return {
      id: `report-package-${stamp}-${Math.random().toString(16).slice(2)}`,
      title,
      fileName: `proxyforge-full-report-package-${stamp}.json`,
      path: `reports/proxyforge-full-report-package-${stamp}.json`,
      generatedAt,
      reportReady: reportReadinessChecks.every((check) => check.status !== 'blocked'),
      issueCount: reportCuration.issues.length,
      evidenceCount: reportCuration.exchanges.length,
      affectedAssets: reportAffectedAssets,
      evidenceManifest: reportEvidenceManifest,
      callbackArtifactManifest: buildReportCallbackArtifactManifest(
        callbackSignedPollBatches,
        callbackCorrelationReplays,
        callbackReplayExecutionBatches,
        callbackLifecycleReviews,
        callbackCiHandoffPackages,
        callbackPublicRelaySoakPackages,
      ),
      readiness: reportReadinessChecks,
      governanceAttestation: reportGovernanceAttestation,
      signature: {
        algorithm: 'HMAC-SHA256',
        signerName: reportSignerName.trim() || reportBrandName,
        keyId: reportSigningKeyId.trim() || 'report-local',
        status: signatureStatus,
        digestPreview,
      },
      content,
    };
  }

  function buildReportPackage() {
    const reportPackage = buildCurrentFullReportPackage('ready-on-export');
    setReportFullPackages((current) => [reportPackage, ...current].slice(0, 30));
    setSelectedReportFullPackageId(reportPackage.id);
    setReportPackageText(reportPackage.content);
    setReportStatus(`Built ${reportPackage.fileName} export readiness package`);
  }

  function exportReportPackage() {
    const reportPackage = buildCurrentFullReportPackage('signed');
    const exportedPackage = {
      ...reportPackage,
      exportedAt: new Date().toISOString(),
      reportReady: true,
    };
    setReportFullPackages((current) => [exportedPackage, ...current.filter((item) => item.id !== reportPackage.id)].slice(0, 30));
    setSelectedReportFullPackageId(exportedPackage.id);
    setReportPackageText(exportedPackage.content);
    setReportStatus(`Exported full report package ${exportedPackage.fileName}`);
  }

  function importReportPackage() {
    try {
      const parsed = JSON.parse(reportPackageText) as {
        kind?: string;
        projectName?: string;
        affectedAssets?: ReportAffectedAsset[];
        evidenceManifest?: ReportEvidenceManifestEntry[];
        callbackArtifactManifest?: ReportFullPackage['callbackArtifactManifest'];
        callbackSignedPollBatches?: unknown[];
        callbackCorrelationReplays?: unknown[];
        callbackReplayExecutionBatches?: unknown[];
        callbackLifecycleReviews?: unknown[];
        callbackCiHandoffPackages?: unknown[];
        callbackPublicRelaySoakPackages?: unknown[];
        exportReadiness?: ReportReadinessCheck[];
        governanceAttestation?: ReportGovernanceAttestation;
        signature?: ReportFullPackage['signature'];
      };
      if (parsed.kind !== 'proxyforge-full-report-package') {
        throw new Error('Report package JSON must use proxyforge-full-report-package kind');
      }
      const importedPackage: ReportFullPackage = {
        id: `report-package-import-${Date.now()}-${Math.random().toString(16).slice(2)}`,
        title: `${parsed.projectName ?? projectName} imported full report package`,
        fileName: `proxyforge-full-report-package-import-${Date.now()}.json`,
        path: 'reports/imported/proxyforge-full-report-package.json',
        generatedAt: new Date().toISOString(),
        importedAt: new Date().toISOString(),
        reportReady: true,
        issueCount: reportCuration.issues.length,
        evidenceCount: reportCuration.exchanges.length,
        affectedAssets: parsed.affectedAssets ?? reportAffectedAssets,
        evidenceManifest: parsed.evidenceManifest ?? reportEvidenceManifest,
        callbackArtifactManifest: normalizeImportedCallbackArtifactManifest(parsed),
        readiness: parsed.exportReadiness ?? reportReadinessChecks,
        governanceAttestation: normalizeReportGovernanceAttestation(parsed.governanceAttestation) ?? reportGovernanceAttestation,
        signature: {
          algorithm: parsed.signature?.algorithm ?? 'HMAC-SHA256',
          signerName: parsed.signature?.signerName ?? reportSignerName,
          keyId: parsed.signature?.keyId ?? reportSigningKeyId,
          status: 'verified-import',
          digestPreview: parsed.signature?.digestPreview ?? getSimpleDigestPreview(reportPackageText),
        },
        content: reportPackageText,
      };
      setReportFullPackages((current) => [importedPackage, ...current].slice(0, 30));
      setSelectedReportFullPackageId(importedPackage.id);
      setReportStatus(`Imported and verified ${importedPackage.fileName}`);
    } catch (error) {
      setReportStatus(error instanceof Error ? `Report package import failed: ${error.message}` : 'Report package import failed');
    }
  }

  function loadLastBundleForVerification() {
    if (!reportArtifact || reportArtifact.format !== 'bundle') {
      setReportVerificationResult({
        status: 'error',
        message: 'Export a signed evidence bundle before loading the last artifact.',
      });
      return;
    }
    setReportVerificationText(reportArtifact.content);
    setReportVerificationResult({
      status: 'idle',
      message: 'Last evidence bundle loaded for verification.',
    });
  }

  async function verifyCurrentEvidenceBundle() {
    setReportVerificationResult({ status: 'idle', message: 'Verifying signed evidence bundle...' });
    const result = await verifyEvidenceBundleSignature(reportVerificationText, reportVerificationSecret);
    setReportVerificationResult(result);
  }

  function importVerifiedBundleIntoProject(mode: BundleMergeMode = 'replace-conflicts') {
    try {
      const mergePreview = buildEvidenceBundleMergePreview(reportVerificationText, reportVerificationResult, issues, exchanges);
      const { importedIssues, importedExchanges } = importVerifiedEvidenceBundle(reportVerificationText, reportVerificationResult);
      const currentIssueKeys = new Set(issues.map(issueMergeKey));
      const currentExchangeKeys = new Set(exchanges.map(exchangeMergeKey));
      const nextImportedIssues = mode === 'new-only'
        ? importedIssues.filter((issue) => !currentIssueKeys.has(issueMergeKey(issue)))
        : importedIssues;
      const nextImportedExchanges = mode === 'new-only'
        ? importedExchanges.filter((exchange) => !currentExchangeKeys.has(exchangeMergeKey(exchange)))
        : importedExchanges;
      if (importedIssues.length === 0 && importedExchanges.length === 0) {
        setReportVerificationResult((current) => ({
          ...current,
          status: 'invalid',
          message: 'Verified bundle contains no findings or evidence to import.',
        }));
        return;
      }
      if (nextImportedIssues.length === 0 && nextImportedExchanges.length === 0) {
        setReportVerificationResult((current) => ({
          ...current,
          status: 'valid',
          message: 'Merge review found no new findings or evidence to import.',
          findings: 0,
          evidence: 0,
        }));
        return;
      }
      setImportedBundleIssues((current) => {
        const conflictKeys = new Set(mode === 'replace-conflicts' ? importedIssues.map(issueMergeKey) : []);
        const retained = conflictKeys.size
          ? current.filter((issue) => !conflictKeys.has(issueMergeKey(issue)))
          : current;
        return mergeIssues(retained, nextImportedIssues).slice(0, 200);
      });
      setExchanges((current) => nextImportedExchanges.reduce((next, exchange) => mergeExchanges(exchange, next), current));
      if (nextImportedIssues[0]) setSelectedIssueId(nextImportedIssues[0].id);
      if (nextImportedExchanges[0]) setSelectedExchangeId(nextImportedExchanges[0].id);
      setReportArtifact(null);
      setReportVerificationResult((current) => ({
        ...current,
        status: 'valid',
        message: mode === 'new-only'
          ? `Imported ${nextImportedIssues.length} new findings and ${nextImportedExchanges.length} new evidence items; skipped ${mergePreview.conflictFindings} finding conflicts and ${mergePreview.duplicateEvidence} duplicate evidence items.`
          : `Imported ${nextImportedIssues.length} findings and ${nextImportedExchanges.length} evidence items into the project; ${mergePreview.conflictFindings} finding conflicts were replaced in the report layer.`,
        findings: nextImportedIssues.length,
        evidence: nextImportedExchanges.length,
      }));
    } catch (error) {
      setReportVerificationResult((current) => ({
        ...current,
        status: 'error',
        message: error instanceof Error ? error.message : 'Bundle import failed.',
      }));
    }
  }

  async function runSequencer(source: SequencerSampleSource = 'manual') {
    const samples = parseSequencerSampleText(sequencerSamples);
    setSequencerStatus(`Analyzing ${samples.length} token sample${samples.length === 1 ? '' : 's'}`);
    try {
      const result = await analyzeSequencerSamples({
        label: source === 'traffic' ? 'Traffic token corpus' : source === 'browser-preview' ? 'Live capture token corpus' : 'Manual token corpus',
        source,
        samples,
      });
      setSequencerResult(result);
      setSequencerResults((current) => [result, ...current.filter((item) => item.id !== result.id)].slice(0, 40));
      setSelectedSequencerResultId(result.id);
      setSequencerStatus(`Sequencer analysis complete: ${result.reliability.level} reliability, ${result.statisticalTests.length} statistical tests`);
    } catch (error) {
      setSequencerStatus(error instanceof Error ? `Sequencer failed: ${error.message}` : 'Sequencer failed');
    }
  }

  function loadTrafficTokensIntoSequencer() {
    const trafficTokens = extractTokenSamples([
      selectedExchange,
      ...exchanges.filter((exchange) => exchange.id !== selectedExchange.id),
    ]);
    if (trafficTokens.length === 0) {
      setSequencerStatus('No token-like values found in current traffic');
      return;
    }
    setSequencerSamples(trafficTokens.join('\n'));
    setSequencerResult(null);
    setSequencerStatus(`Loaded ${trafficTokens.length} token-like value${trafficTokens.length === 1 ? '' : 's'} from traffic`);
  }

  function startSequencerLiveCapture() {
    const location = sequencerTokenLocation(sequencerTokenLocationKind, sequencerTokenLocationName, sequencerCustomExtractor);
    const capture = buildSequencerLiveCapture(selectedExchange, location, sequencerLiveCaptureCount);
    setSequencerLiveCaptures((current) => [capture, ...current].slice(0, 40));
    setSelectedSequencerLiveCaptureId(capture.id);
    if (!capture.extractedTokens.length) {
      setSequencerStatus(capture.summary);
      return;
    }
    setSequencerSamples(capture.extractedTokens.join('\n'));
    setSequencerResult(null);
    setSequencerStatus(`${capture.summary} Ready to analyze now.`);
  }

  function detectSequencerTokenLocations() {
    setSequencerTokenLocationKind('custom');
    setSequencerTokenLocationName('authorization cookie body query location');
    setSequencerStatus('Detected token locations across authorization, cookie, query, and body locations from the selected response.');
  }

  function compareSequencerProfile() {
    const candidate = sequencerResult ?? selectedSequencerStoredResult;
    const baseline = sequencerResults.find((result) => result.id !== candidate?.id) ?? (selectedSequencerLiveCapture?.extractedTokens.length ? undefined : sequencerResults[1]);
    if (!candidate || !baseline) {
      setSequencerStatus('Run at least two Sequencer analyses before comparing token profiles');
      return;
    }
    const comparison = compareSequencerProfiles(baseline, candidate);
    setSequencerProfileComparisons((current) => [comparison, ...current].slice(0, 40));
    setSelectedSequencerProfileComparisonId(comparison.id);
    setSequencerStatus(`Sequencer profile comparison ready: ${comparison.summary}`);
  }

  function exportSequencerEvidence() {
    const result = sequencerResult ?? selectedSequencerStoredResult;
    if (!result) {
      setSequencerStatus('Analyze tokens before exporting Sequencer evidence');
      return;
    }
    const issue = issueFromSequencerResult(result, selectedExchange);
    const artifact = buildSequencerExportArtifact(result, selectedSequencerProfileComparison, issue.id);
    setSequencerExports((current) => [artifact, ...current].slice(0, 40));
    setSelectedSequencerExportId(artifact.id);
    setSequencerExportText(artifact.content);
    setImportedBundleIssues((current) => [issue, ...current.filter((item) => item.id !== issue.id)].slice(0, 200));
    setSelectedIssueId(issue.id);
    setReportArtifact(null);
    setSequencerStatus(`Exported Sequencer evidence and promoted report finding: ${issue.title}`);
  }

  async function runDecoderAction(transformId: DecoderTransformId) {
    const transform = decoderTransforms.find((item) => item.id === transformId);
    setDecoderStatus(`Running ${transform?.label ?? transformId}`);
    const result = await runDecoderTransform(transformId, decoderInput);
    setDecoderOutput(result.output);
    setDecoderChain((current) => [result, ...current].slice(0, 12));
    setDecoderStatus(result.ok ? `${result.label} complete` : `${result.label} failed: ${result.notes[0]}`);
  }

  function loadSelectedExchangeIntoDecoder() {
    const raw = selectedExchange.requestRaw.includes('Authorization:')
      ? selectedExchange.requestRaw
      : `${selectedExchange.requestRaw}\n${selectedExchange.responseRaw}`;
    setDecoderInput(raw);
    setDecoderOutput('');
    setDecoderStatus(`Loaded ${selectedExchange.method} ${selectedExchange.path}`);
  }

  function promoteDecoderOutput() {
    setDecoderInput(decoderOutput);
    setDecoderStatus('Output promoted to input');
  }

  async function analyzeDecoderAdvanced() {
    setDecoderStatus('Running smart decode and encoding analysis');
    const [analysis, recipe] = await Promise.all([
      analyzeDecoderInput(decoderInput, 'Manual Decoder input'),
      buildDecoderSmartRecipe(decoderInput, 'Current Decoder transform recipe'),
    ]);
    setDecoderAnalysisRuns((current) => [analysis, ...current.filter((item) => item.id !== analysis.id)].slice(0, 40));
    setSelectedDecoderAnalysisId(analysis.id);
    setDecoderRecipes((current) => [recipe, ...current.filter((item) => item.id !== recipe.id)].slice(0, 40));
    setSelectedDecoderRecipeId(recipe.id);
    if (analysis.detectedLayers.length) {
      setDecoderOutput(analysis.finalPreview);
    }
    setDecoderStatus(`Smart decode complete: ${analysis.summary}`);
  }

  async function buildDecoderRecipe() {
    setDecoderStatus('Building recursive transform recipe');
    const recipe = await buildDecoderSmartRecipe(decoderInput, 'Current Decoder transform recipe');
    setDecoderRecipes((current) => [recipe, ...current.filter((item) => item.id !== recipe.id)].slice(0, 40));
    setSelectedDecoderRecipeId(recipe.id);
    setDecoderExportText(recipe.content);
    setDecoderStatus(`Recipe ready: ${recipe.summary}`);
  }

  function applyDecoderRecipe() {
    if (!selectedDecoderRecipe) {
      setDecoderStatus('Build a Decoder recipe before applying it');
      return;
    }
    setDecoderOutput(selectedDecoderRecipe.outputPreview);
    setDecoderStatus(`Applied recursive recipe: ${selectedDecoderRecipe.summary}`);
  }

  async function buildDecoderJwtEditor() {
    setDecoderStatus('Building JWT/JWS/JWE workspace');
    const isJweInput = decoderInput.trim().split('.').length === 5;
    const workspace = await buildDecoderJwtWorkspace(
      decoderInput,
      isJweInput && decoderJwtHeader === defaultDecoderJwtHeader ? undefined : decoderJwtHeader,
      isJweInput && decoderJwtPayload === defaultDecoderJwtPayload ? undefined : decoderJwtPayload,
      decoderJwtSecret,
    );
    setDecoderJwtWorkspaces((current) => [workspace, ...current.filter((item) => item.id !== workspace.id)].slice(0, 40));
    setSelectedDecoderJwtWorkspaceId(workspace.id);
    setDecoderJwtHeader(workspace.headerJson);
    setDecoderJwtPayload(workspace.payloadJson);
    setDecoderOutput(workspace.signedTokenPreview);
    setDecoderStatus(`JWT workspace ready: ${workspace.summary}`);
  }

  async function inspectDecoderBytes() {
    setDecoderStatus('Inspecting binary and hex data');
    const inspection = await inspectDecoderBinary(decoderInput);
    setDecoderBinaryInspections((current) => [inspection, ...current.filter((item) => item.id !== inspection.id)].slice(0, 40));
    setSelectedDecoderBinaryInspectionId(inspection.id);
    setDecoderExportText(inspection.hexDump);
    setDecoderStatus(`Binary inspector ready: ${inspection.summary}`);
  }

  function exportDecoderTransformLibrary() {
    const library = buildDecoderTransformLibraryPackage(
      decoderRecipes.slice(0, 10),
      decoderAnalysisRuns.slice(0, 10),
      decoderJwtWorkspaces.slice(0, 10),
      decoderBinaryInspections.slice(0, 10),
    );
    setDecoderTransformLibraries((current) => [library, ...current.filter((item) => item.id !== library.id)].slice(0, 30));
    setSelectedDecoderTransformLibraryId(library.id);
    setDecoderExportText(library.content);
    setDecoderStatus(`Decoder transform library exported: ${library.summary}`);
  }

  function issueFromDecoderEvidence(exportArtifact: DecoderReportExportArtifact): Issue {
    const analysis = selectedDecoderAnalysis;
    const jwt = selectedDecoderJwtWorkspace;
    const binary = selectedDecoderBinaryInspection;
    const severity: Severity = analysis?.encodingInsights.some((item) => item.severity === 'warning') || jwt?.status === 'signed-preview'
      ? 'medium'
      : analysis?.detectedLayers.length || binary?.highBytes
        ? 'low'
        : 'info';
    return {
      id: `decoder-issue-${exportArtifact.id}`,
      title: 'Decoder opaque data transformation review',
      severity,
      host: selectedExchange.host,
      path: selectedExchange.path,
      confidence: severity === 'medium' ? 'firm' : 'tentative',
      status: 'open',
      detail: `Decoder evidence captured smart decode layers, recursive transform recipe steps, JWT/JWS/JWE editing and signing preview, binary/hex inspection, hash analysis, and import/exportable transform library metadata for ${selectedExchange.method} ${selectedExchange.path}.`,
      remediation: 'Review decoded plaintext and token claims, preserve the transform recipe for replay, avoid trusting client-controlled opaque data, and verify server-side signature, encryption, and authorization checks before closing.',
      triageNote: `Decoder report artifact ${exportArtifact.fileName} is attached with smart decode, JWT/JWS/JWE, binary, hash, and transform-library evidence.`,
    };
  }

  function attachDecoderEvidenceToReport() {
    const library = selectedDecoderTransformLibrary ?? buildDecoderTransformLibraryPackage(
      decoderRecipes.slice(0, 10),
      decoderAnalysisRuns.slice(0, 10),
      decoderJwtWorkspaces.slice(0, 10),
      decoderBinaryInspections.slice(0, 10),
    );
    if (!selectedDecoderTransformLibrary) {
      setDecoderTransformLibraries((current) => [library, ...current.filter((item) => item.id !== library.id)].slice(0, 30));
      setSelectedDecoderTransformLibraryId(library.id);
    }
    const report = buildDecoderReportExport(
      selectedDecoderAnalysis,
      selectedDecoderRecipe,
      selectedDecoderJwtWorkspace,
      selectedDecoderBinaryInspection,
      library,
      undefined,
    );
    const issue = issueFromDecoderEvidence(report);
    const finalReport = buildDecoderReportExport(
      selectedDecoderAnalysis,
      selectedDecoderRecipe,
      selectedDecoderJwtWorkspace,
      selectedDecoderBinaryInspection,
      library,
      issue.id,
    );
    setDecoderReportExports((current) => [finalReport, ...current.filter((item) => item.id !== finalReport.id)].slice(0, 40));
    setSelectedDecoderReportExportId(finalReport.id);
    setDecoderExportText(finalReport.content);
    setImportedBundleIssues((current) => [issue, ...current.filter((item) => item.id !== issue.id)].slice(0, 200));
    setSelectedIssueId(issue.id);
    setReportArtifact(null);
    setDecoderStatus(`Decoder evidence attached to report: ${issue.title}`);
  }

  function loadSelectedRequestResponseIntoComparer() {
    setComparerLeft(selectedExchange.requestRaw);
    setComparerRight(selectedExchange.responseRaw);
    setComparerStatus(`Loaded request and response for ${selectedExchange.method} ${selectedExchange.path}`);
  }

  function loadReplayResponseIntoComparer() {
    setComparerLeft(selectedExchange.responseRaw);
    setComparerRight(repeaterResult.responseRaw);
    setComparerStatus(`Comparing selected response with latest replay result ${repeaterResult.status}`);
  }

  function swapComparerSides() {
    setComparerLeft(comparerRight);
    setComparerRight(comparerLeft);
    setComparerStatus('Swapped comparison sides');
  }

  function comparerWorkspaceIssueIds() {
    const combined = `${comparerLeft}\n${comparerRight}`;
    return issues.filter((issue) => (
      combined.includes(issue.host)
      || combined.includes(issue.path)
      || reportExchangeMatchesIssue(selectedExchange, issue)
      || reportExchangeMatchesIssue(repeaterResult, issue)
    )).map((issue) => issue.id);
  }

  function runComparerAdvancedComparison(nextMode = comparerMode) {
    const result = buildAdvancedComparison({
      left: comparerLeft,
      right: comparerRight,
      mode: nextMode,
      normalizationPresetId: comparerNormalizationPresetId,
      label: `${nextMode.replace('-', ' ')} ${comparerWorkspaceName || 'comparison'}`,
    });
    setComparerMode(nextMode);
    setComparerAdvancedRuns((current) => [result, ...current.filter((item) => item.id !== result.id)].slice(0, 40));
    setSelectedComparerAdvancedRunId(result.id);
    setComparerAdvancedText(nextMode === 'binary-hex' || nextMode === 'bytes' ? result.hexView : result.textView);
    setComparerStatus(`Advanced Comparer ${result.summary}`);
  }

  function reviewComparerReplayDelta() {
    const run = selectedComparerAdvancedRun ?? buildAdvancedComparison({
      left: comparerLeft,
      right: comparerRight,
      mode: comparerMode,
      normalizationPresetId: comparerNormalizationPresetId,
      label: 'Replay delta review comparison',
    });
    if (!selectedComparerAdvancedRun) {
      setComparerAdvancedRuns((current) => [run, ...current].slice(0, 40));
      setSelectedComparerAdvancedRunId(run.id);
      setComparerAdvancedText(run.textView);
    }
    const statusChanged = selectedExchange.status !== repeaterResult.status;
    const lengthDelta = repeaterResult.length - selectedExchange.length;
    const timingDelta = repeaterResult.timing - selectedExchange.timing;
    const privileged = /support_admin|admin|approved|refunds\.write|role/i.test(`${comparerLeft}\n${comparerRight}`) && run.differenceCount > 0;
    const review: ComparerReplayDeltaReview = {
      id: `comparer-delta-${Date.now()}-${Math.random().toString(16).slice(2)}`,
      createdAt: new Date().toISOString(),
      baselineLabel: `${selectedExchange.method} ${selectedExchange.path} ${selectedExchange.status}`,
      candidateLabel: `${repeaterResult.method} ${repeaterResult.path} ${repeaterResult.status}`,
      statusChanged,
      lengthDelta,
      timingDelta,
      risk: privileged || statusChanged ? 'medium' : Math.abs(lengthDelta) > 512 ? 'low' : 'info',
      verdict: privileged ? 'privilege-drift' : statusChanged || lengthDelta || timingDelta ? 'changed' : 'same',
      advancedRunId: run.id,
      linkedExchangeIds: Array.from(new Set([selectedExchange.id, repeaterResult.id])),
      linkedIssueIds: comparerWorkspaceIssueIds(),
      summary: `Replay/baseline delta ${statusChanged ? 'changed status' : 'kept status'}, length delta ${lengthDelta}, timing delta ${timingDelta}ms, ${run.differenceCount} advanced differences.`,
      evidence: [
        `Baseline: ${selectedExchange.method} ${selectedExchange.url} status ${selectedExchange.status}`,
        `Candidate: ${repeaterResult.method} ${repeaterResult.url} status ${repeaterResult.status}`,
        `Mode: ${run.mode}; normalization: ${run.normalizationLabel}`,
        `Differences: ${run.differenceCount}; similarity: ${formatPercent(run.similarity)}`,
        run.textView.slice(0, 1200),
      ].join('\n'),
      reportReady: true,
    };
    setComparerReplayDeltaReviews((current) => [review, ...current.filter((item) => item.id !== review.id)].slice(0, 40));
    setSelectedComparerReplayDeltaReviewId(review.id);
    setComparerStatus(`Replay delta review ready: ${review.summary}`);
  }

  function buildComparerLibraryPackage() {
    const exportedAt = new Date().toISOString();
    const presetIds = Array.from(new Set([
      comparerNormalizationPresetId,
      ...comparerAdvancedRuns.map((run) => run.normalizationPresetId),
    ]));
    const unsigned = {
      kind: 'proxyforge-comparer-library-package',
      exportedAt,
      advancedRuns: comparerAdvancedRuns.slice(0, 10),
      workspaces: comparerWorkspaces.slice(0, 10),
      diffPackages: comparerDiffPackages.slice(0, 10),
      replayDeltaReviews: comparerReplayDeltaReviews.slice(0, 10),
      normalizationPresets: comparerNormalizationPresets.filter((preset) => presetIds.includes(preset.id)),
      reportReady: true,
    };
    const digestPreview = getSimpleDigestPreview(JSON.stringify(unsigned));
    const content = JSON.stringify({ ...unsigned, digestPreview }, null, 2);
    const stamp = exportedAt.replace(/[:.]/g, '-');
    return {
      id: `comparer-library-${Date.now()}-${Math.random().toString(16).slice(2)}`,
      title: 'Comparer advanced diff library',
      fileName: `proxyforge-comparer-library-${stamp}.json`,
      path: `reports/proxyforge-comparer-library-${stamp}.json`,
      exportedAt,
      advancedRunIds: comparerAdvancedRuns.slice(0, 10).map((item) => item.id),
      workspaceIds: comparerWorkspaces.slice(0, 10).map((item) => item.id),
      diffPackageIds: comparerDiffPackages.slice(0, 10).map((item) => item.id),
      replayDeltaReviewIds: comparerReplayDeltaReviews.slice(0, 10).map((item) => item.id),
      normalizationPresetIds: presetIds,
      reportReady: true,
      digestPreview,
      summary: `${comparerAdvancedRuns.length} advanced diff run${comparerAdvancedRuns.length === 1 ? '' : 's'}, ${comparerWorkspaces.length} workspace${comparerWorkspaces.length === 1 ? '' : 's'}, and ${comparerReplayDeltaReviews.length} replay delta review${comparerReplayDeltaReviews.length === 1 ? '' : 's'} exported.`,
      content,
    } satisfies ComparerLibraryPackage;
  }

  function exportComparerLibrary() {
    const library = buildComparerLibraryPackage();
    setComparerLibraries((current) => [library, ...current.filter((item) => item.id !== library.id)].slice(0, 30));
    setSelectedComparerLibraryId(library.id);
    setComparerDiffPackageText(library.content);
    setComparerStatus(`Exported Comparer library ${library.fileName}`);
  }

  function issueFromComparerAdvancedEvidence(attachment: ComparerEvidenceAttachment): Issue {
    const run = selectedComparerAdvancedRun;
    const review = selectedComparerReplayDeltaReview;
    const severity: Severity = review?.risk ?? (run && run.differenceCount > 4 ? 'low' : 'info');
    return {
      id: `comparer-advanced-issue-${attachment.id}`,
      title: 'Comparer advanced diff review',
      severity,
      host: selectedExchange.host,
      path: selectedExchange.path,
      confidence: severity === 'medium' ? 'firm' : 'tentative',
      status: 'open',
      detail: `Comparer advanced evidence captured word diff, byte diff, structured HTTP diff, binary/hex comparison, normalization presets, saved comparison library metadata, replay/baseline delta review, and report-ready attachments for ${selectedExchange.method} ${selectedExchange.path}.`,
      remediation: 'Review normalized differences for authorization drift, volatile headers, binary payload changes, and replay behavior before deciding whether the delta represents expected behavior or a security finding.',
      triageNote: `Comparer evidence attachment ${attachment.fileName} is report-ready and includes mode ${run?.mode ?? comparerMode}, normalization ${run?.normalizationLabel ?? comparerNormalizationPresetId}, and replay delta verdict ${review?.verdict ?? 'not reviewed'}.`,
    };
  }

  function attachComparerAdvancedEvidenceToReport() {
    const library = selectedComparerLibrary ?? buildComparerLibraryPackage();
    if (!selectedComparerLibrary) {
      setComparerLibraries((current) => [library, ...current.filter((item) => item.id !== library.id)].slice(0, 30));
      setSelectedComparerLibraryId(library.id);
    }
    const createdAt = new Date().toISOString();
    const stamp = createdAt.replace(/[:.]/g, '-');
    const unsigned = {
      kind: 'proxyforge-comparer-advanced-evidence',
      createdAt,
      advancedRun: selectedComparerAdvancedRun,
      replayDeltaReview: selectedComparerReplayDeltaReview,
      library,
      diffPackage: comparerDiffPackages.find((item) => item.id === selectedComparerDiffPackageId) ?? comparerDiffPackages[0],
      parityFeatures: [
        'word diff',
        'byte diff',
        'structured HTTP diff',
        'binary/hex comparison',
        'normalization presets',
        'saved comparison library',
        'replay/baseline delta review',
        'evidence attachments',
        'Reports handoff',
      ],
    };
    const content = JSON.stringify({ ...unsigned, digestPreview: getSimpleDigestPreview(JSON.stringify(unsigned)) }, null, 2);
    const attachment: ComparerEvidenceAttachment = {
      id: `comparer-attachment-${Date.now()}-${Math.random().toString(16).slice(2)}`,
      title: 'Comparer advanced evidence attachment',
      fileName: `proxyforge-comparer-advanced-${stamp}.json`,
      path: `reports/proxyforge-comparer-advanced-${stamp}.json`,
      createdAt,
      advancedRunId: selectedComparerAdvancedRun?.id,
      libraryPackageId: library.id,
      replayDeltaReviewId: selectedComparerReplayDeltaReview?.id,
      reportReady: true,
      summary: 'Report-ready Comparer attachment with word/byte/structured/binary diffs, normalization, replay delta, and library metadata.',
      content,
    };
    const issue = issueFromComparerAdvancedEvidence(attachment);
    const finalAttachment = { ...attachment, issueId: issue.id };
    setComparerEvidenceAttachments((current) => [finalAttachment, ...current.filter((item) => item.id !== finalAttachment.id)].slice(0, 40));
    setSelectedComparerEvidenceAttachmentId(finalAttachment.id);
    setComparerDiffPackageText(finalAttachment.content);
    setImportedBundleIssues((current) => [issue, ...current.filter((item) => item.id !== issue.id)].slice(0, 200));
    setSelectedIssueId(issue.id);
    setReportArtifact(null);
    setComparerStatus(`Attached Comparer advanced evidence to report: ${issue.title}`);
  }

  function createCallbackProbe() {
    const payload = createCallbackPayload({
      protocol: callbackProtocol,
      label: callbackLabel,
      exchange: selectedExchange,
    });
    setCallbackPayloads((current) => [payload, ...current].slice(0, 100));
    setSelectedCallbackId(payload.id);
    setCallbackStatus(`Generated ${callbackProtocolLabels[payload.protocol]} payload ${payload.token}`);
  }

  function pollCallbackInteractions() {
    const result = simulateCallbackPoll(callbackPayloads, callbackInteractions, selectedExchange);
    setCallbackPayloads(result.payloads);
    setCallbackInteractions(result.interactions);
    if (result.newInteractions.length > 0) {
      setCallbackWorkspaces((current) => current.map((workspace) => {
        const matchingInteractions = result.newInteractions.filter((interaction) => workspace.payloadIds.includes(interaction.payloadId));
        if (!matchingInteractions.length) return workspace;
        return {
          ...workspace,
          updatedAt: new Date().toISOString(),
          interactionIds: Array.from(new Set([...workspace.interactionIds, ...matchingInteractions.map((interaction) => interaction.id)])),
          protocols: Array.from(new Set([...workspace.protocols, ...matchingInteractions.map((interaction) => interaction.protocol)])),
          severity: highestFindingSeverity([...matchingInteractions, { severity: workspace.severity }]),
          status: 'confirmed',
        };
      }));
    }
    if (result.newInteractions[0]) setSelectedCallbackId(result.newInteractions[0].payloadId);
    setCallbackStatus(result.message);
  }

  function buildCurrentCallbackListenerProfile() {
    return selectedCallbackListenerProfile ?? buildCallbackListenerProfile({
      mode: callbackListenerMode,
      host: callbackListenerHost,
      publicBaseUrl: callbackListenerPublicBaseUrl,
      httpPort: callbackListenerHttpPort,
      dnsPort: callbackListenerDnsPort,
      smtpPort: callbackListenerSmtpPort,
      pollIntervalSeconds: callbackListenerPollIntervalSeconds,
      retentionHours: callbackListenerRetentionHours,
      signingKeyId: callbackListenerSigningKeyId,
    });
  }

  async function planCallbackListenerBackend() {
    const profile = buildCallbackListenerProfile({
      mode: callbackListenerMode,
      host: callbackListenerHost,
      publicBaseUrl: callbackListenerPublicBaseUrl,
      httpPort: callbackListenerHttpPort,
      dnsPort: callbackListenerDnsPort,
      smtpPort: callbackListenerSmtpPort,
      pollIntervalSeconds: callbackListenerPollIntervalSeconds,
      retentionHours: callbackListenerRetentionHours,
      signingKeyId: callbackListenerSigningKeyId,
    });
    let nextProfile = profile;
    let statusMessage = profile.summary;
    if (isElectronBridgeReady() && profile.mode !== 'browser-preview') {
      try {
        const runtime = await startCallbackListener(profile, callbackPayloads);
        nextProfile = {
          ...profile,
          status: runtime.running ? 'running' : 'blocked',
          httpPort: runtime.ports.http ?? profile.httpPort,
          dnsPort: runtime.ports.dns ?? profile.dnsPort,
          smtpPort: runtime.ports.smtp ?? profile.smtpPort,
          healthChecks: runtime.healthChecks.length ? runtime.healthChecks : profile.healthChecks,
          summary: runtime.message,
          content: JSON.stringify({ kind: 'proxyforge-callback-runtime-listener-status', profile, runtime }, null, 2),
        };
        statusMessage = runtime.message;
      } catch (error) {
        const message = error instanceof Error ? error.message : String(error);
        nextProfile = {
          ...profile,
          status: 'blocked',
          summary: `Callback listener failed to start: ${message}`,
          content: JSON.stringify({ kind: 'proxyforge-callback-runtime-listener-error', profile, error: message }, null, 2),
        };
        statusMessage = nextProfile.summary;
      }
    }
    setCallbackListenerProfiles((current) => [nextProfile, ...current.filter((item) => item.id !== nextProfile.id)].slice(0, 20));
    setSelectedCallbackListenerProfileId(nextProfile.id);
    setCallbackLiveBackendText(nextProfile.content);
    setCallbackStatus(statusMessage);
  }

  async function pollSignedCallbackInteractions() {
    const profile = buildCurrentCallbackListenerProfile();
    if (isElectronBridgeReady() && profile.mode !== 'browser-preview') {
      try {
        const runtimeResult = await pollCallbackListener(profile.id, callbackPayloads);
        const newInteractions = runtimeResult.interactions.filter((interaction) => (
          runtimeResult.newInteractionIds.includes(interaction.id)
          && !callbackInteractions.some((existing) => existing.id === interaction.id)
        ));
        const mergedInteractions = mergeCallbackInteractions(callbackInteractions, runtimeResult.interactions);
        const nextPayloads = markCallbackPayloadsObserved(callbackPayloads, mergedInteractions);
        const runtimeProfile = {
          ...profile,
          status: runtimeResult.status.running ? 'running' as const : 'blocked' as const,
          httpPort: runtimeResult.status.ports.http ?? profile.httpPort,
          dnsPort: runtimeResult.status.ports.dns ?? profile.dnsPort,
          smtpPort: runtimeResult.status.ports.smtp ?? profile.smtpPort,
          healthChecks: runtimeResult.status.healthChecks.length ? runtimeResult.status.healthChecks : profile.healthChecks,
          summary: runtimeResult.status.message,
          content: JSON.stringify({ kind: 'proxyforge-callback-runtime-poll-status', profile, runtime: runtimeResult.status, newInteractionIds: runtimeResult.newInteractionIds }, null, 2),
        };
        const batch = buildCallbackSignedPollBatch({
          profile: runtimeProfile,
          payloads: nextPayloads,
          interactions: mergedInteractions,
          newInteractions,
          workspaces: callbackWorkspaces,
          exploitRuns,
          signerName: callbackPayloadOwner,
          signingSecret: callbackListenerSigningKeyId,
          summary: runtimeResult.status.message,
        });
        setCallbackListenerProfiles((current) => [runtimeProfile, ...current.filter((item) => item.id !== runtimeProfile.id)].slice(0, 20));
        setSelectedCallbackListenerProfileId(runtimeProfile.id);
        setCallbackPayloads(nextPayloads);
        setCallbackInteractions(mergedInteractions);
        setCallbackSignedPollBatches((current) => [batch, ...current.filter((item) => item.id !== batch.id)].slice(0, 40));
        setSelectedCallbackSignedPollBatchId(batch.id);
        setCallbackLiveBackendText(batch.content);
        if (newInteractions[0]) setSelectedCallbackId(newInteractions[0].payloadId);
        setCallbackStatus(batch.summary);
        return;
      } catch (error) {
        setCallbackStatus(`Callback listener poll failed: ${error instanceof Error ? error.message : String(error)}`);
      }
    }
    const result = pollCallbackLiveInteractions({
      profile,
      payloads: callbackPayloads,
      interactions: callbackInteractions,
      fallbackExchange: selectedExchange,
      workspaces: callbackWorkspaces,
      exploitRuns,
      signerName: callbackPayloadOwner,
      signingSecret: callbackListenerSigningKeyId,
    });
    setCallbackListenerProfiles((current) => [profile, ...current.filter((item) => item.id !== profile.id)].slice(0, 20));
    setSelectedCallbackListenerProfileId(profile.id);
    setCallbackPayloads(result.payloads);
    setCallbackInteractions(result.interactions);
    setCallbackSignedPollBatches((current) => [result.batch, ...current.filter((item) => item.id !== result.batch.id)].slice(0, 40));
    setSelectedCallbackSignedPollBatchId(result.batch.id);
    setCallbackLiveBackendText(result.batch.content);
    if (result.newInteractions.length > 0) {
      setCallbackWorkspaces((current) => current.map((workspace) => {
        const matchingInteractions = result.newInteractions.filter((interaction) => workspace.payloadIds.includes(interaction.payloadId));
        if (!matchingInteractions.length) return workspace;
        return {
          ...workspace,
          updatedAt: new Date().toISOString(),
          interactionIds: Array.from(new Set([...workspace.interactionIds, ...matchingInteractions.map((interaction) => interaction.id)])),
          protocols: Array.from(new Set([...workspace.protocols, ...matchingInteractions.map((interaction) => interaction.protocol)])),
          severity: highestFindingSeverity([...matchingInteractions, { severity: workspace.severity }]),
          status: 'confirmed',
        };
      }));
      setSelectedCallbackId(result.newInteractions[0].payloadId);
    }
    setCallbackStatus(result.batch.summary);
  }

  function mergeCallbackInteractions(existing: CallbackInteraction[], incoming: CallbackInteraction[]) {
    const seen = new Set<string>();
    return [...incoming, ...existing].filter((interaction) => {
      if (seen.has(interaction.id)) return false;
      seen.add(interaction.id);
      return true;
    }).slice(0, 200);
  }

  function markCallbackPayloadsObserved(payloads: CallbackPayload[], interactions: CallbackInteraction[]) {
    return payloads.map((payload) => {
      const latestInteraction = interactions.find((interaction) => interaction.payloadId === payload.id);
      if (!latestInteraction || payload.status === 'archived') return payload;
      return {
        ...payload,
        status: 'observed' as const,
        lastInteractionAt: latestInteraction.observedAt,
      };
    });
  }

  function replayCallbackCorrelation() {
    const profile = buildCurrentCallbackListenerProfile();
    const replay = buildCallbackCorrelationReplayPackage({
      profile,
      payload: selectedCallbackPayload,
      interactions: selectedCallbackPayload ? selectedCallbackInteractions : callbackInteractions,
      exchange: selectedExchange,
      exploitRuns,
      targetTool: 'repeater',
    });
    setCallbackListenerProfiles((current) => [profile, ...current.filter((item) => item.id !== profile.id)].slice(0, 20));
    setSelectedCallbackListenerProfileId(profile.id);
    setCallbackCorrelationReplays((current) => [replay, ...current.filter((item) => item.id !== replay.id)].slice(0, 40));
    setSelectedCallbackCorrelationReplayId(replay.id);
    setCallbackLiveBackendText(replay.content);
    setActiveRepeaterRaw(replay.replayRequestRaw);
    setActiveRepeaterTargetUrl(selectedExchange.url);
    setCallbackStatus(replay.summary);
  }

  function executeCallbackReplayBatch() {
    const profile = buildCurrentCallbackListenerProfile();
    const seedReplay = selectedCallbackCorrelationReplay ?? buildCallbackCorrelationReplayPackage({
      profile,
      payload: selectedCallbackPayload,
      interactions: selectedCallbackPayload ? selectedCallbackInteractions : callbackInteractions,
      exchange: selectedExchange,
      exploitRuns,
      targetTool: 'repeater',
    });
    const existingTargets = new Set(callbackCorrelationReplays.map((replay) => replay.targetTool));
    const targetReplays = [
      seedReplay,
      ...(['scanner', 'exploit-lab'] as const)
        .filter((targetTool) => !existingTargets.has(targetTool))
        .map((targetTool) => buildCallbackCorrelationReplayPackage({
          profile,
          payload: selectedCallbackPayload,
          interactions: selectedCallbackPayload ? selectedCallbackInteractions : callbackInteractions,
          exchange: selectedExchange,
          exploitRuns,
          targetTool,
        })),
      ...callbackCorrelationReplays.filter((replay) => replay.id !== seedReplay.id),
    ].slice(0, 8);
    const batch = executeCallbackCorrelationReplayBatch({
      profile,
      replays: targetReplays,
      payloads: callbackPayloads,
      interactions: callbackInteractions,
      exploitRuns,
      exchanges,
      scopeAllowlist: effectiveScopeAllowlist,
      mode: 'local-verified',
    });
    setCallbackListenerProfiles((current) => [profile, ...current.filter((item) => item.id !== profile.id)].slice(0, 20));
    setSelectedCallbackListenerProfileId(profile.id);
    setCallbackCorrelationReplays((current) => {
      const merged = [...targetReplays, ...current];
      const seen = new Set<string>();
      return merged.filter((replay) => {
        if (seen.has(replay.id)) return false;
        seen.add(replay.id);
        return true;
      }).slice(0, 40);
    });
    setSelectedCallbackCorrelationReplayId(seedReplay.id);
    setCallbackReplayExecutionBatches((current) => [batch, ...current.filter((item) => item.id !== batch.id)].slice(0, 40));
    setSelectedCallbackReplayExecutionBatchId(batch.id);
    setCallbackLiveBackendText(batch.content);
    setCallbackStatus(batch.summary);
  }

  function reviewCallbackPayloadLifecycle() {
    const profile = buildCurrentCallbackListenerProfile();
    const review = buildCallbackPayloadLifecycleReview({
      profile,
      payloads: callbackPayloads,
      interactions: callbackInteractions,
      retentionHours: callbackListenerRetentionHours,
    });
    setCallbackListenerProfiles((current) => [profile, ...current.filter((item) => item.id !== profile.id)].slice(0, 20));
    setSelectedCallbackListenerProfileId(profile.id);
    setCallbackLifecycleReviews((current) => [review, ...current.filter((item) => item.id !== review.id)].slice(0, 40));
    setSelectedCallbackLifecycleReviewId(review.id);
    setCallbackLiveBackendText(review.content);
    setCallbackStatus(review.summary);
  }

  function exportCallbackCiHandoff() {
    const profile = buildCurrentCallbackListenerProfile();
    const workspace = callbackWorkspaces.find((item) => item.id === selectedCallbackWorkspaceId);
    const handoff = buildCallbackCiHandoffPackage({
      profile,
      workspace,
      payloads: callbackPayloads,
      interactions: callbackInteractions,
      provider: callbackCiProvider,
    });
    setCallbackListenerProfiles((current) => [profile, ...current.filter((item) => item.id !== profile.id)].slice(0, 20));
    setSelectedCallbackListenerProfileId(profile.id);
    setCallbackCiHandoffPackages((current) => [handoff, ...current.filter((item) => item.id !== handoff.id)].slice(0, 40));
    setSelectedCallbackCiHandoffPackageId(handoff.id);
    setCallbackLiveBackendText(handoff.content);
    setCallbackStatus(handoff.summary);
  }

  function buildCallbackRelaySoakPackage() {
    const profile = selectedCallbackListenerProfile ?? buildCurrentCallbackListenerProfile();
    const workspace = callbackWorkspaces.find((item) => item.id === selectedCallbackWorkspaceId);
    const soak = buildCallbackPublicRelaySoakPackage({
      profile,
      workspace,
      payloads: callbackPayloads,
      interactions: callbackInteractions,
      signedPollBatches: callbackSignedPollBatches,
      replayExecutionBatches: callbackReplayExecutionBatches,
      lifecycleReviews: callbackLifecycleReviews,
      ciHandoffPackages: callbackCiHandoffPackages,
      minPayloadCount: 1,
      minInteractionCount: 1,
      minProtocolCount: Math.min(3, Math.max(2, profile.protocols.length)),
    });
    setCallbackListenerProfiles((current) => [profile, ...current.filter((item) => item.id !== profile.id)].slice(0, 20));
    setSelectedCallbackListenerProfileId(profile.id);
    setCallbackPublicRelaySoakPackages((current) => [soak, ...current.filter((item) => item.id !== soak.id)].slice(0, 40));
    setSelectedCallbackPublicRelaySoakPackageId(soak.id);
    setCallbackLiveBackendText(soak.content);
    setCallbackStatus(soak.summary);
  }

  async function copySelectedCallbackPayload() {
    if (!selectedCallbackPayload) {
      setCallbackStatus('No callback payload selected');
      return;
    }
    try {
      await navigator.clipboard.writeText(selectedCallbackPayload.endpoint);
      setCallbackStatus(`Copied ${selectedCallbackPayload.token} endpoint`);
    } catch {
      setCallbackStatus(`Endpoint ready: ${selectedCallbackPayload.endpoint}`);
    }
  }

  function stageSelectedCallbackInRepeater() {
    if (!selectedCallbackPayload) {
      setCallbackStatus('No callback payload selected');
      return;
    }
    setActiveRepeaterRaw(injectCallbackIntoRawRequest(selectedExchange.requestRaw, selectedCallbackPayload.endpoint));
    setActiveRepeaterTargetUrl(selectedExchange.url);
    setActiveTool('repeater');
    setCallbackStatus(`Staged ${selectedCallbackPayload.token} in Repeater`);
  }

  function archiveSelectedCallbackPayload() {
    if (!selectedCallbackPayload) {
      setCallbackStatus('No callback payload selected');
      return;
    }
    setCallbackPayloads((current) => current.map((payload) => (
      payload.id === selectedCallbackPayload.id ? { ...payload, status: 'archived' } : payload
    )));
    setCallbackStatus(`Archived ${selectedCallbackPayload.token}`);
  }

  function promoteSelectedCallbackFinding() {
    if (!selectedCallbackPayload) {
      setCallbackStatus('No callback payload selected');
      return;
    }
    const hasInteractions = callbackInteractions.some((interaction) => interaction.payloadId === selectedCallbackPayload.id);
    if (!hasInteractions) {
      setCallbackStatus(`No interactions observed for ${selectedCallbackPayload.token}`);
      return;
    }
    setSelectedIssueId(`callback-${selectedCallbackPayload.id}`);
    setActiveTool('scanner');
    setCallbackStatus(`Promoted ${selectedCallbackPayload.token} callback evidence to issue triage`);
  }

  function installExtensionFromCatalog(item: ExtensionCatalogItem) {
    const existing = installedExtensions.find((extension) => extension.catalogId === item.id);
    if (existing) {
      setSelectedExtensionId(existing.id);
      setExtensionStatus(`${item.name} is already installed`);
      return;
    }
    const extension = installCatalogExtension(item);
    setInstalledExtensions((current) => [extension, ...current]);
    setSelectedExtensionId(extension.id);
    setExtensionStatus(`Installed ${extension.name}`);
  }

  function installExtensionFromManifest() {
    const result = installManifestExtension(extensionManifestText, installedExtensions);
    if (result.error || !result.extension) {
      setExtensionStatus(result.error ?? 'Manifest install failed');
      return;
    }
    setInstalledExtensions((current) => [result.extension!, ...current].slice(0, 100));
    setSelectedExtensionId(result.extension.id);
    setExtensionStatus(`Installed local extension ${result.extension.name}`);
  }

  function toggleSelectedExtension() {
    if (!selectedExtension) {
      setExtensionStatus('No extension selected');
      return;
    }
    setInstalledExtensions((current) => current.map((extension) => (
      extension.id === selectedExtension.id ? { ...extension, enabled: !extension.enabled } : extension
    )));
    setExtensionStatus(`${selectedExtension.enabled ? 'Disabled' : 'Enabled'} ${selectedExtension.name}`);
  }

  function removeSelectedExtension() {
    if (!selectedExtension) {
      setExtensionStatus('No extension selected');
      return;
    }
    setInstalledExtensions((current) => current.filter((extension) => extension.id !== selectedExtension.id));
    setExtensionRuns((current) => current.filter((run) => run.extensionId !== selectedExtension.id));
    setExtensionRuntimeApiPolicies((current) => current.filter((policy) => policy.extensionId !== selectedExtension.id));
    setExtensionDependencyReviews((current) => current.filter((review) => review.extensionId !== selectedExtension.id));
    setExtensionHeadlessEvidence((current) => current.filter((evidence) => evidence.extensionId !== selectedExtension.id));
    setExtensionSignedUpdates((current) => current.filter((update) => update.extensionId !== selectedExtension.id));
    setExtensionCompatibilityFixtures((current) => current.filter((fixture) => fixture.extensionId !== selectedExtension.id));
    setExtensionRuntimeDiagnostics((current) => current.filter((diagnostic) => diagnostic.extensionId !== selectedExtension.id));
    setExtensionMigrationGuides((current) => current.filter((guide) => guide.extensionId !== selectedExtension.id));
    const next = installedExtensions.find((extension) => extension.id !== selectedExtension.id);
    setSelectedExtensionId(next?.id ?? '');
    setExtensionStatus(`Removed ${selectedExtension.name}`);
  }

  function runSelectedExtension() {
    if (!selectedExtension) {
      setExtensionStatus('No extension selected');
      return;
    }
    const run = runExtension(selectedExtension, extensionHook, selectedExchange);
    const latencyMs = Math.max(1, new Date(run.completedAt).getTime() - new Date(run.startedAt).getTime());
    const apiCapabilities = buildExtensionApiCapabilities(selectedExtension);
    const runtimeHealth: ExtensionRuntimeHealthEntry = {
      id: `ext-health-${Date.now()}-${Math.random().toString(16).slice(2)}`,
      extensionId: selectedExtension.id,
      extensionName: selectedExtension.name,
      hook: extensionHook,
      runId: run.id,
      status: run.status === 'complete' ? 'success' : run.status,
      observedAt: run.completedAt,
      latencyMs,
      permissionScope: selectedExtension.permissions,
      apiCapabilities,
      summary: `${run.status === 'complete' ? 'healthy' : run.status} runtime ${latencyMs}ms: ${run.summary}`,
    };
    setExtensionRuns((current) => [run, ...current].slice(0, 100));
    setExtensionRuntimeHealth((current) => [runtimeHealth, ...current].slice(0, 100));
    if (run.exchange) {
      setExchanges((current) => mergeExchanges(run.exchange!, current));
      setSelectedExchangeId(run.exchange.id);
    }
    if (run.issue) setSelectedIssueId(run.issue.id);
    const statusText = `${run.extensionName}: ${run.summary}`;
    setExtensionStatus(statusText);
    void recordExtensionRun(run)
      .then((result) => {
        mergeProjectRunStateStats(result);
        if (result) setExtensionStatus(`${statusText} · persisted to Project Store`);
      })
      .catch((error: unknown) => {
        setExtensionStatus(error instanceof Error ? `${statusText} · Project Store persist failed: ${error.message}` : `${statusText} · Project Store persist failed`);
      });
  }

  function buildExtensionPackageManifestContent(extension: InstalledExtension, exportedAt: string, digestPreview: string) {
    const apiCapabilities = buildExtensionApiCapabilities(extension);
    return JSON.stringify({
      kind: 'proxyforge-extension-package-manifest',
      exportedAt,
      extension: {
        id: extension.id,
        catalogId: extension.catalogId,
        name: extension.name,
        author: extension.author,
        version: extension.version,
        trustLevel: extension.trustLevel,
        enabled: extension.enabled,
      },
      scopedRuntime: {
        hooks: extension.hooks,
        permissions: extension.permissions,
        apiCapabilities,
        trafficMutationApi: apiCapabilities.trafficMutationApi,
        replayApi: apiCapabilities.replayApi,
        issueHandoff: apiCapabilities.issueHandoff,
        evidenceHandoff: apiCapabilities.evidenceHandoff,
      },
      signature: {
        algorithm: 'HMAC-SHA256',
        signerName: 'ProxyForge extension signer',
        keyId: 'extension-local',
        status: 'signed',
        digestPreview,
      },
    }, null, 2);
  }

