  function importExtensionPolicyPreset() {
    try {
      const parsed = JSON.parse(extensionPolicyPresetText) as {
        kind?: string;
        name?: string;
        scopedRuntime?: {
          hooks?: ExtensionHook[];
          permissions?: InstalledExtension['permissions'];
          trustLevels?: InstalledExtension['trustLevel'][];
          apiCapabilities?: ExtensionApiCapabilities;
        };
      };
      if (parsed.kind !== 'proxyforge-extension-policy-preset' || !parsed.name) {
        throw new Error('Policy preset JSON requires proxyforge-extension-policy-preset kind and name');
      }
      const preset: ExtensionPolicyPreset = {
        id: `ext-policy-${Date.now()}-${Math.random().toString(16).slice(2)}`,
        name: parsed.name,
        createdAt: new Date().toISOString(),
        hooks: (parsed.scopedRuntime?.hooks ?? selectedExtension?.hooks ?? ['passive-scan']) as ExtensionHook[],
        permissions: (parsed.scopedRuntime?.permissions ?? selectedExtension?.permissions ?? ['read-traffic']),
        trustLevels: (parsed.scopedRuntime?.trustLevels ?? (selectedExtension ? [selectedExtension.trustLevel] : ['verified'])),
        apiCapabilities: parsed.scopedRuntime?.apiCapabilities ?? (selectedExtension ? buildExtensionApiCapabilities(selectedExtension) : {
          trafficMutationApi: false,
          replayApi: true,
          issueHandoff: false,
          evidenceHandoff: true,
        }),
        content: extensionPolicyPresetText,
      };
      setExtensionPolicyPresets((current) => [preset, ...current.filter((item) => item.name !== preset.name)].slice(0, 40));
      setSelectedExtensionPolicyPresetId(preset.id);
      setExtensionPolicyPresetName(preset.name);
      setExtensionStatus(`Imported extension policy preset ${preset.name}`);
    } catch (error) {
      setExtensionStatus(error instanceof Error ? error.message : 'Policy preset import failed');
    }
  }

