  function recordAutomationMacro() {
    const workflow = createMacroWorkflow(selectedExchange, effectiveScopeAllowlist);
    setAutomationWorkflows((current) => [workflow, ...current].slice(0, 100));
    setSelectedAutomationId(workflow.id);
    setAutomationStatus(`Recorded macro from ${selectedExchange.method} ${selectedExchange.path}`);
  }

  function runSelectedAutomation() {
    if (!selectedAutomation) {
      setAutomationStatus('No workflow selected');
      return;
    }
    const estimatedRequests = selectedAutomation.steps.reduce((total, step) => total + step.maxRequests, 0);
    const maxRequests = safetyMaxRequests();
    if (estimatedRequests > maxRequests) {
      const message = `Safety policy blocked automation: estimated ${estimatedRequests} requests exceeds max ${maxRequests}`;
      setAutomationStatus(message);
      appendAuditEvent({
        tool: 'automations',
        action: 'Run workflow',
        target: selectedAutomation.name,
        decision: 'blocked',
        detail: message,
        requestCount: estimatedRequests,
        risk: 'medium',
      });
      return;
    }
    const result = runAutomationWorkflow(selectedAutomation, selectedExchange, effectiveScopeAllowlist);
    setAutomationWorkflows((current) => current.map((workflow) => (
      workflow.id === result.workflow.id ? result.workflow : workflow
    )));
    setAutomationExecutions((current) => [result.execution, ...current].slice(0, 100));
    if (result.execution.exchange) {
      setExchanges((current) => mergeExchanges(result.execution.exchange!, current));
      setSelectedExchangeId(result.execution.exchange.id);
    }
    if (result.execution.issue) setSelectedIssueId(result.execution.issue.id);
    const statusText = `${result.workflow.name}: ${result.execution.status === 'complete' ? 'workflow complete' : 'workflow blocked'}`;
    setAutomationStatus(statusText);
    void recordAutomationRun(result.execution)
      .then((persisted) => {
        mergeProjectRunStateStats(persisted);
        if (persisted) setAutomationStatus(`${statusText} · persisted to Project Store`);
      })
      .catch((error: unknown) => {
        setAutomationStatus(error instanceof Error ? `${statusText} · Project Store persist failed: ${error.message}` : `${statusText} · Project Store persist failed`);
      });
    appendAuditEvent({
      tool: 'automations',
      action: 'Run workflow',
      target: result.workflow.name,
      decision: result.execution.status === 'complete' ? 'completed' : 'blocked',
      detail: result.execution.logs.join(' '),
      requestCount: result.execution.totalRequests,
      risk: result.execution.status === 'complete' ? 'info' : 'medium',
    });
  }

  function toggleSelectedAutomationSchedule() {
    if (!selectedAutomation) {
      setAutomationStatus('No workflow selected');
      return;
    }
    const next = toggleWorkflowSchedule(selectedAutomation);
    setAutomationWorkflows((current) => current.map((workflow) => (
      workflow.id === selectedAutomation.id ? next : workflow
    )));
    setAutomationSchedulerState((current) => createAutomationSchedulerState(
      automationWorkflows.map((workflow) => (workflow.id === selectedAutomation.id ? next : workflow)),
      new Date(),
      current,
    ));
    setAutomationStatus(`${next.scheduleEnabled ? 'Scheduled' : 'Unscheduled'} ${next.name}`);
  }

  function tickAutomationSchedulerService() {
    const result = runAutomationSchedulerTick({
      state: automationSchedulerState,
      workflows: automationWorkflows,
      exchange: selectedExchange,
      scopeAllowlist: effectiveScopeAllowlist,
      ownerId: 'proxyforge-ui',
    });
    setAutomationSchedulerState(result.state);
    setAutomationWorkflows(result.workflows);
    if (result.executions.length > 0) {
      setAutomationExecutions((current) => [...result.executions, ...current].slice(0, 100));
      const exchangePatch = result.executions.find((execution) => execution.exchange)?.exchange;
      const issue = result.executions.find((execution) => execution.issue)?.issue;
      if (exchangePatch) {
        setExchanges((current) => mergeExchanges(exchangePatch, current));
        setSelectedExchangeId(exchangePatch.id);
      }
      if (issue) setSelectedIssueId(issue.id);
      void Promise.all(result.executions.map((execution) => recordAutomationRun(execution)))
        .then((persisted) => {
          persisted.forEach(mergeProjectRunStateStats);
          if (persisted.some(Boolean)) setAutomationStatus(`Scheduler tick: ${result.claimedJobs} claimed, ${result.completedJobs} complete, ${result.blockedJobs} blocked · persisted to Project Store`);
        })
        .catch((error: unknown) => {
          setAutomationStatus(error instanceof Error ? `Scheduler Project Store persist failed: ${error.message}` : 'Scheduler Project Store persist failed');
        });
    }
    setAutomationStatus(`Scheduler tick: ${result.claimedJobs} claimed, ${result.completedJobs} complete, ${result.blockedJobs} blocked`);
    appendAuditEvent({
      tool: 'automations',
      action: 'Scheduler tick',
      target: 'Automation scheduler service',
      decision: result.blockedJobs > 0 ? 'blocked' : 'completed',
      detail: result.logs.join(' '),
      requestCount: result.executions.reduce((total, execution) => total + execution.totalRequests, 0),
      risk: result.blockedJobs > 0 ? 'medium' : 'info',
    });
  }

