    setAutomationExecutions((current) => [execution, ...current].slice(0, 100));
    setAutomationStatus(`Generated ${automationCiProviderLabels[selectedAutomationCiProvider]} config for ${selectedAutomation.name}`);
    void recordAutomationRun(execution)
