function buildSitemap(exchanges: HttpExchange[]): Array<{ host: string; count: number }> {
  const counts = new Map<string, number>();
  for (const exchange of exchanges) {
    if (!exchange.host) continue;
    counts.set(exchange.host, (counts.get(exchange.host) ?? 0) + 1);
  }
  return Array.from(counts.entries())
    .map(([host, count]) => ({ host, count }))
    .sort((a, b) => b.count - a.count);
}

function formatHexDump(text: string): string {
  if (!text) return '';
  const bytes = new TextEncoder().encode(text);
  const lines: string[] = [];
  for (let offset = 0; offset < bytes.length; offset += 16) {
    const slice = bytes.subarray(offset, offset + 16);
    const hex = Array.from(slice, (byte) => byte.toString(16).padStart(2, '0')).join(' ').padEnd(48, ' ');
    const ascii = Array.from(slice, (byte) => (byte >= 32 && byte < 127 ? String.fromCharCode(byte) : '.')).join('');
    lines.push(`${offset.toString(16).padStart(8, '0')}  ${hex}  ${ascii}`);
    if (lines.length >= 4096) {
      lines.push('… (truncated)');
      break;
    }
  }
  return lines.join('\n');
}

function prettyFormat(text: string, mime: string): string {
  if (!text) return '';
  const trimmed = text.trim();
  if (/json/i.test(mime) || (trimmed.startsWith('{') || trimmed.startsWith('['))) {
    try {
      return JSON.stringify(JSON.parse(trimmed), null, 2);
    } catch {
      return text;
    }
  }
  return text;
}

function EditorPane({ label, meta, value, mime }: { label: string; meta?: string; value: string; mime: string }) {
  const [mode, setMode] = useState<'pretty' | 'raw' | 'hex'>('raw');
  const display = mode === 'pretty' ? prettyFormat(value, mime) : mode === 'hex' ? formatHexDump(value) : value;
  return (
    <div className="editor-pane">
      <div className="message-tabs">
        <strong className="message-label">{label}</strong>
        <div className="message-mode-toggle" role="tablist" aria-label={`${label} display mode`}>
          {(['pretty', 'raw', 'hex'] as const).map((option) => (
            <button
              key={option}
              type="button"
              role="tab"
              aria-selected={mode === option}
              className={classNames('mode-pill', mode === option && 'is-active')}
              onClick={() => setMode(option)}
            >
              {option}
            </button>
          ))}
        </div>
        {meta ? <span className="message-meta">{meta}</span> : null}
      </div>
      <pre className="message-editor">
        <code>{display || <span className="message-empty">No {label.toLowerCase()} data — select a row from the history above.</span>}</code>
      </pre>
    </div>
  );
}

interface InspectorPaneProps {
  activeTool: ToolId;
  selectedExchange: HttpExchange;
  selectedIssue: Issue;
  issues: Issue[];
  updateIssueTriage: (issueId: string, patch: Partial<Pick<IssueTriageOverride, 'status' | 'assignee' | 'triageNote'>>, recordAudit?: boolean) => void;
  scannerAuditQueue: ScannerAuditQueueItem[];
  setSelectedIssueId: (id: string) => void;
}

const INSPECTOR_TOOLS = new Set<ToolId>(['proxy', 'target', 'repeater', 'scanner', 'intruder', 'logger', 'viewer', 'search']);

function InspectorPane({ activeTool, selectedExchange, selectedIssue, issues, updateIssueTriage, scannerAuditQueue, setSelectedIssueId }: InspectorPaneProps) {
  const [collapsed, setCollapsed] = useState(false);
  if (!INSPECTOR_TOOLS.has(activeTool)) return null;
  const hasExchange = Boolean(selectedExchange?.id && selectedExchange.url);
  const hasIssues = issues.length > 0;
  const hasQueue = scannerAuditQueue.length > 0;
  if (!hasExchange && !hasIssues && !hasQueue) return null;
  if (collapsed) {
    return (
      <aside className="inspector is-collapsed" aria-label="Inspector (collapsed)">
        <button
          type="button"
          className="inspector-toggle"
          onClick={() => setCollapsed(false)}
          title="Show Inspector"
          aria-label="Show Inspector"
        >
          ◀
        </button>
      </aside>
    );
  }
  return (
    <aside className="inspector">
      <button
        type="button"
        className="inspector-toggle is-floating"
        onClick={() => setCollapsed(true)}
        title="Hide Inspector"
        aria-label="Hide Inspector"
      >
        ▶
      </button>
      {hasExchange ? (
        <div className="inspector-section">
          <div className="section-title">
            <Activity size={16} />
            <span>Request Metadata</span>
          </div>
          <dl className="metadata-grid">
            <div>
              <dt>Tool</dt>
              <dd>{activeTool}</dd>
            </div>
            <div>
              <dt>Source</dt>
              <dd>{selectedExchange.source}</dd>
            </div>
            <div>
              <dt>Host</dt>
              <dd>{selectedExchange.host}</dd>
            </div>
            <div>
              <dt>Risk</dt>
              <dd>
                <SeverityBadge severity={selectedExchange.risk} />
              </dd>
            </div>
            <div>
              <dt>Tags</dt>
              <dd>{selectedExchange.tags.join(', ')}</dd>
            </div>
            <div>
              <dt>URL</dt>
              <dd>{selectedExchange.url}</dd>
            </div>
          </dl>
        </div>
      ) : null}

      {hasIssues ? (<div className="inspector-section issue-section">
        <div className="section-title">
          <ShieldAlert size={16} />
          <span>Issue Triage</span>
        </div>
        <div className="issue-list">
          {issues.map((issue) => (
            <button
              key={issue.id}
              className={classNames('issue-row', selectedIssue.id === issue.id && 'is-active')}
              onClick={() => setSelectedIssueId(issue.id)}
            >
              <SeverityBadge severity={issue.severity} />
              <span>{issue.title}</span>
              <small>{issueStatusLabels[issue.status]}</small>
            </button>
          ))}
        </div>
        <article className="issue-detail" aria-label="Inspector issue triage">
          <SeverityBadge severity={selectedIssue.severity} />
          <h2>{selectedIssue.title}</h2>
          <p>{selectedIssue.detail}</p>
          <h3>Remediation</h3>
          <p>{selectedIssue.remediation}</p>
          <div className="issue-meta">
            <span>{selectedIssue.confidence}</span>
            <span>{issueStatusLabels[selectedIssue.status]}</span>
            {selectedIssue.assignee ? <span>{selectedIssue.assignee}</span> : null}
            {selectedIssue.lastTriagedAt ? <span>{new Date(selectedIssue.lastTriagedAt).toLocaleString([], { hour12: false })}</span> : null}
          </div>
          <div className="issue-triage-form">
            <label>
              Status
              <select
                value={selectedIssue.status}
                onChange={(event) => updateIssueTriage(selectedIssue.id, { status: event.target.value as Issue['status'] }, true)}
                aria-label="Inspector issue status"
              >
                {Object.entries(issueStatusLabels).map(([status, label]) => (
                  <option key={status} value={status}>{label}</option>
                ))}
              </select>
            </label>
            <label>
              Assignee
              <input
                value={selectedIssue.assignee ?? ''}
                onChange={(event) => updateIssueTriage(selectedIssue.id, { assignee: event.target.value })}
                aria-label="Inspector issue assignee"
                placeholder="Unassigned"
              />
            </label>
            <label className="triage-note-field">
              Note
              <textarea
                value={selectedIssue.triageNote ?? ''}
                onChange={(event) => updateIssueTriage(selectedIssue.id, { triageNote: event.target.value })}
                aria-label="Inspector issue triage note"
                placeholder="Evidence, replay checks, owner, or false-positive rationale"
              />
            </label>
          </div>
        </article>
      </div>) : null}

      {scannerAuditQueue.length > 0 ? (
        <div className="inspector-section">
          <div className="section-title">
            <ListChecks size={16} />
            <span>Queue</span>
          </div>
          <div className="queue-list">
            {scannerAuditQueue.map((item) => (
              <span key={item.id}>{item.label}: {queueStatusLabels[item.status]}</span>
            ))}
          </div>
        </div>
      ) : null}
    </aside>
  );
}

